-- Poems batch 261
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6b191f3e-4c71-453b-8898-0b2b2018e124','次韻','牟巘','宋','宋诗','song-poetry','','[]','大海相環宛一洲，浮漚乍起已千秋。',64,'全唐诗/poet.song.233000.json','["大海相環宛一洲，浮漚乍起已千秋。", "三壬笑向人間世，四癸時尋物外遊。", "我輩安能知許事，平生未若樂斯丘。", "開窗翠竹時相對，更說諸餘總謬悠。"]'),
('c03b3401-5884-4e27-97ac-99861356b4f2','送程晉輔長和靖','牟巘','宋','宋诗','song-poetry','','[]','傳家氣脈固深長，挾策來登和靖堂。',64,'全唐诗/poet.song.233000.json','["傳家氣脈固深長，挾策來登和靖堂。", "南渡金聲元不泯，西庵草色可能荒。", "要知持守爲涵養，好把精微重發揚。", "共喜慈幃得甘旨，他時遠到未渠央。"]'),
('8291115b-a0fa-417b-a360-7121c4028b53','趙君寶宣慰別三十五年矣末由再晤近張倩仲實轉似西湖詩圖乃知吟嘯湖山之樂輒爲五詩奉答  其一','牟巘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南屏環擁翠雲堆，誰遣精廬特地開。',64,'全唐诗/poet.song.233000.json','["南屏環擁翠雲堆，誰遣精廬特地開。", "祭酒先生甘隠遁，燃藜太乙忽飛來。", "胸中礧磈五千卷，門外芙蕖十萬栽。", "白日竟拋妻子去，群仙携手上瑶臺。"]'),
('5b6a1578-c20f-4e43-b20b-2d843a665619','趙君寶宣慰別三十五年矣末由再晤近張倩仲實轉似西湖詩圖乃知吟嘯湖山之樂輒爲五詩奉答  其二','牟巘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','橘園亭畔市多塵，麯院橋邊境轉清。',64,'全唐诗/poet.song.233000.json','["橘園亭畔市多塵，麯院橋邊境轉清。", "山色湖光精舍敞，筆牀茶竈釣船輕。", "奈何一字不堪煮，且與三賢相並行。", "笑問壽藏何早計，不妨更學趙臺卿。"]'),
('42e2fda6-b7b8-42e4-82a3-70b04f2f0dd1','趙君寶宣慰別三十五年矣末由再晤近張倩仲實轉似西湖詩圖乃知吟嘯湖山之樂輒爲五詩奉答  其三','牟巘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','毅齋大老除新綬，名節尤偏無所尊。',64,'全唐诗/poet.song.233000.json','["毅齋大老除新綬，名節尤偏無所尊。", "曾是臚傳第一唱，却留衣付外諸孫。", "挹挼柳汁初承渥，稱泛霞觴共拜恩。", "尚記吾家多夙契，何當握手得重論。"]'),
('b2354046-c84c-4af3-b1a7-cf3a044433ec','趙君寶宣慰別三十五年矣末由再晤近張倩仲實轉似西湖詩圖乃知吟嘯湖山之樂輒爲五詩奉答  其四','牟巘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','伯子堯夫豪傑人，四時佳致四時春。',64,'全唐诗/poet.song.233000.json','["伯子堯夫豪傑人，四時佳致四時春。", "靜能觀動一機活，會復乘元千古淳。", "造物生生還化化，世情故故又新新。", "不妨長向亭中醉，自覺沖融氣味真。"]'),
('d9f30a5f-984c-4649-80c2-9569bf98a35c','趙君寶宣慰別三十五年矣末由再晤近張倩仲實轉似西湖詩圖乃知吟嘯湖山之樂輒爲五詩奉答  其五','牟巘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','平生知舊一李友，別後長關白板扉。',64,'全唐诗/poet.song.233000.json','["平生知舊一李友，別後長關白板扉。", "偶有客來孤鶴起，也無人覺小舟歸。", "儘渠俗子頻相惱，只恐仙禽未肯飛。", "莫笑爨琴并煮鶴，醉眠林下兩忘機。"]'),
('6911e40c-d113-4b05-b351-c72726b59c95','孤雁','牟巘','宋','宋诗','song-poetry','','[]','如何苦作斷腸聲，度盡關山失弟兄。',64,'全唐诗/poet.song.233000.json','["如何苦作斷腸聲，度盡關山失弟兄。", "萬里他鄉誰是伴，單棲半夜若爲情。", "嘐嘐每歎衆人薄，落落孤將一意行。", "只恐影沉湘水後，更無來者繼高名。"]'),
('4bb53ff6-cccd-430e-a70c-94f26616bb38','贈陳東洲','牟巘','宋','宋诗','song-poetry','','[]','散髮披襟頗自由，野麋見客忽驚投。',64,'全唐诗/poet.song.233000.json','["散髮披襟頗自由，野麋見客忽驚投。", "新詩生怕將愁至，博學何妨與藝游。", "未說天邊金彈子，試尋城外土饅頭。", "不然且學伯倫醉，荷插相隨死便休。"]'),
('cd3a68d3-f8f9-4590-a2ed-14a6ea09e58c','題陸起潛皆山樓','牟巘','宋','宋诗','song-poetry','','[]','醉翁朝暮四時景，誰遣描摹入此圖。',64,'全唐诗/poet.song.233000.json','["醉翁朝暮四時景，誰遣描摹入此圖。", "喚作皆山真箇是，携來到處與之俱。", "也曾佳客相陪否，亦有清泉可釀無。", "更喜一般僧侶舊，高樓百尺俯塵區。"]'),
('fbfb3ee9-d477-4b1a-b01b-c2938e42d634','送屠存博教授溧水','牟巘','宋','宋诗','song-poetry','','[]','直道方心古所難，任渠俗眼笑儒冠。',64,'全唐诗/poet.song.233000.json','["直道方心古所難，任渠俗眼笑儒冠。", "子龍有屋猶黄壤，老鄭無氈漫冷官。", "一片湖光清客署，三州鼎足屹書壇。", "只應翠綠迎人意，歲月功名正好看。"]'),
('0dc94281-4e0b-4b11-ae2a-d94c5313594c','送鄣南俞教諭歸里','牟巘','宋','宋诗','song-poetry','','[]','試把溪堂舊譜看，三千苜蓿守酸寒。',64,'全唐诗/poet.song.233000.json','["試把溪堂舊譜看，三千苜蓿守酸寒。", "吟肩祇自初來瘦，疐尾方知細滿難。", "憂患可能期學力，功名終不誤儒冠。", "到家莫作多時住，趁取秋風送羽翰。"]'),
('fb9d34e6-4079-4c24-bd2e-754e1929182e','賈節菴冒夏暑越修塗過我苕霅情誼甚厚令聞古式無思大節不可復見而骨肉消息訪問難真相對殆感慨不能爲懷青燈夜語誦少陵夜闌更秉燭相對如夢寐之句意甚惘然其歸也兒曹以此爲韻賦詩道別余亦作焉衰老拙惡姑寫我懷且以卜後期云爾  其一','牟巘','宋','宋诗','song-poetry','','[]','君留劍水潯，我卧弁峰下。',24,'全唐诗/poet.song.233000.json','["君留劍水潯，我卧弁峰下。", "十書九不到，思君無日夜。"]'),
('92c0a9cc-2b63-4c20-8262-58f19f0e7c1d','賈節菴冒夏暑越修塗過我苕霅情誼甚厚令聞古式無思大節不可復見而骨肉消息訪問難真相對殆感慨不能爲懷青燈夜語誦少陵夜闌更秉燭相對如夢寐之句意甚惘然其歸也兒曹以此爲韻賦詩道別余亦作焉衰老拙惡姑寫我懷且以卜後期云爾  其二','牟巘','宋','宋诗','song-poetry','','[]','一朝忽在眼，喜極生悲酸。',24,'全唐诗/poet.song.233000.json','["一朝忽在眼，喜極生悲酸。", "老淚如撒菽，淚盡氣亦闌。"]'),
('f9f3cb5b-206c-41ba-afd7-9864936c98ea','賈節菴冒夏暑越修塗過我苕霅情誼甚厚令聞古式無思大節不可復見而骨肉消息訪問難真相對殆感慨不能爲懷青燈夜語誦少陵夜闌更秉燭相對如夢寐之句意甚惘然其歸也兒曹以此爲韻賦詩道別余亦作焉衰老拙惡姑寫我懷且以卜後期云爾  其三','牟巘','宋','宋诗','song-poetry','','[]','事故不可料，柯爛棋局更。',24,'全唐诗/poet.song.233000.json','["事故不可料，柯爛棋局更。", "兩家骨肉內，往往隔死生。"]'),
('5b200795-2bdb-4617-9d23-add3892f19b4','賈節菴冒夏暑越修塗過我苕霅情誼甚厚令聞古式無思大節不可復見而骨肉消息訪問難真相對殆感慨不能爲懷青燈夜語誦少陵夜闌更秉燭相對如夢寐之句意甚惘然其歸也兒曹以此爲韻賦詩道別余亦作焉衰老拙惡姑寫我懷且以卜後期云爾  其四','牟巘','宋','宋诗','song-poetry','','[]','英英君令弟，介烈夙所秉。',24,'全唐诗/poet.song.233000.json','["英英君令弟，介烈夙所秉。", "就死得處所，我意復何恨。"]'),
('25897902-30a6-496b-bd6d-34553503dc7f','賈節菴冒夏暑越修塗過我苕霅情誼甚厚令聞古式無思大節不可復見而骨肉消息訪問難真相對殆感慨不能爲懷青燈夜語誦少陵夜闌更秉燭相對如夢寐之句意甚惘然其歸也兒曹以此爲韻賦詩道別余亦作焉衰老拙惡姑寫我懷且以卜後期云爾  其五','牟巘','宋','宋诗','song-poetry','','[]','吾女去二穉，何處吞聲哭。',24,'全唐诗/poet.song.233000.json','["吾女去二穉，何處吞聲哭。", "忠孝果何辜，神理諒未燭。"]'),
('8bdfb320-80a5-4487-83be-5b683c8dc66d','賈節菴冒夏暑越修塗過我苕霅情誼甚厚令聞古式無思大節不可復見而骨肉消息訪問難真相對殆感慨不能爲懷青燈夜語誦少陵夜闌更秉燭相對如夢寐之句意甚惘然其歸也兒曹以此爲韻賦詩道別余亦作焉衰老拙惡姑寫我懷且以卜後期云爾  其六','牟巘','宋','宋诗','song-poetry','','[]','君能爲置後，此意不可忘。',24,'全唐诗/poet.song.233000.json','["君能爲置後，此意不可忘。", "嶢嶢峙頭骨，正好玉其相。"]'),
('a6d68590-374d-4d89-9a9d-798e95c65615','賈節菴冒夏暑越修塗過我苕霅情誼甚厚令聞古式無思大節不可復見而骨肉消息訪問難真相對殆感慨不能爲懷青燈夜語誦少陵夜闌更秉燭相對如夢寐之句意甚惘然其歸也兒曹以此爲韻賦詩道別余亦作焉衰老拙惡姑寫我懷且以卜後期云爾  其七','牟巘','宋','宋诗','song-poetry','','[]','自言勤教督，燈火與之對。',24,'全唐诗/poet.song.233000.json','["自言勤教督，燈火與之對。", "淵明定不孤，門戶期汝大。"]'),
('1627806c-b6d0-46e8-a20c-4731eb9e4a30','賈節菴冒夏暑越修塗過我苕霅情誼甚厚令聞古式無思大節不可復見而骨肉消息訪問難真相對殆感慨不能爲懷青燈夜語誦少陵夜闌更秉燭相對如夢寐之句意甚惘然其歸也兒曹以此爲韻賦詩道別余亦作焉衰老拙惡姑寫我懷且以卜後期云爾  其八','牟巘','宋','宋诗','song-poetry','','[]','我爲饑寒困，坐遣恩義疏。',24,'全唐诗/poet.song.233000.json','["我爲饑寒困，坐遣恩義疏。", "君固不忘我，我愧當何如。"]'),
('4797d3c6-b438-4ad7-a114-8a38b7510360','賈節菴冒夏暑越修塗過我苕霅情誼甚厚令聞古式無思大節不可復見而骨肉消息訪問難真相對殆感慨不能爲懷青燈夜語誦少陵夜闌更秉燭相對如夢寐之句意甚惘然其歸也兒曹以此爲韻賦詩道別余亦作焉衰老拙惡姑寫我懷且以卜後期云爾  其九','牟巘','宋','宋诗','song-poetry','','[]','連宵接軟語，共說夢中夢。',24,'全唐诗/poet.song.233000.json','["連宵接軟語，共說夢中夢。", "聚行時未多，歸驂忽已動。"]'),
('7743b40e-84aa-4b62-b559-b30fd4f2b3c8','賈節菴冒夏暑越修塗過我苕霅情誼甚厚令聞古式無思大節不可復見而骨肉消息訪問難真相對殆感慨不能爲懷青燈夜語誦少陵夜闌更秉燭相對如夢寐之句意甚惘然其歸也兒曹以此爲韻賦詩道別余亦作焉衰老拙惡姑寫我懷且以卜後期云爾  其一○','牟巘','宋','宋诗','song-poetry','','[]','別餞別尤苦，輾轉那得寐。',24,'全唐诗/poet.song.233000.json','["別餞別尤苦，輾轉那得寐。", "後會倘可期，握手三致意。"]'),
('07f82018-5c9e-4d7a-a957-0f8f1463bb2a','拂菻天馬圖','牟巘','宋','宋诗','song-poetry','','[]','赤手謝銜轡，踏蹴翻九衢。',24,'全唐诗/poet.song.233000.json','["赤手謝銜轡，踏蹴翻九衢。", "健哉此女子，果勝大丈夫。"]'),
('d024c189-38a5-440b-b470-ed8f97515b4a','和漁具十絕  其一','牟巘','宋','宋诗','song-poetry','','[]','買得五瀉舟，江湖落我手。',24,'全唐诗/poet.song.233000.json','["買得五瀉舟，江湖落我手。", "呼兒下笥去，此事渠能了。"]'),
('dddb0ecb-adbd-49dd-bc24-8a819393a78e','和漁具十絕  其二','牟巘','宋','宋诗','song-poetry','','[]','卧吹月明裏，龍吟鼉打鼓。',24,'全唐诗/poet.song.233000.json','["卧吹月明裏，龍吟鼉打鼓。", "別是一家風，荻花擺頭舞。"]'),
('61b5cb0a-3d8c-41a7-9198-fb7da1785042','和漁具十絕  其三','牟巘','宋','宋诗','song-poetry','','[]','披時響蕭騷，卧處堆偪仄。',24,'全唐诗/poet.song.233000.json','["披時響蕭騷，卧處堆偪仄。", "傲然烟雨中，安知有睢澤。"]'),
('f7d8ebac-29f7-47c9-8481-19284ce1b50a','和漁具十絕  其四','牟巘','宋','宋诗','song-poetry','','[]','輕圓兀其顛，不受暑雨厄。',24,'全唐诗/poet.song.233000.json','["輕圓兀其顛，不受暑雨厄。", "時將篷外挂，旋轉卷七澤。"]'),
('7e89a2bf-81f8-4991-8e63-bce3b9798c63','和漁具十絕  其五','牟巘','宋','宋诗','song-poetry','','[]','裊裊不自持，何以制沈犗。',24,'全唐诗/poet.song.233000.json','["裊裊不自持，何以制沈犗。", "聊懸一魴餌，鯨鱣未可狎。"]'),
('188cd2a8-7e45-46bc-8a9b-cf3d80b66070','和漁具十絕  其六','牟巘','宋','宋诗','song-poetry','','[]','彼已苦其密，此猶患其疏。',24,'全唐诗/poet.song.233000.json','["彼已苦其密，此猶患其疏。", "歡呼試新網，一舉雙白魚。"]'),
('2cdc1099-c000-4e8c-a635-6877d1d647af','和漁具十絕  其七','牟巘','宋','宋诗','song-poetry','','[]','熒熒枯蚌中，急雪灑不滅。',24,'全唐诗/poet.song.233000.json','["熒熒枯蚌中，急雪灑不滅。", "西風明日晴，雙花爲儂結。"]'),
('d8e569eb-0696-437d-8559-bed95e7e8bd9','和漁具十絕  其八','牟巘','宋','宋诗','song-poetry','','[]','呼風忙趁魚，一片如掌大。',24,'全唐诗/poet.song.233000.json','["呼風忙趁魚，一片如掌大。", "且等後船來，過船猶早在。"]'),
('192e3be3-6795-4199-a096-755201cc6c70','和漁具十絕  其九','牟巘','宋','宋诗','song-poetry','','[]','登登遠還合，聲從何處起。',24,'全唐诗/poet.song.233000.json','["登登遠還合，聲從何處起。", "魚走潛深波，禍在深波裏。"]'),
('c979722d-c1e1-43bb-adbd-42a420aecc2b','和漁具十絕  其一○','牟巘','宋','宋诗','song-poetry','','[]','即此是庾冰，醉棹舞波面。',24,'全唐诗/poet.song.233000.json','["即此是庾冰，醉棹舞波面。", "何似宮亭湖，爲我覓如願。"]'),
('91deaafc-ae89-4c0b-b0ca-2cc46d32bb79','贈薛東湖  其一','牟巘','宋','宋诗','song-poetry','','[]','抱疴蓬廬下，白日背我馳。',24,'全唐诗/poet.song.233000.json','["抱疴蓬廬下，白日背我馳。", "我生已如此，天命復奚疑。"]'),
