('86d77788-926d-4957-9ed9-33df87925f3c','送戚性傳','牟巘','宋','宋诗','song-poetry','','[]','睢陽書院戚先生，綸也名孫侍從臣。',32,'全唐诗/poet.song.233000.json','["睢陽書院戚先生，綸也名孫侍從臣。", "文物相傳今幾葉，又開講席淑來人。"]'),
('c8f7ab45-743e-44f7-80d7-9b054f1057a4','送蕭之剛','牟巘','宋','宋诗','song-poetry','','[]','旬宣幕府得君重，直到千峰盡處回。',32,'全唐诗/poet.song.233000.json','["旬宣幕府得君重，直到千峰盡處回。", "聞道棠陰春更綠，不妨依舊入東來。"]'),
('0b7aca25-7aa9-4eef-a3e8-5ed5456df5f8','倦書圖  其一','牟巘','宋','宋诗','song-poetry','','[]','日長偏困校讐人，袖手旁觀亦欠伸。',32,'全唐诗/poet.song.233000.json','["日長偏困校讐人，袖手旁觀亦欠伸。", "一覺黑甜酣午枕，絕憐識字苦勞神。"]'),
('990899d2-d99d-4632-9a35-41bd1f88ae00','倦書圖  其二','牟巘','宋','宋诗','song-poetry','','[]','誰道春酣雨不禁，蒙籠眼色透雲屏。',32,'全唐诗/poet.song.233000.json','["誰道春酣雨不禁，蒙籠眼色透雲屏。", "著人花氣深於霧，却是三郎睡未醒。"]'),
('de56c05b-2a03-4811-9d24-39038ed56497','題高麗字跡','牟巘','宋','宋诗','song-poetry','','[]','片紙殷勤贈跋篇，來從箕子舊朝鮮。',32,'全唐诗/poet.song.233000.json','["片紙殷勤贈跋篇，來從箕子舊朝鮮。", "六經原不經秦火，好爲刊傳惠後賢。"]'),
('c07c378a-2af0-48b1-ac4b-7abb8c25fd09','毗山之居不皆竹也而其所尚友獨在竹遂擅此山予觀野縱橫陳荆扉半啟小舟划柳下不覺欣然呼渡徑入萬竹烟霏中山靈頗怪俗客何自來耶因留詩云  其一','牟巘','宋','宋诗','song-poetry','','[]','指點山居向那邊，閉門花木養風烟。',32,'全唐诗/poet.song.233000.json','["指點山居向那邊，閉門花木養風烟。", "鄰人不饌蒼玉束，一一而今欲造天。"]'),
('3a68af87-8abb-40e0-b422-349a0468d528','毗山之居不皆竹也而其所尚友獨在竹遂擅此山予觀野縱橫陳荆扉半啟小舟划柳下不覺欣然呼渡徑入萬竹烟霏中山靈頗怪俗客何自來耶因留詩云  其二','牟巘','宋','宋诗','song-poetry','','[]','山人猶未出山時，風月雲烟總爲詩。',32,'全唐诗/poet.song.233000.json','["山人猶未出山時，風月雲烟總爲詩。", "笑問年來間何闊，此盟應有此君知。"]'),
('63fa8a83-2a78-4caa-bcbb-7a47204a1549','右軍書裙帖','牟巘','宋','宋诗','song-poetry','','[]','戲將墨妙寫烟雲，曉起驚呼失素裙。',32,'全唐诗/poet.song.233000.json','["戲將墨妙寫烟雲，曉起驚呼失素裙。", "盡洗當年羞澀態，從今不比舊羊欣。"]'),
('fdd0219b-cec6-492a-bbae-0bf33387ec8d','題四畫  其一','牟巘','宋','宋诗','song-poetry','','[]','天氣融和凍已開，桃花浪暖亦佳哉。',32,'全唐诗/poet.song.233000.json','["天氣融和凍已開，桃花浪暖亦佳哉。", "人生辦取東南尉，底用一雙鸂鶒來。"]'),
('7d6fcda8-e860-40a2-a67b-398211cf7e85','題四畫  其二','牟巘','宋','宋诗','song-poetry','','[]','多情宛頸兩鴛鴦，貪趁湖心錯裹香。',32,'全唐诗/poet.song.233000.json','["多情宛頸兩鴛鴦，貪趁湖心錯裹香。", "散髮幽人休盪槳，夜深花露濕衣裳。"]'),
('2d03937f-b127-4ece-9673-fe83b98e301e','題四畫  其三','牟巘','宋','宋诗','song-poetry','','[]','金飈爭放木夫容，蘸影清波分外紅。',32,'全唐诗/poet.song.233000.json','["金飈爭放木夫容，蘸影清波分外紅。", "玉立前庭一公子，丰標不與俗人同。"]'),
('04c96b54-6482-4b29-bec5-857cbb8236bb','題四畫  其四','牟巘','宋','宋诗','song-poetry','','[]','積雪凝寒不肯融，梅花佇立待春風。',32,'全唐诗/poet.song.233000.json','["積雪凝寒不肯融，梅花佇立待春風。", "嫩波正比鴨頭綠，厚葉休嗤鶴頂紅。"]'),
('e59eb6ca-3341-4439-8884-bd11c6d5b2cc','南岳魏監廟曩自請奉祠恬於聲利十餘年來益閉戶讀易人罕識之余托婣且契比來吳惠教五絕篤敘故舊情誼藹然用韻復寄不足酬盛意  其一','牟巘','宋','宋诗','song-poetry','','[]','人生一世匆匆爾，筵帙亡何已旅酬。',32,'全唐诗/poet.song.233000.json','["人生一世匆匆爾，筵帙亡何已旅酬。", "南岳罏頭芋初熟，等閒知閲幾春秋。"]'),
('4c1f6b0f-c29a-4ca4-b1fe-59442dafaa3e','南岳魏監廟曩自請奉祠恬於聲利十餘年來益閉戶讀易人罕識之余托婣且契比來吳惠教五絕篤敘故舊情誼藹然用韻復寄不足酬盛意  其二','牟巘','宋','宋诗','song-poetry','','[]','誰知白鶴早登門，遺墨猶餘屋漏痕。',32,'全唐诗/poet.song.233000.json','["誰知白鶴早登門，遺墨猶餘屋漏痕。", "師友百年同慧脈，固應自有不云存。"]'),
('707a00e4-fb55-4e48-bc39-45f71d055ba4','南岳魏監廟曩自請奉祠恬於聲利十餘年來益閉戶讀易人罕識之余托婣且契比來吳惠教五絕篤敘故舊情誼藹然用韻復寄不足酬盛意  其三','牟巘','宋','宋诗','song-poetry','','[]','全真閉戶魏不琢，二紀怡然外世榮。',32,'全唐诗/poet.song.233000.json','["全真閉戶魏不琢，二紀怡然外世榮。", "留得詩名皮陸集，到君句法有餘清。"]'),
('09cb0de2-7e46-4824-8f1b-7274c52cfd61','南岳魏監廟曩自請奉祠恬於聲利十餘年來益閉戶讀易人罕識之余托婣且契比來吳惠教五絕篤敘故舊情誼藹然用韻復寄不足酬盛意  其四','牟巘','宋','宋诗','song-poetry','','[]','阿囝離鸞嗟囑耳，誰陪老婦祭瓶盆。',32,'全唐诗/poet.song.233000.json','["阿囝離鸞嗟囑耳，誰陪老婦祭瓶盆。", "二雛幸足寬懷抱，共說河汾有外孫。"]'),
('26f435ae-bb10-4b44-b535-d3ef978289f3','南岳魏監廟曩自請奉祠恬於聲利十餘年來益閉戶讀易人罕識之余托婣且契比來吳惠教五絕篤敘故舊情誼藹然用韻復寄不足酬盛意  其五','牟巘','宋','宋诗','song-poetry','','[]','靜探五一共誰論，悔不當初逕扣門。',32,'全唐诗/poet.song.233000.json','["靜探五一共誰論，悔不當初逕扣門。", "自笑吾玄今尚白，刻舟空守舊時痕。"]'),
('eb12d2a3-07dc-47e9-a624-bf241af87f68','三禽  其一','牟巘','宋','宋诗','song-poetry','','[]','何處飛來把修竹，數聲圓活夢還驚。',32,'全唐诗/poet.song.233000.json','["何處飛來把修竹，數聲圓活夢還驚。", "雨鳩那解知人意，寂寞梨花雨又晴。"]'),
('a5ffb910-7307-4a70-84e7-4fa951de0bec','三禽  其二','牟巘','宋','宋诗','song-poetry','','[]','風裏空餘碧玉柯，離離秋子不勝多。',32,'全唐诗/poet.song.233000.json','["風裏空餘碧玉柯，離離秋子不勝多。", "莫教却向人間語，金井銀牀愁奈何。"]'),
('fe953ca1-6f0c-4967-a6cf-0df331ee7ecb','送恩上人還雲門  其一','牟巘','宋','宋诗','song-poetry','','[]','當日親曾見珙公，如雷辨舌振宗風。',32,'全唐诗/poet.song.233000.json','["當日親曾見珙公，如雷辨舌振宗風。", "分明句句字字是，又向苕川訪病翁。"]'),
('61b5b180-6a23-43dc-bc9f-4e271346ceda','送恩上人還雲門  其二','牟巘','宋','宋诗','song-poetry','','[]','澈師何處覓遺蹤，坐聽雲門寺裏鐘。',32,'全唐诗/poet.song.233000.json','["澈師何處覓遺蹤，坐聽雲門寺裏鐘。", "正自年來苦行脚，箇中元自有千峰。"]'),
('b07e7a21-7ec9-4245-a627-2cc1e3f9d99c','挽楊知府  其一','牟巘','宋','宋诗','song-poetry','','[]','蜀有古愛直，公爲令子孫。',48,'全唐诗/poet.song.233000.json','["蜀有古愛直，公爲令子孫。", "駐原曾婉畫，治獄輒平反。", "槁落榮觀盡，紆徐雅道存。", "靈光洞劫火，德齒晚彌尊。"]'),
('b55ba4ee-dc7f-4106-ac09-2adfff82de34','挽楊知府  其二','牟巘','宋','宋诗','song-poetry','','[]','骯髒群飛外，康强七袠餘。',48,'全唐诗/poet.song.233000.json','["骯髒群飛外，康强七袠餘。", "耆年猶謹禮，細字每抄書。", "十載甘琳館，三州奉板輿。", "挂冠天未可，雙犢老康廬。"]'),
('a696d900-9fa3-46b6-9173-e8e13a38ad08','挽楊知府  其三','牟巘','宋','宋诗','song-poetry','','[]','見說佳眠食，遺身疾自無。',48,'全唐诗/poet.song.233000.json','["見說佳眠食，遺身疾自無。", "方期操几杖，俄已易牀膚。", "久讀耆舊傳，仍聯嫁娶圖。", "湘岑望不到，灑淚向天隅。"]'),
('116e1312-1411-4dcb-b5ba-a3bd1e57fe11','挽師叔理  其一','牟巘','宋','宋诗','song-poetry','','[]','卓爾見成鐻，超然驚絕塵。',48,'全唐诗/poet.song.233000.json','["卓爾見成鐻，超然驚絕塵。", "形骸脫邊幅，肝膈炯精神。", "正自關天分，應難語俗人。", "誰收身後稿，雋逸更清新。"]'),
('c7f9108a-814d-48fe-b9d6-b4fd1550b5b7','挽師叔理  其二','牟巘','宋','宋诗','song-poetry','','[]','已飽憂患味，方收翰墨勳。',48,'全唐诗/poet.song.233000.json','["已飽憂患味，方收翰墨勳。", "龍飛新進士，猿臂老將軍。", "千里推車軸，群工愧斧斤。", "天乎如有意，更爲續斯文。"]'),
('80c38ed3-3cfa-4ff1-9de1-9286bbe2f8d6','挽師叔理  其三','牟巘','宋','宋诗','song-poetry','','[]','四海東坡老，平生秦太虛。',48,'全唐诗/poet.song.233000.json','["四海東坡老，平生秦太虛。", "神遊已冥漠，坐念更欷歔。", "手墨看猶濕，心期炯未疏。", "堪憐疇昔語，腹痛勿驅車。"]'),
('29c7374b-9ee6-4b8d-9cf2-423f1b7e2e04','挽趙春谷  其一','牟巘','宋','宋诗','song-poetry','','[]','墮地追風驥，垂天駕海鵬。',48,'全唐诗/poet.song.233000.json','["墮地追風驥，垂天駕海鵬。", "嗟哉中道止，藉甚到今稱。", "幾士待舉火，一生甘飲冰。", "居然使跖壽，念此拂人膺。"]'),
('19ae37d6-01a5-47bd-8d89-4f577119d02c','挽趙春谷  其二','牟巘','宋','宋诗','song-poetry','','[]','子美轉同谷，靈均懷此都。',48,'全唐诗/poet.song.233000.json','["子美轉同谷，靈均懷此都。", "修名千載短，多難一臣孤。", "天意終難料，心期自不渝。", "西風吹更急，蕭索間泉途。"]'),
('8c7a8e85-5647-4162-936b-6ebc4f576ad5','挽趙春谷  其三','牟巘','宋','宋诗','song-poetry','','[]','北弁方胥會，西崦遽莫追。',48,'全唐诗/poet.song.233000.json','["北弁方胥會，西崦遽莫追。", "津梁摩詰病，臺沼雍門悲。", "鶴有還家夢，烏無反哺期。", "瀧岡松檟近，足慰九原思。"]'),
('722a2864-50c2-45de-a947-4c2fcda3dfe0','挽孫太監','牟巘','宋','宋诗','song-poetry','','[]','埋玉愁聞薤露歌，向來耆艾日消磨。',64,'全唐诗/poet.song.233000.json','["埋玉愁聞薤露歌，向來耆艾日消磨。", "平生所至棠陰在，晚歲其如麥秀何。", "洛社竟虛同甲會，鑑湖應改舊時波。", "四春手植煩調護，萬感今猶憶爛柯。"]'),
('c6a7a39b-78ef-4e23-b286-45d69e9f19eb','挽陳本齋尚書  其一','牟巘','宋','宋诗','song-poetry','','[]','在昔實齋老，公能繼盛名。',48,'全唐诗/poet.song.233000.json','["在昔實齋老，公能繼盛名。", "平生守師說，晚歲萃儒榮。", "禋赦原兵禍，臺綱忤物情。", "抽身甬東去，騰上幾公卿。"]'),
('33d05d7f-bb02-4048-b06b-4da44e3d0863','挽陳本齋尚書  其二','牟巘','宋','宋诗','song-poetry','','[]','天俾公多壽，人知道不孤。',48,'全唐诗/poet.song.233000.json','["天俾公多壽，人知道不孤。", "超然一室內，不與萬波俱。", "甲子新詩稿，烝嘗舊布襦。", "何妨傳遺老，文字照龜趺。"]'),
('59bc78eb-748a-411e-81b7-16eeafeb1958','挽陳本齋尚書  其三','牟巘','宋','宋诗','song-poetry','','[]','有意超塵俗，無心愛夕暉。',48,'全唐诗/poet.song.233000.json','["有意超塵俗，無心愛夕暉。", "勸餐惟屢却，持璧竟全歸。", "得正復奚憾，偷生良所非。", "傳家孫子盛，端不墜前徽。"]'),
('d0147b6d-03f4-4960-8269-d206a9fb3b72','挽王厚齋尚書  其一','牟巘','宋','宋诗','song-poetry','','[]','清要三朝望，文章一世榮。',48,'全唐诗/poet.song.233000.json','["清要三朝望，文章一世榮。", "掌綸誇獨直，荷橐表群英。", "石室資殫洽，金華頼闡明。", "孤臣傷暮景，風雨自鷄鳴。"]'),
('346e0114-9f4e-4ad1-80f4-e066fe2cd6a5','挽王厚齋尚書  其二','牟巘','宋','宋诗','song-poetry','','[]','開慶言容悅，咸淳奏直前。',48,'全唐诗/poet.song.233000.json','["開慶言容悅，咸淳奏直前。", "每逢時宰怒，自保哲人全。", "垂世三千卷，歸田二十年。", "汾亭有遺操，獨拍淚潸然。"]'),
('c202e5c2-e50a-4274-8922-3e4dbb837a73','挽王厚齋尚書  其三','牟巘','宋','宋诗','song-poetry','','[]','文獻遺諸老，風霜魯殿餘。',48,'全唐诗/poet.song.233000.json','["文獻遺諸老，風霜魯殿餘。", "斯人不可贖，吾道意何如。", "永念年家好，曾聯選部居。", "無由陪縞送，東望淚沾裾。"]'),
('ef908af7-c542-446f-a2a8-4dccc7b6f320','挽成峨峰  其一','牟巘','宋','宋诗','song-poetry','','[]','輕舉游帷宅，高辭神武門。',48,'全唐诗/poet.song.233000.json','["輕舉游帷宅，高辭神武門。", "賜湖分老監，遺笏付諸孫。", "玉映神尤朗，丹成道自真。", "只應峩頂月，萬里照仙魂。"]'),
('8d9faee3-2d9f-4155-8412-c36bfb3a8530','挽成峨峰  其二','牟巘','宋','宋诗','song-poetry','','[]','吾叔聯姻好，當年記漢嘉。',48,'全唐诗/poet.song.233000.json','["吾叔聯姻好，當年記漢嘉。", "回頭一甲子，遺恨滿天涯。", "尚喜長庚老，俄聞大耋嗟。", "區區論疇昔，何處挹蜚霞。"]'),
('cad410f5-2212-493b-8eb5-24922ddc28af','挽趙止善  其一','牟巘','宋','宋诗','song-poetry','','[]','自處若素士，不知爲貴游。',48,'全唐诗/poet.song.233000.json','["自處若素士，不知爲貴游。", "多聞每是正，寡欲更清修。", "方借望郎重，已深宗國憂。", "嗟哉事竟爾，喬木委林丘。"]'),
('3ab4c76d-58aa-4508-907a-da2255331352','挽趙止善  其二','牟巘','宋','宋诗','song-poetry','','[]','昔日三株樹，彫容頓可驚。',48,'全唐诗/poet.song.233000.json','["昔日三株樹，彫容頓可驚。", "一癯危獨坐，多難失孤撐。", "官舍煎茶夢，天涯裹飯情。", "無由送車後，抆淚愧平生。"]'),
('6dccef22-4ceb-4d03-8410-e8c5656597c2','挽親家孟從吾','牟巘','宋','宋诗','song-poetry','','[]','東野哭其子，難存百感身。',48,'全唐诗/poet.song.233000.json','["東野哭其子，難存百感身。", "孤孫猶在抱，行路亦沾巾。", "滿目家園樹，何時淚葉春。", "諸生爲執紼，良足化鄉人。"]'),
('9ed345fc-e5a1-430a-b8bd-501bf6424480','挽岳君舉','牟巘','宋','宋诗','song-poetry','','[]','五十餘年事，都將作夢看。',48,'全唐诗/poet.song.233000.json','["五十餘年事，都將作夢看。", "早方磨鐵硯，老遂葬桐棺。", "蟻結途方戒，駒馳歲已闌。", "山前一片石，讀者爲悲酸。"]'),
('cb011088-bad5-4131-b547-84cbd2aa6cff','挽姚景春','牟巘','宋','宋诗','song-poetry','','[]','昔在仙都世，人稱善士門。',48,'全唐诗/poet.song.233000.json','["昔在仙都世，人稱善士門。", "丘山歎華屋，風雨長孤根。", "鶴瘦空餘影，鴻冥更斷魂。", "植齋書萬卷，喜有外孫存。"]'),
('915ebe50-f4fa-4d05-ab0e-93e6f08ff936','挽趙碧蘭母劉氏','牟巘','宋','宋诗','song-poetry','','[]','苗裔真王後，儀型老監同。',48,'全唐诗/poet.song.233000.json','["苗裔真王後，儀型老監同。", "庭惟參玉樹，氣未感秋蓬。", "衣制先期具，舟藏半夜空。", "故應芳懿在，位刻賁幽宮。"]'),
('3771dabc-94f9-4723-a1f1-4455b02cbd01','挽張師道  其一','牟巘','宋','宋诗','song-poetry','','[]','少日追楊晏，由來間氣鍾。',48,'全唐诗/poet.song.233000.json','["少日追楊晏，由來間氣鍾。", "兩科無近比，萬里有奇逢。", "正喜鼇扉重，俄驚鵩舍凶。", "輤車方遠稅，已見若堂封。"]'),
('6f3f6a00-d228-4bc1-9bc4-212d332f3459','挽張師道  其二','牟巘','宋','宋诗','song-poetry','','[]','在昔台州守，先人事分多。',48,'全唐诗/poet.song.233000.json','["在昔台州守，先人事分多。", "通家能記憶，上冢每來過。", "老我病未死，送君情奈何。", "賢哉幸有子，健翮看雲摩。"]'),
('076406e5-ae5d-4dde-a4b5-63e2f3aad0c6','挽唐學賓','牟巘','宋','宋诗','song-poetry','','[]','奕世詩書味，端知積慶長。',48,'全唐诗/poet.song.233000.json','["奕世詩書味，端知積慶長。", "於人不畦畛，爲世作津梁。", "肯助魯修泮，能令齊發棠。", "陰功天所相，食報在諸郎。"]'),
('372ff123-f4d2-45a7-b2c1-355f1f03cce6','有翅天馬圖','牟巘','宋','宋诗','song-poetry','','[]','何年塵鏡昏乍洗，金背湧出狀怪詭。',165,'全唐诗/poet.song.233000.json','["何年塵鏡昏乍洗，金背湧出狀怪詭。", "自古空言馬生角，今乃見馬生兩翅。", "恐是渥漥種，往往感龍氣。", "龍惟神，飛行天，若傅兩翅何足貴。", "想似穆天子會瑶池，肉多身重不得飛。", "一朝乘之逍遥出六合，奔風軼電那容追。", "萬里一息日未旰，當時從官無乃疲。", "或云車轍馬迹往往有，如此安用彼翅爲。", "徒留誕譎誑後世，我願觀者更勿疑。", "我聞西王母，參目而虎首，物以類應固宜爾。"]'),
('8d6c72c8-cc17-4f00-809f-b86290225e26','跋恩上人詩','牟巘','宋','宋诗','song-poetry','','[]','把斷風光不許通，坐天目頂月明中。',32,'全唐诗/poet.song.233000.json','["把斷風光不許通，坐天目頂月明中。", "下方雷作嬰兒叫，莫是山僧耳太聰。"]'),
('6fa8e51f-f6cd-467a-89cc-40500bc296f3','宴交代楊寺丞樂語口號','牟巘','宋','宋诗','song-poetry','','[]','眉間黄色喜浮浮，天遣鸞皇爲相攸。',64,'全唐诗/poet.song.233000.json','["眉間黄色喜浮浮，天遣鸞皇爲相攸。", "新綰絲綸歸右掖，舊游泉石記南州。", "春風自滿甘棠國，曉雪初晴杜若洲。", "樂飲更爲三百住，邦人未許別賢侯。"]'),
('3b1f7ec0-4c4a-4bae-9750-85ec7ba78a74','宴公孫倅樂語口號','牟巘','宋','宋诗','song-poetry','','[]','後先相守是鄉人，自有都梁見未曾。',64,'全唐诗/poet.song.233000.json','["後先相守是鄉人，自有都梁見未曾。", "藥玉船中頻送酒，鏤金勝畔又行燈。", "雁橋舊夢猶能記，鳳闕新除自此升。", "一笑不妨追樂事，坐看諸縣樂豐登。"]'),
('6f03a442-1652-42cd-bdec-61b8aa63d7d1','宴交代趙寺丞樂語口號','牟巘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','帝教雲牧重雲山，柱輒清朝玉立班。',64,'全唐诗/poet.song.233000.json','["帝教雲牧重雲山，柱輒清朝玉立班。", "八月星槎來海上，九天藜杖照人間。", "煩公政事文章手，開此江山父老顔。", "若到西湖應記取，明年此日看徵環。"]'),
('ccde079d-aedd-4462-9b29-076db9089d73','宴黄倅樂語口號','牟巘','宋','宋诗','song-poetry','','[]','向來南岳鳳曾鳴，再駕緹屏又一星。',64,'全唐诗/poet.song.233000.json','["向來南岳鳳曾鳴，再駕緹屏又一星。", "文物君謨丹荔譜，江山白傅百花亭。", "舂容相與頻呼斝，肯綮爭看妙發硎。", "紫橐青氈吾舊物，孔鸞行矣集明廷。"]'),
('41865cae-596a-479c-bf0d-9629eac4edda','燕交代□□樂語口號','牟巘','宋','宋诗','song-poetry','','[]','兩君先後締交承，一笑何妨玉斝傾。',64,'全唐诗/poet.song.233000.json','["兩君先後締交承，一笑何妨玉斝傾。", "馳馹催人來異渥，卧龍留客自多情。", "告新聽說三年最，敘舊欣尋再世盟。", "天上除書人已到，便看鵠立侍通明。"]'),
('19e014ce-068a-4081-9ece-d209bdfd163b','宴安撫洪尚書樂語口號','牟巘','宋','宋诗','song-poetry','','[]','琱戈紅旆轡如絲，暫爲君王鎮左畿。',64,'全唐诗/poet.song.233000.json','["琱戈紅旆轡如絲，暫爲君王鎮左畿。", "下鵠池邊新有詔，卧龍山畔又催歸。", "共看閣老今黄闥，却笑門生也繡衣。", "起舞祝公千歲壽，蓬萊雲氣正霏霏。"]'),
('8bf17828-8f8c-40df-af09-498faea65f16','奉寄沈公介石老仙','牟巘','宋','宋诗','song-poetry','','[]','不貪富貴即神仙，茗椀香爐古易編。',64,'全唐诗/poet.song.233000.json','["不貪富貴即神仙，茗椀香爐古易編。", "誰向急流能勇退，方知介石是幾先。", "三危露下聞清唳，九鎖山中斷俗緣。", "喜有詩人相共住，何時一笑醉丹泉。"]'),
('1685d8f0-847a-4a79-9b50-2a9cc11cb602','送婁伯高遊吳','牟巘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','桃花水暖清明前，長堤柳色青如烟。',160,'全唐诗/poet.song.233000.json','["桃花水暖清明前，長堤柳色青如烟。", "男兒年少重意氣，春風買醉吳江船。", "西湖三月春更好，笙歌錦繡神仙鳥。", "紫燕樓深翠黛間，碧羅天凈楊花老。", "興亡往事置勿論，千金不惜酬歌尊。", "酒酣莫作後庭曲，游人思斷江南魂。", "去去知君訪陳迹，吳山吳水青歷歷。", "花殘鈿碎館娃空，春草年年爲誰碧。", "君行正樂我爲愁，白髮送君思舊遊。", "平生漫浪無似我，努力功名須黑頭。"]'),
('3bc323fb-01d9-400b-a06a-cb346e108ba8','題水竹居','牟巘','宋','宋诗','song-poetry','','[]','繞屋清波隔翠綃，魚鱗發發鳥翛翛。',64,'全唐诗/poet.song.233000.json','["繞屋清波隔翠綃，魚鱗發發鳥翛翛。", "畫闌影漾清漣動，書几陰來綠雨摇。", "文采巧當鮫杼薄，秋聲微度玉笙嬌。", "豈惟釣艇終堪繫，况是佳人不待招。"]'),
('d9265846-fa8f-43a8-a35c-d5c221ad76aa','句','牟巘','宋','宋诗','song-poetry','','[]','翻手可覆手，曲身成直身。',12,'全唐诗/poet.song.233000.json','["翻手可覆手，曲身成直身。"]'),
('9d7fb881-36cf-496e-96d3-fb626474f2d7','秦鸞曲','陳允平','宋','宋诗','song-poetry','','[]','盈盈白玉鈿，裊裊黄金縷。',48,'全唐诗/poet.song.233000.json','["盈盈白玉鈿，裊裊黄金縷。", "拍拍水晶奩，皎皎珊瑚樹。", "簾前雙燕飛，門外桃花雨。", "無處說相思，羞對秦鸞舞。"]'),
('77ed89c9-23f9-4460-af3a-04123a67e9b3','登吳山','陳允平','宋','宋诗','song-poetry','','[]','登高一展眺，宮樹鬰嵯峨。',48,'全唐诗/poet.song.233000.json','["登高一展眺，宮樹鬰嵯峨。", "樓閣春風滿，東南王氣多。", "青天行日月，大地布山河。", "柳色沙堤路，時聞響玉珂。"]'),
('b7ee83e8-bebd-4648-8053-d09854c7505d','明皇按樂圖','陳允平','宋','宋诗','song-poetry','','[]','日日霓裳宴綵樓，三千歌粉侍宸旒。',64,'全唐诗/poet.song.233000.json','["日日霓裳宴綵樓，三千歌粉侍宸旒。", "月明宮殿雙龍伏，雲擁簫韶九鳳游。", "翠袖半籠金約臂，寶釵斜墜玉搔頭。", "不知舞到弓彎處，一拍春風一拍愁。"]'),
('dcc0a061-0804-4af1-b5c9-0a806cc5b19e','鄂王墓','陳允平','宋','宋诗','song-poetry','','[]','鄂王墓在棲霞嶺，一片忠魂萬古存。',64,'全唐诗/poet.song.233000.json','["鄂王墓在棲霞嶺，一片忠魂萬古存。", "鏡裏赤心懸日月，劍邊英氣塞乾坤。", "蒼苔雨暗龍蛇壁，老樹烟凝虎豹旛。", "獨倚東風揮客淚，不堪回首望中原。"]'),
('04c01b5f-7c7e-4e6c-824c-1f03afb7b181','賀伯父大資休致','陳允平','宋','宋诗','song-poetry','','[]','不戀清時白玉璫，便將身世寄滄浪。',64,'全唐诗/poet.song.233000.json','["不戀清時白玉璫，便將身世寄滄浪。", "三朝元老黄樞閣，四海閑人綠野堂。", "楚楚菁蘭秋带雨，蕭蕭寒菊晚宜霜。", "擬成東甬耆英社，賸樂壺天日月長。"]'),
('198c6724-58d4-44a7-b0dd-d304a7a63056','送中上人遊天台','陳允平','宋','宋诗','song-poetry','','[]','師作天台去，長亭復短亭。',48,'全唐诗/poet.song.233000.json','["師作天台去，長亭復短亭。", "焚香參祖塔，振錫動山靈。", "石罅移菖歜，松根斸茯苓。", "何時白雲下，相與話青青。"]'),
('6301405a-8ed4-49b5-a2e6-6315ecfd4412','寄王尊師','陳允平','宋','宋诗','song-poetry','','[]','彩雲繚繞七香車，洞裏神仙煉紫霞。',32,'全唐诗/poet.song.233000.json','["彩雲繚繞七香車，洞裏神仙煉紫霞。", "華表鶴歸春寂寂，東風吹盡碧桃花。"]'),
('24c52b70-20cd-40d7-9c54-724f874b8478','過田家','陳允平','宋','宋诗','song-poetry','','[]','村南啼布穀，村北響繅車。',48,'全唐诗/poet.song.233000.json','["村南啼布穀，村北響繅車。", "隔浦賣魚市，傍橋沽酒家。", "野花朝日暖，溪柳背風斜。", "又過東鄰去，東鄰採菊芽。"]'),
('a81a4d93-8de2-410c-a6c3-99927363b18d','秋暮登太白','陳允平','宋','宋诗','song-poetry','','[]','飄飄短褐袍，倚杖立金鼇。',48,'全唐诗/poet.song.233000.json','["飄飄短褐袍，倚杖立金鼇。", "橋束溪流急，樹增山勢高。", "白雲連海嶠，黄葉滿亭臯。", "落日西風惡，塵埃兩鬢毛。"]'),
('73bed2e2-e49d-48d8-88e6-bf0138bc3378','雪','陳允平','宋','宋诗','song-poetry','','[]','樓臺萬瓦玉鱗鱗，遮盡人間富與貧。',32,'全唐诗/poet.song.233000.json','["樓臺萬瓦玉鱗鱗，遮盡人間富與貧。", "可笑世情剛道冷，不知片片是陽春。"]'),
('4769d3e7-e8ad-40e5-800b-80b3813676e6','觀弈象棋','陳允平','宋','宋诗','song-poetry','','[]','陣勢頻分合，機鋒互應酬。',48,'全唐诗/poet.song.233000.json','["陣勢頻分合，機鋒互應酬。", "馬飛關塞月，砲落漢天秋。", "不問知心友，翻成敵面仇。", "誰能勞勝負，獨立大江流。"]'),
('4c8e8b31-5088-486a-92ee-0202702773f3','香奩體','陳允平','宋','宋诗','song-poetry','','[]','小院薰風滿，閑庭白晝長。',240,'全唐诗/poet.song.233000.json','["小院薰風滿，閑庭白晝長。", "蜻蜓楊柳岸，鸂鶒芰荷塘。", "雲合朱檐卸，山高翠閣涼。", "蔓滋青薜荔，芽長紫良薑。", "簾幕深深地，闌干曲曲廊。", "淡烟瑶草細，流水碧桃香。", "幡影重門靜，苔痕小篆荒。", "螭盤丹鼎雪，龍吸露臺漿。", "琴古翻新調，笙沉靘舊簧。", "雨聲犀角枕，月色象牙牀。", "掌上雙鸚鵡，屏間兩鳳凰。", "石函藏寶劍，金鑰啟瑶箱。", "扇雉團清影，奩鴛試曉妝。", "霞綃衣窄索，雲錦珮玎璫。", "鬢攏金蟬矗，釵橫玉燕翔。", "袂飄天水碧，裙濺鬰金黄。", "太液簫初遠，蓬壺漏未央。", "流星飛碧落，零雨下銀潢。", "去去人千里，迢迢天一方。", "斷腸春洛浦，殘夢夜瀟湘。"]'),
('33bd9525-cee3-47a0-9eab-486408271b93','侍謝立齋小酌湖樓','陳允平','宋','宋诗','song-poetry','','[]','風捲珠簾客珮清，杜鵑啼老送春聲。',64,'全唐诗/poet.song.233000.json','["風捲珠簾客珮清，杜鵑啼老送春聲。", "水浮亭館花間出，船載笙歌柳外行。", "千里夕陽歸夢遠，六橋飛絮馬蹄輕。", "欄干倚遍暮天闊，烟樹一鈎新月生。"]'),
('51da431b-591c-4de2-bb48-92ae87418c6b','題李丹壺壁','陳允平','宋','宋诗','song-poetry','','[]','閑乘海上槎，來訪謫仙家。',48,'全唐诗/poet.song.233000.json','["閑乘海上槎，來訪謫仙家。", "風逆磬聲短，日低旛影斜。", "猿攀高樹果，蜂採半巖花。", "誰在丹臺上，三更煉紫霞。"]'),
('e846ffe2-0e67-475c-bf0f-509d61570b58','謁烏龍廟','陳允平','宋','宋诗','song-poetry','','[]','斷碑猶紀唐時事，山氣陰沉暗綠苔。',64,'全唐诗/poet.song.233000.json','["斷碑猶紀唐時事，山氣陰沉暗綠苔。", "松木已逾千歲壽，香烟知化幾爐灰。", "廊深無月鬼神過，殿古有雲風雨來。", "曲曲九溪春水落，子陵灘下復東回。"]'),
('83389fa1-4520-477a-af3b-dbdd6335aabe','即事','陳允平','宋','宋诗','song-poetry','','[]','重重簾幕燕翩翩，塵鎖朱樓十四絃。',32,'全唐诗/poet.song.233000.json','["重重簾幕燕翩翩，塵鎖朱樓十四絃。", "榆火漸催寒食節，海棠花畔縛秋千。"]'),
('ef6be253-3856-4a01-a945-ac7397746138','春詞','陳允平','宋','宋诗','song-poetry','','[]','楊柳春風三月三，畫橋芳草碧纖纖。',32,'全唐诗/poet.song.233000.json','["楊柳春風三月三，畫橋芳草碧纖纖。", "一雙燕子歸來後，十二紅樓捲繡簾。"]'),
('a6d1b3c4-8727-43c0-9582-13902afd329a','江南謠','陳允平','宋','宋诗','song-poetry','','[]','柳絮飛時話別離，梅花開後待郎歸。',32,'全唐诗/poet.song.233000.json','["柳絮飛時話別離，梅花開後待郎歸。", "梅花開後無消息，更待明年柳絮飛。"]'),
('a8133298-bb93-4d9a-84dc-e4fc18da945c','嘆鏡辭','陳允平','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','憶妾初嫁時，金屋藏窈窕。',139,'全唐诗/poet.song.233000.json','["憶妾初嫁時，金屋藏窈窕。", "忽見洛陽人，鬻鏡長安道。", "明月掌上寒，團團復皎皎。", "千金買得歸，惜之如重寶。", "奩開雙鳳飛，带結青鸞裊。", "當時照妾顔，妾顔正年少。", "如今照妾顔，妾顔羞已老。", "對鏡頻嘆嗟，掩鏡徒懊惱。", "不恨妾嫁遲，惟恨妾生早。", "此恨空綿綿，天涯滿芳草。", "君不見長江逝水無逆流，歲去年來多白頭。"]'),
('6c3eaf5b-33bc-4b0d-9a1f-6c64d622a347','登招寶山','陳允平','宋','宋诗','song-poetry','','[]','宇宙初開闢，何神立此山。',48,'全唐诗/poet.song.233000.json','["宇宙初開闢，何神立此山。", "中流天柱石，大地海門關。", "浪惡蛟龍怒，雲深虎豹閑。", "潮期與日月，千古一循環。"]'),
('6300f272-56b6-40fe-ac65-8ca0a3708af9','秋夜遊東墅','陳允平','宋','宋诗','song-poetry','','[]','雲壓高空雁陣低，江城歷歷草離離。',64,'全唐诗/poet.song.233000.json','["雲壓高空雁陣低，江城歷歷草離離。", "樓臺秋淡玉簫遠，簾幕夜寒銅漏遲。", "明月鷺鷥菱葉浦，西風蟋蟀豆花籬。", "一樽酒盡銀河落，猶有殘鍾出古祠。"]'),
('57891a03-89dd-4729-9a68-cbc92ee8d61b','春遊曲','陳允平','宋','宋诗','song-poetry','','[]','長安二月東風裏，千紅陌上香塵起。',128,'全唐诗/poet.song.233000.json','["長安二月東風裏，千紅陌上香塵起。", "都人歡呼去踏青，馬如游龍車如水。", "兩兩三三爭買花，青樓酒旗三百家。", "長安酒貴人未醉，岸頭芳草日半斜。", "誰家女子嬌似玉，約莫青春十五六。", "鬰金羅带蘇合香，琵琶自度相思曲。", "相思曲，聲斷續，斷續回文不堪讀。", "回文斷續有續時，離腸寸斷無續期。"]'),
('75ed8db8-a921-495d-8f63-7249ddad6c6d','春閨怨','陳允平','宋','宋诗','song-poetry','','[]','妾家住在湘江曲，門枕湘江春水綠。',144,'全唐诗/poet.song.233000.json','["妾家住在湘江曲，門枕湘江春水綠。", "年年長是暮春時，兩岸垂楊啼布穀。", "自君話別湘江頭，獨上層樓彈箜篌。", "蛾眉不掃遠山碧，滿堤芳草春正愁。", "舉頭不見君，但見湘江雲。", "江雲散復聚，妾心空如熏。", "舉頭不見君，但見湘江水。", "江水去復回，妾顔爲誰美。", "湘江雲，湘江水，雲水悠悠何日已。", "舉頭望君君未歸，門前楊柳空依依。"]'),
('177624a7-cd64-4c0e-ac65-9170f142b104','野人家','陳允平','宋','宋诗','song-poetry','','[]','繞江生杜若，滿地長辛夷。',48,'全唐诗/poet.song.233000.json','["繞江生杜若，滿地長辛夷。", "剪草塗新壁，褰藤縛舊籬。", "瓦瓶春貯酒，土竈夜蒸藜。", "獨步歸來晚，東臯雨一犁。"]'),
('79c774bd-b4c6-4ffd-8698-a02573f678ce','遊陽明洞天','陳允平','宋','宋诗','song-poetry','','[]','萬木陰沉鎖石門，烟霞深處近崑崙。',64,'全唐诗/poet.song.233000.json','["萬木陰沉鎖石門，烟霞深處近崑崙。", "洞簫聲接玉臺磬，寶蓋影摇金殿旛。", "湘浦有龍雲氣濕，越山無鶴露華昏。", "靈芝採盡歸何處，溪上白蘋花正繁。"]'),
('1807d9cc-4376-402d-91be-51882662df7a','哭樓梅麓','陳允平','宋','宋诗','song-poetry','','[]','白玉樓成去作文，祇從西棘掛朝冠。',64,'全唐诗/poet.song.233000.json','["白玉樓成去作文，祇從西棘掛朝冠。", "生來病苦相如渴，沒後人知范叔寒。", "野店春閑沽酒榼，溪堂月冷釣魚竿。", "梅花麓上誰彈淚，歲歲東風吹不乾。"]'),
('3f5c280d-2a87-4895-821a-883afd001c36','宮詞','陳允平','宋','宋诗','song-poetry','','[]','三十六宮春漏長，隔簾時送御樓香。',32,'全唐诗/poet.song.233000.json','["三十六宮春漏長，隔簾時送御樓香。", "倚籠盡日教鸚鵡，爲我君前說斷腸。"]'),
('3c6e3b38-0432-40cf-ac38-cc920258bcfc','無題','陳允平','宋','宋诗','song-poetry','','[]','閑拈紅葉欲題詩，待得詩成又懶題。',32,'全唐诗/poet.song.233000.json','["閑拈紅葉欲題詩，待得詩成又懶題。", "心事不隨流水去，月明人在赤橋西。"]'),
('21073db4-6d1b-48f2-9973-b7463379158a','題胡月山吟屋','陳允平','宋','宋诗','song-poetry','','[]','蘇公堤上路，日日課新吟。',48,'全唐诗/poet.song.233000.json','["蘇公堤上路，日日課新吟。", "流水行花影，斜陽卧柳陰。", "斷橋春聽樂，矮屋夜鳴琴。", "皎皎山間月，如君一片心。"]'),
('447fd793-065a-4823-a4a9-30a74162406b','有所思','陳允平','宋','宋诗','song-poetry','','[]','憶昔美人初別時，長亭兩岸柳依依。',152,'全唐诗/poet.song.233000.json','["憶昔美人初別時，長亭兩岸柳依依。", "今日美人天之涯，美人美人胡不歸。", "憶昔君別妾，分破青鸞鏡，破鏡如破心。", "與妾表相憶，相憶圖久深。", "憶昔妾別君，剪斷金鳳釵，斷釵如斷腸。", "贈君表相思，相思圖久長。", "一日一日復一日，青鏡鸞孤釵鳳隻。", "未必君相思，能如妾相憶。", "寒衣剪就欲寄君，長安門外無行人。", "雁聲半夜西風惡，窗前一片梧桐落。"]'),
('27a97cc8-3073-41f4-a069-6dc4d518fb6a','觀猿','陳允平','宋','宋诗','song-poetry','','[]','掛石攀雲日半斜，亂山深處飽烟霞。',32,'全唐诗/poet.song.233000.json','["掛石攀雲日半斜，亂山深處飽烟霞。", "香林月滿僧歸去，啼落春風幾樹花。"]'),
('403a895f-6fec-4c66-bc8b-7d88e23d3d60','失鶴','陳允平','宋','宋诗','song-poetry','','[]','頂上新成九轉丹，銜花日日到詩壇。',32,'全唐诗/poet.song.233000.json','["頂上新成九轉丹，銜花日日到詩壇。", "夜深飛上雲霄去，華表月明風露寒。"]'),
('6253b1e3-7afb-4ca5-b7d4-2e2356dbd91b','宿大慈山悟真觀','陳允平','宋','宋诗','song-poetry','','[]','終南道士學彈琴，門外松蘿鎖翠陰。',64,'全唐诗/poet.song.233000.json','["終南道士學彈琴，門外松蘿鎖翠陰。", "瀕海八龍朝出洞，隔山群鹿夜歸林。", "琪花過雨金風澹，玉樹籠烟璧月沉。", "三十六壇鍾鼓寂，雲璈聲接步虛音。"]'),
('14ec3888-37a5-4fab-a056-580496e238c1','寄翁賓暘','陳允平','宋','宋诗','song-poetry','','["\u897f\u6e56"]','歷歷長涂謁魯侯，征塵寧復戀貂裘。',64,'全唐诗/poet.song.233000.json','["歷歷長涂謁魯侯，征塵寧復戀貂裘。", "江城露冷霜初滑，海谷冰消水欲流。", "夜月觀書徐穉榻，春風聽樂仲宣樓。", "料君頻作西湖夢，曾憶孤山有舊游。"]'),
('bfb62a8c-1e41-4b61-842a-7eb8baa359bc','下第懷樓壽朋','陳允平','宋','宋诗','song-poetry','','[]','百尺丹梯擬共登，共登天上最高層。',64,'全唐诗/poet.song.233000.json','["百尺丹梯擬共登，共登天上最高層。", "南山有霧空藏豹，北海無雲可化鵬。", "勳業十年塵裏鏡，詩書萬卷雨前燈。", "桃花開盡不歸去，又逐春風過武陵。"]'),
('366b0245-e32d-432d-a68e-7b7a92595dd1','別何橘潭','陳允平','宋','宋诗','song-poetry','','[]','駐馬赤欄橋，餘寒著柳條。',48,'全唐诗/poet.song.233000.json','["駐馬赤欄橋，餘寒著柳條。", "舟車富陽路，風雨浙江潮。", "惜別津亭暮，思歸故國遥。", "臨行莫惆悵，回日定花朝。"]'),
('3b1a9a34-2e5d-4097-b0fa-491db458ed60','有感','陳允平','宋','宋诗','song-poetry','','[]','軟紅塵裏度韶華，楊柳橋邊舊酒家。',32,'全唐诗/poet.song.233000.json','["軟紅塵裏度韶華，楊柳橋邊舊酒家。", "燕子不歸春漸老，東風開盡刺桐花。"]'),
('ee20694e-28d6-4a5a-8d30-01abfb6a4317','暮春','陳允平','宋','宋诗','song-poetry','','[]','柳外宮鶑囀曉寒，萬花開盡正春殘。',32,'全唐诗/poet.song.233000.json','["柳外宮鶑囀曉寒，萬花開盡正春殘。", "沉香亭北欄干曲，獨抱琵琶看牡丹。"]'),
('e7fd611f-a06e-42f8-9a3f-ac98251dbd80','終日','陳允平','宋','宋诗','song-poetry','','[]','終日懷人憑曲欄，餘陰未放客衣單。',64,'全唐诗/poet.song.233000.json','["終日懷人憑曲欄，餘陰未放客衣單。", "祇緣二月風光澹，別作一般天氣看。", "梅粉有香銷夜雨，柳絲無力受春寒。", "閑情漠漠難拘管，自逐輕鷗下急灘。"]'),
('ca5c1ac4-f135-4bae-8303-76503ef7c9f5','過釣臺作','陳允平','宋','宋诗','song-poetry','','[]','雙臺屹屹幾春秋，千古高風一釣鈎。',64,'全唐诗/poet.song.233000.json','["雙臺屹屹幾春秋，千古高風一釣鈎。", "越嶺有雲山北障，桐江無浪水東流。", "雪深黄葉埋寒虎，烟暖青莎卧白鷗。", "漢業已隨宮樹老，月明長到客星樓。"]'),
('818ac841-5a42-4ec3-a6c8-8f1858de8f3d','春閨','陳允平','宋','宋诗','song-poetry','','[]','寂寞梨花院落閑，遠山愁入兩眉彎。',32,'全唐诗/poet.song.233000.json','["寂寞梨花院落閑，遠山愁入兩眉彎。", "黄金絡索珊瑚墜，獨立春風教白鷳。"]'),
('bce18f43-1649-41f4-8b01-59621cefd2ff','倚樓','陳允平','宋','宋诗','song-poetry','','[]','金虬熏盡鷓鴣班，獨上層樓倚畫欄。',32,'全唐诗/poet.song.233000.json','["金虬熏盡鷓鴣班，獨上層樓倚畫欄。", "滿院梨花香寂寞，隔簾風雨正春寒。"]'),
('26c13edd-f659-4e88-b7f4-975319960ef6','嚴陵郡舍','陳允平','宋','宋诗','song-poetry','','[]','花飛石上班，水落白雲灣。',48,'全唐诗/poet.song.233000.json','["花飛石上班，水落白雲灣。", "簾捲千重樹，窗開四面山。", "鼓聲魚市近，旗影訟庭閑。", "滿目皆吟思，殘陽縹緲間。"]'),
('0554b8a2-bab2-4620-a889-7df34932f3e2','西興','陳允平','宋','宋诗','song-poetry','','[]','西興潮半落，漁浦日初昏。',48,'全唐诗/poet.song.233000.json','["西興潮半落，漁浦日初昏。", "嶽面雲收脚，沙頭浪積痕。", "樓鍾鳴野寺，船鼓入江村。", "回首長安路，歸心幾斷魂。"]'),
('01a35b58-59da-4c78-bb28-5443d3b4dce9','曹娥廟','陳允平','宋','宋诗','song-poetry','','[]','漢碣嵯峨幾百秋，曲墳遺廟越山頭。',64,'全唐诗/poet.song.233000.json','["漢碣嵯峨幾百秋，曲墳遺廟越山頭。", "潮聲侵帳鳳屏冷，雲氣繞臺鸞鏡愁。", "孝節稜稜雙檜立，哀魂渺渺一江流。", "椒觴載奠靈風起，知我懷親送遠舟。"]'),
('68be2804-4c3f-4b62-a662-8ccb6348bd0e','梁湖道上','陳允平','宋','宋诗','song-poetry','','[]','東風酒旆斜，浦口第三家。',48,'全唐诗/poet.song.233000.json','["東風酒旆斜，浦口第三家。", "谷鳥鳴春樹，江鷗起暮沙。", "故鄉山漸近，曲岸柳初芽。", "客路歸心切，孤帆带落霞。"]'),
('d639bfc3-30cd-47c1-a448-a823bf59c2c3','閨情','陳允平','宋','宋诗','song-poetry','','[]','閑拈花片貼紗窗，繡幕斜飛燕子雙。',32,'全唐诗/poet.song.233000.json','["閑拈花片貼紗窗，繡幕斜飛燕子雙。", "細數歸期相次近，倚樓日日望春江。"]'),
('b91915bb-f731-496f-a055-a2f7911b1d4f','梅梁堰','陳允平','宋','宋诗','song-poetry','','[]','廟近雲濤觀，山遥翠欲重。',48,'全唐诗/poet.song.233000.json','["廟近雲濤觀，山遥翠欲重。", "祇應溪上木，便是洞中龍。", "堰折潮歸海，樓迎浪答鍾。", "斷碑荒蘚合，終古載靈蹤。"]'),
('7849026e-a5f8-476a-9da8-e0f1dd88dd14','虎丘即事','陳允平','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','西風劍珮輕，獨立妙高亭。',48,'全唐诗/poet.song.233000.json','["西風劍珮輕，獨立妙高亭。", "山吐巖頭月，江涵水面星。", "石奔蒼虎勢，樹結老龍形。", "何處吹簫客，扁舟過洞庭。"]'),
('b2c94848-c372-4f5d-9836-bc60f2f7bc38','青龍渡頭','陳允平','宋','宋诗','song-poetry','','[]','天闊雁飛飛，淞江鱸正肥。',48,'全唐诗/poet.song.233000.json','["天闊雁飛飛，淞江鱸正肥。", "柳風欺客帽，松露濕僧衣。", "塔影隨潮沒，鍾聲隔岸微。", "不堪回首處，何日可東歸。"]'),
('cd5e5344-5c91-41f2-b740-9d2d208c5c84','仲冬南樓野望','陳允平','宋','宋诗','song-poetry','','[]','繡幕香溫生暮寒，淡烟漠漠水漫漫。',64,'全唐诗/poet.song.233000.json','["繡幕香溫生暮寒，淡烟漠漠水漫漫。", "吟殘庾嶺梅千樹，夢繞湘江竹萬竿。", "風捲亂鴉棲古塔，雪迷孤雁落前灘。", "一聲玉笛人何所，更上南樓獨倚欄。"]'),
('66f23463-ee08-4f95-b35e-c3a2782bf208','夜泊','陳允平','宋','宋诗','song-poetry','','[]','停舟野渡頭，客路恨悠悠。',48,'全唐诗/poet.song.233000.json','["停舟野渡頭，客路恨悠悠。", "葉落風千樹，鍾殘月半樓。", "蘆花雙過雁，莎草獨眠鷗。", "山鬼燒青火，飛來照髑髏。"]'),
('bbbf2331-1c7e-440b-847e-d35fb5bfd409','梨花','陳允平','宋','宋诗','song-poetry','','[]','流鶑偷入未央宮，望斷昭陽信不通。',32,'全唐诗/poet.song.233000.json','["流鶑偷入未央宮，望斷昭陽信不通。", "寂寞雨聲寒食夜，一枝香淚泣東風。"]'),
('4d8e959b-26a2-42b5-897b-6f455ab2f81b','賦林景參梅嶼','陳允平','宋','宋诗','song-poetry','','[]','結廬分得雁山雲，嶼上梅花是四鄰。',64,'全唐诗/poet.song.233000.json','["結廬分得雁山雲，嶼上梅花是四鄰。", "水月一天薌世界，冰霜千古玉精神。", "短檠夜雨西窗夢，長鋏秋風北塞塵。", "我亦烟波綸釣侶，與君同作歲寒人。"]'),
('e484d2e3-3531-4855-8e4f-21972a056f4f','懷潘鄮屋','陳允平','宋','宋诗','song-poetry','','[]','洛陽纔解珮，過眼忽秋分。',48,'全唐诗/poet.song.233000.json','["洛陽纔解珮，過眼忽秋分。", "四海一明月，千山共白雲。", "雁烟迷曉樹，蟲露濕香芹。", "滿紙相思字，臨風欲寄君。"]'),
('04e153d5-4bf5-454a-ba4c-c76bdc41fbd5','吳江道上','陳允平','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','夜半扁舟出洞庭，客帆初掛早潮平。',64,'全唐诗/poet.song.233000.json','["夜半扁舟出洞庭，客帆初掛早潮平。", "社風纔起海鷹至，嵐霧未收江鵠鳴。", "吳岫亂雲擎古塔，楚臯寒葉擁荒城。", "垂虹橋外天連水，無限別離生杜蘅。"]'),
('3214a661-89c9-4aa9-9529-09e824307c13','登西樓懷湯損之','陳允平','宋','宋诗','song-poetry','','[]','楊柳飄飄春思長，綠橋流水繞官牆。',32,'全唐诗/poet.song.233000.json','["楊柳飄飄春思長，綠橋流水繞官牆。", "碧雲望斷空回首，一半闌干無夕陽。"]'),
('28a31076-bc20-4c29-b49e-a7c0b751944f','吳山雪霽','陳允平','宋','宋诗','song-poetry','','[]','九天宮闕春風滿，陸地樓臺夜月寒。',32,'全唐诗/poet.song.233000.json','["九天宮闕春風滿，陸地樓臺夜月寒。", "鐵笛一聲吹雁落，片雲不到玉闌干。"]'),
('baad83e4-5678-4b00-8480-1a896bc3c8bd','后土廟','陳允平','宋','宋诗','song-poetry','','[]','塵擁妝臺翡翠翹，瓊花開盡玉魂銷。',32,'全唐诗/poet.song.233000.json','["塵擁妝臺翡翠翹，瓊花開盡玉魂銷。", "崑崙山上天風落，二十四橋吹洞簫。"]'),
('f8a1037c-d560-4a49-a5f3-eb9b9cec5795','湖上','陳允平','宋','宋诗','song-poetry','','[]','流水斷橋邊，笙歌擁畫船。',48,'全唐诗/poet.song.233000.json','["流水斷橋邊，笙歌擁畫船。", "日酣花半醉，春困柳三眠。", "策杖登雲洞，觀魚上玉泉。", "鳳城歸去晚，山鎖萬重烟。"]'),
('600088a9-ced5-423a-bc2a-a6edaf051a27','西湖暮春','陳允平','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雲山疊疊樹重重，浙水迢遥客夢中。',64,'全唐诗/poet.song.233000.json','["雲山疊疊樹重重，浙水迢遥客夢中。", "啼鴂數聲春去日，落花滿地夜來風。", "松關鶴立吟壇靜，竹院僧眠丈室空。", "明日馬蹄何處所，夕陽芳草畫橋東。"]'),
('dd21fd13-3818-4db1-8156-45fe58dfdae7','山房','陳允平','宋','宋诗','song-poetry','','[]','軒窗四面開，風送海雲來。',48,'全唐诗/poet.song.233000.json','["軒窗四面開，風送海雲來。", "一陣催花雨，數聲驚蟄雷。", "蝸涎明石凳，蟻陣繞山臺。", "此際衣偏濕，熏籠著麝煤。"]'),
('39c74099-59e1-4eca-a3ce-b54b481fe822','馬塍道上','陳允平','宋','宋诗','song-poetry','','[]','閑拖瘦竹筇，獨步馬塍東。',48,'全唐诗/poet.song.233000.json','["閑拖瘦竹筇，獨步馬塍東。", "鳥影青山外，春愁碧樹中。", "麥潮風化蝶，櫻熟雨生蟲。", "莫過溪頭去，溪頭多落紅。"]'),
('2babc5f2-c2a2-4ff6-9519-80a90df7e17a','遊仙曲','陳允平','宋','宋诗','song-poetry','','[]','中秋月正明，夜半飛紫瓊。',120,'全唐诗/poet.song.233000.json','["中秋月正明，夜半飛紫瓊。", "拂袖天上去，攬衣朝太清。", "縹緲黄金闕，迢遥白玉京。", "離離百寶幢，裊裊九華旌。", "簫韶起碧落，散花飄群英。", "翺翔鸞鶴舞，清徹雲璈聲。", "凌凌九霄寒，風露薄青冥。", "弱水三萬里，仙路眇蓬瀛。", "不赴瑶池宴，相約董雙成。", "吹笙騎鳳凰，飛上芙蓉城。"]'),
('a962f7a9-74ec-48af-86ed-bab354215cca','戍婦','陳允平','宋','宋诗','song-poetry','','[]','梧桐葉落雁來時，見說沙場未解圍。',32,'全唐诗/poet.song.233000.json','["梧桐葉落雁來時，見說沙場未解圍。", "夜夜燈前做針線，倩誰邊上寄寒衣。"]'),
('79ea1284-ad29-4a8e-9459-3a23fcc2ff38','過姚秋江釣磯','陳允平','宋','宋诗','song-poetry','','[]','莎草離離碧樹閑，祇疑曾是子陵灘。',64,'全唐诗/poet.song.233000.json','["莎草離離碧樹閑，祇疑曾是子陵灘。", "槿花籬落蟲聲碎，蘆葉汀洲雁陣寒。", "江上浪平潮正熟，渡頭人去月初殘。", "夜深不管蛟龍睡，獨對西風把釣竿。"]'),
('a535af04-bd38-4747-b8c9-3ea4ef4e8486','己酉秋留鶴江有感','陳允平','宋','宋诗','song-poetry','','[]','賓鴻幾過淀山湖，夜夜西風轉轆轤。',64,'全唐诗/poet.song.233000.json','["賓鴻幾過淀山湖，夜夜西風轉轆轤。", "苜蓿草衰江館靜，枇杷葉老石泉枯。", "曲終明月閑歌扇，病去寒灰滿藥爐。", "客夢不堪千里遠，故園籬菊正荒蕪。"]'),
('908ddf52-6206-4328-9f6d-9e641ff0bef9','經馮將軍墓','陳允平','宋','宋诗','song-poetry','','[]','同山半白雲，此地葬將軍。',48,'全唐诗/poet.song.233000.json','["同山半白雲，此地葬將軍。", "香火空遺像，朝廷紀舊勳。", "鐵衣懸古塔，金鉞鎮荒墳。", "一澗清泠水，年年生紫芹。"]'),
('3d90bbf9-e6f7-4eb4-bc21-dd3869235109','江村','陳允平','宋','宋诗','song-poetry','','[]','草舍蔬畦繞，柴門竹逕通。',48,'全唐诗/poet.song.233000.json','["草舍蔬畦繞，柴門竹逕通。", "斷雲遮落日，細雨濕斜風。", "野艾抽花碧，山茄带葉紅。", "烟深南浦遠，難認楚江楓。"]'),
('0b3338b6-df51-4f54-b183-c004bbf2a60b','江館野望','陳允平','宋','宋诗','song-poetry','','[]','江邊雁過秋，江上暮雲愁。',48,'全唐诗/poet.song.233000.json','["江邊雁過秋，江上暮雲愁。", "嶺曲山橫轉，潮回水逆流。", "亂莎行石蟹，殘荻卧沙鷗。", "黯淡三更月，何人獨倚樓。"]'),
('a693fc21-80a0-47f1-a223-d72eded2a907','暮秋遊虎丘','陳允平','宋','宋诗','song-poetry','','[]','寂寞虛廊暗草萊，天風繚繞寶華臺。',64,'全唐诗/poet.song.233000.json','["寂寞虛廊暗草萊，天風繚繞寶華臺。", "江空露冷蛟龍伏，殿古雲深鸛鵲來。", "山館老松褰綠蔓，石壇芳桂落蒼苔。", "寒鍾敲斷楓橋月，半夜禪僧入定回。"]'),
('d41e166d-806d-430c-891a-6088c96aa945','小樓','陳允平','宋','宋诗','song-poetry','','[]','寒空漠漠起愁雲，玉笛吹殘正斷魂。',32,'全唐诗/poet.song.233000.json','["寒空漠漠起愁雲，玉笛吹殘正斷魂。", "寂寞小樓簾半捲，雁烟蛩雨又黄昏。"]'),
('b63e4917-59e1-4917-a6ad-e1471c8bc59d','侍趙別駕宴壽樂堂','陳允平','宋','宋诗','song-poetry','','[]','別駕移樽宴草堂，四軒簾幕捲斜陽。',64,'全唐诗/poet.song.233000.json','["別駕移樽宴草堂，四軒簾幕捲斜陽。", "芰荷香滿鴛鴦宿，楊柳陰濃翡翠藏。", "風過水亭秋尚熱，月侵山閣夜偏涼。", "更闌酒盡不知去，坐看曉星飛玉潢。"]'),
('88f720a1-dbbd-4e4f-b813-2b745405e34f','留鶴江有感','陳允平','宋','宋诗','song-poetry','','[]','抱玉歸來淚滿襟，世間何許覓知音。',64,'全唐诗/poet.song.233000.json','["抱玉歸來淚滿襟，世間何許覓知音。", "此生雖有噬臍悔，到死終無嘗膽心。", "伏櫪馬思雲路遠，避鈎魚隠石潭深。", "故人若問淞江客，自採芙蓉學楚吟。"]'),
('d8a9ebdb-b011-4e83-b3ed-bacfab294897','送吳松溪過淮','陳允平','宋','宋诗','song-poetry','','[]','鐵硯毛錐未策功，又携琴劍過臨邛。',64,'全唐诗/poet.song.233000.json','["鐵硯毛錐未策功，又携琴劍過臨邛。", "荆山有玉鳴朝鳳，滄海無珠走夜龍。", "浦口月來僧館榻，渡頭霜落客船鍾。", "自君別後知音少，空憶雁山溪上松。"]'),
('8c024ac7-378d-48e1-8633-9819c32c6d80','送趙知縣歸天台','陳允平','宋','宋诗','song-poetry','','[]','自是中朝柱石材，西風塵土暗蒿萊。',64,'全唐诗/poet.song.233000.json','["自是中朝柱石材，西風塵土暗蒿萊。", "河陽縣裏花初放，彭澤門前柳未栽。", "準擬鳴珂來鳳沼，徘徊抱玉下烏臺。", "明朝琴鶴歸何處，三逕故園多綠苔。"]'),
('244d4850-7466-412e-8eae-288d8098eaf1','姑蘇館','陳允平','宋','宋诗','song-poetry','','[]','楚岫高低接太行，吳江渺漠下滄浪。',64,'全唐诗/poet.song.233000.json','["楚岫高低接太行，吳江渺漠下滄浪。", "秋城霜滿葦花白，夜館月寒莎草黄。", "芳苑鹿臺初解珮，故宮鸞閣尚鳴璫。", "五湖一葉扁舟去，十二西樓幾夕陽。"]'),
('1e30e005-7909-47b9-a016-01a756e82067','雲間洞天','陳允平','宋','宋诗','song-poetry','','[]','門掩青松間綠槐，一奩圖畫自天開。',64,'全唐诗/poet.song.233000.json','["門掩青松間綠槐，一奩圖畫自天開。", "朝霞煉藥黄金井，夜月吹笙白玉臺。", "樹老有枝皆薜荔，地閑無處不莓苔。", "數聲野鶴驚殘夢，疑是神仙出洞來。"]'),
('575f459d-4577-44f6-90a6-f7170e72d0e9','採桑行','陳允平','宋','宋诗','song-poetry','','[]','妾本秦羅敷，家住曲江曲。',176,'全唐诗/poet.song.233000.json','["妾本秦羅敷，家住曲江曲。", "門前楊柳青，春風啼布穀。", "樹頭桑初芽，家家蠶始浴。", "相呼出採桑，採桑如採玉。", "屈曲迴高枝，攀條剪柔綠。", "朝晴採桑南，暮雨採桑北。", "採得桑歸遲，小姑怨相促。", "陌上綺羅人，問妾眉何蹙。", "妾恨妾自知，問妾何所欲。", "消磨三十春，漸喜蠶上簇。", "七日收得繭百斤，十日繅成絲兩束。", "一絲一線工，織成羅與縠。", "百人共辛勤，一人衣不足。", "舉頭忽見桑葉黄，低頭垂淚羞布裳。"]'),
('0a72e59b-3a82-4af7-9673-e8b617ee4bbf','對燭','陳允平','宋','宋诗','song-poetry','','[]','忽憶巴山夜，西窗風雨寒。',48,'全唐诗/poet.song.233000.json','["忽憶巴山夜，西窗風雨寒。", "自憐清影獨，誰識寸心丹。", "草長花猶在，香銷淚不乾。", "海棠貪睡去，惆悵五更殘。"]'),
('03180f78-e491-4bdd-a850-159f7841ad15','春曉','陳允平','宋','宋诗','song-poetry','','[]','曉風獵獵捲芭蕉，簾幕深深燕子巢。',32,'全唐诗/poet.song.233000.json','["曉風獵獵捲芭蕉，簾幕深深燕子巢。", "十二畫欄都倚遍，一雙蝴蝶上花梢。"]'),
('ef6777bd-cf2f-47a4-a4b3-d6f240160307','侍趙開府夜宴','陳允平','宋','宋诗','song-poetry','','[]','賸陪華珮醉蟠桃，楊柳飄飄拂午橋。',64,'全唐诗/poet.song.233000.json','["賸陪華珮醉蟠桃，楊柳飄飄拂午橋。", "夜月樓臺行錦障，春風簾幕捲紅綃。", "歌傳杏苑黄金縷，樂奏梨園紫玉簫。", "銀漏滴殘珠履散，踏花歸去路迢遥。"]'),
('bb813e72-8fde-4e10-acc9-530f3351186a','雷峰少憩','陳允平','宋','宋诗','song-poetry','','[]','倚塔看明月，寒光度玉繩。',48,'全唐诗/poet.song.233000.json','["倚塔看明月，寒光度玉繩。", "曲堤藏小艇，疏柳見孤燈。", "水竹映苔石，巖花緣澗藤。", "香雲吹散後，猿鶴伴高僧。"]'),
('47aea832-a911-4877-81c2-c2558aa48ee8','錢塘旅舍','陳允平','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','雲山千萬疊，身事恨悠悠。',48,'全唐诗/poet.song.233000.json','["雲山千萬疊，身事恨悠悠。", "客鬢秋風急，鄉心夜雨愁。", "蛩鳴鄰寺壁，雁過隔湖樓。", "目送千帆遠，長江空自流。"]'),
('1172e0a3-21f4-4237-8359-3485f4434378','避暑','陳允平','宋','宋诗','song-poetry','','[]','避暑入林扃，同僧坐竹亭。',48,'全唐诗/poet.song.233000.json','["避暑入林扃，同僧坐竹亭。", "鳥飛晴地影，龍掛雨天形。", "掃葉鋪椰簟，臨流注石瓶。", "更無塵跡到，日落夢初醒。"]'),
('2718431f-5e19-4e3b-8194-35ae0a1b9b3d','山中吟','陳允平','宋','宋诗','song-poetry','','[]','平生獨愛山，日日頻躋攀。',48,'全唐诗/poet.song.233000.json','["平生獨愛山，日日頻躋攀。", "自得山中趣，結廬萬山間。", "山西茂林麓，中有盤旋谷。", "飄飄雙鳳凰，飛立山上玉。"]'),
('50f2b443-0c84-41fd-9114-61de09134a60','山中吟  其一','陳允平','宋','宋诗','song-poetry','','[]','平生獨愛山，日日頻躋攀。',24,'全唐诗/poet.song.233000.json','["平生獨愛山，日日頻躋攀。", "自得山中趣，結廬萬山間。"]'),
('3e4d4e1e-a281-4c6e-9c18-cffdf4448bbb','山中吟  其二','陳允平','宋','宋诗','song-poetry','','[]','山西茂林麓，中有盤旋谷。',24,'全唐诗/poet.song.233000.json','["山西茂林麓，中有盤旋谷。", "飄飄雙鳳凰，飛立山上玉。"]'),
('6478495c-dd3e-4406-badf-a63b226e428c','山中吟  其三','陳允平','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','日出華山陽，月出廬山崗。',24,'全唐诗/poet.song.233000.json','["日出華山陽，月出廬山崗。", "巫山雲漠漠，雁山烟蒼蒼。"]'),
('f6281a36-97cb-4930-abdd-21513f911dd6','山中吟  其四','陳允平','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','東望泰嶽松，西望蒼梧竹。',24,'全唐诗/poet.song.233000.json','["東望泰嶽松，西望蒼梧竹。", "知心侶漁樵，忘情友麋鹿。"]'),
('381ff32e-31ec-4524-8eac-019fc29f442b','山中吟  其五','陳允平','宋','宋诗','song-poetry','','[]','山深春亦寒，野鳥聲綿蠻。',24,'全唐诗/poet.song.233000.json','["山深春亦寒，野鳥聲綿蠻。", "山花隨處發，香風吹幽蘭。"]'),
('440f621a-241c-4a92-a52f-5c64ccb35817','山中吟  其六','陳允平','宋','宋诗','song-poetry','','[]','夏日飛火雲，枕簟訪深僻。',24,'全唐诗/poet.song.233000.json','["夏日飛火雲，枕簟訪深僻。", "坐此松竹林，冰泉嗽寒石。"]'),
('ed03b620-f6c6-44f7-85e0-d314720f26d7','山中吟  其七','陳允平','宋','宋诗','song-poetry','','[]','西風凉蕭蕭，雁過秋空高。',24,'全唐诗/poet.song.233000.json','["西風凉蕭蕭，雁過秋空高。", "時有巖桂發，落葉飛長臯。"]'),
('bb835683-32b6-4e10-bb34-fcc6c55c91b8','山中吟  其八','陳允平','宋','宋诗','song-poetry','','[]','三冬氣凜冽，獨立千崖雪。',24,'全唐诗/poet.song.233000.json','["三冬氣凜冽，獨立千崖雪。", "橫斜溪上梅，影落溪橋月。"]'),
('eb2d708e-0685-48b7-b22b-7b569fc2f3f0','山中吟  其九','陳允平','宋','宋诗','song-poetry','','[]','身在此山中，閑情薄太空。',24,'全唐诗/poet.song.233000.json','["身在此山中，閑情薄太空。", "行歌白雲裏，白雲連崆峒。"]'),
('209cd769-f9b0-4db8-9cfa-c26e403fb34e','山中吟  其一○','陳允平','宋','宋诗','song-poetry','','[]','朝餐山上霞，暮採山下藥。',24,'全唐诗/poet.song.233000.json','["朝餐山上霞，暮採山下藥。", "安得山中人，共跨山頭鶴。"]'),
('a21f9b18-7658-4345-959e-ea244e5212e8','無題  其一','陳允平','宋','宋诗','song-poetry','','[]','鮫綃簾捲錦屏開，弱柳絲絲拂吹臺。',32,'全唐诗/poet.song.233000.json','["鮫綃簾捲錦屏開，弱柳絲絲拂吹臺。", "閑品琵琶不成調，落花飛趁曉風來。"]'),
('b7223ace-cec0-4bf8-b06a-8dd04c9980dd','無題  其二','陳允平','宋','宋诗','song-poetry','','[]','千樹琅玕碧玉梢，秋聲半夜浙江潮。',32,'全唐诗/poet.song.233000.json','["千樹琅玕碧玉梢，秋聲半夜浙江潮。", "小庭寂寞無人到，誰與同吹月下簫。"]'),
('1c021ba6-4c63-4596-bb0f-31b5b5725a2c','人日即事','陳允平','宋','宋诗','song-poetry','','[]','春寒猶撥地爐灰，門巷蕭條客不來。',32,'全唐诗/poet.song.233000.json','["春寒猶撥地爐灰，門巷蕭條客不來。", "特有落梅三四點，晚風吹上石棋臺。"]'),
('9df4d7d8-eedd-4b60-9f4d-0956b38dc3b1','客中懷友','陳允平','宋','宋诗','song-poetry','','[]','霜露濕征衣，行非少壯時。',48,'全唐诗/poet.song.233000.json','["霜露濕征衣，行非少壯時。", "何堪萬里役，動是一年期。", "高誼貧中見，深情別後知。", "相思相望處，雲樹碧參差。"]'),
('d3dcf48b-1844-458d-bbf2-63c6829b0500','憶諸姪','陳允平','宋','宋诗','song-poetry','','[]','萬里經年別，臨分手重携。',48,'全唐诗/poet.song.233000.json','["萬里經年別，臨分手重携。", "地寒冬氣早，家遠暮雲低。", "有信秋憑雁，無眠夜聽雞。", "滿懷霜露感，不隔故山西。"]'),
('08de6c99-7064-4a3c-a21e-5026dde500f1','贈杜郎中','陳允平','宋','宋诗','song-poetry','','[]','草堂人遠只存詩，幾席臨風入詠思。',64,'全唐诗/poet.song.233000.json','["草堂人遠只存詩，幾席臨風入詠思。", "文印幸傳同谷譜，祖燈猶照曲江碑。", "濡毫省闥春霖足，立馬君門夜漏遲。", "憔悴江南老詞客，柳邊曾挹漢威儀。"]'),
('ca31ee68-a7ce-4171-9c68-d28f9b5116a6','贈佛光法師','陳允平','宋','宋诗','song-poetry','','[]','竺寺王城近，金門講大乘。',48,'全唐诗/poet.song.233000.json','["竺寺王城近，金門講大乘。", "教中初有記，祖外久無僧。", "身被山河衲，心懸日月燈。", "南湖雨華座，十載復誰登。"]'),
('2152920b-de27-4b9b-bc75-c862713f7911','贈新羅僧','陳允平','宋','宋诗','song-poetry','','[]','便帆纔過日東來，淺色伽梨短樣裁。',64,'全唐诗/poet.song.233000.json','["便帆纔過日東來，淺色伽梨短樣裁。", "野鶴怨時心共遠，海鯨降處定初回。", "長年守律因師戒，中土傳經爲國災。", "幾日應酬官事了，南湖聽法雨華臺。"]'),
('0d4661cc-905d-4e0b-861c-54b85cfd6487','贈雪竇','陳允平','宋','宋诗','song-poetry','','[]','一從說法雨華臺，椶葉蕉花幾度開。',64,'全唐诗/poet.song.233000.json','["一從說法雨華臺，椶葉蕉花幾度開。", "春盡瀑泉猶濺雪，地幽篁竹亦生苔。", "臨溪洗鉢青猿過，背石持經白鳥來。", "笑指庭前雙柏樹，住庵時節手親栽。"]'),
('5be5f84a-c73a-4b72-bb47-93b6fd7be6fc','贈律師','陳允平','宋','宋诗','song-poetry','','[]','傳來二十五條衣，晝夜修行晝夜持。',32,'全唐诗/poet.song.233000.json','["傳來二十五條衣，晝夜修行晝夜持。", "老去任教零落盡，獼猴偷□□□□。"]'),
('908ea989-7b27-4dc5-a2a7-8c1f12b76c15','贈訥行人','陳允平','宋','宋诗','song-poetry','','[]','諸方參請盡，秋晚別京畿。',48,'全唐诗/poet.song.233000.json','["諸方參請盡，秋晚別京畿。", "乞食一齋飽，隨緣百念微。", "夜聲鳴鐵笛，寒色脆荷衣。", "久學南山律，終身不敢違。"]'),
('316aaa19-1e60-46ed-a04e-35f64df07290','贈東皋恭行人','陳允平','宋','宋诗','song-poetry','','[]','重門臨驛路，幾向月中開。',48,'全唐诗/poet.song.233000.json','["重門臨驛路，幾向月中開。", "殿勢江山合，鍾聲雲水來。", "長吟松濺瀑，久定石生苔。", "九品金沙觀，青蓮次第栽。"]'),
('1d26de31-49b0-4fd1-98a1-58f558e25d27','贈羅知宮','陳允平','宋','宋诗','song-poetry','','[]','霞帔雲巾占石牀，磬聲初引步虛長。',64,'全唐诗/poet.song.233000.json','["霞帔雲巾占石牀，磬聲初引步虛長。", "擬朝碧落非無路，學煮黄金信有方。", "雲暗石潭龍骨蛻，草肥山崦麝臍香。", "青城夢窅蓬萊近，滄海爲田合種桑。"]'),
('1a24d7ec-3c47-4d76-a184-564b018774fc','贈明道者','陳允平','宋','宋诗','song-poetry','','[]','三衣終日護，白社踵東林。',48,'全唐诗/poet.song.233000.json','["三衣終日護，白社踵東林。", "浄業心無住，清齋力不禁。", "蓮香秋觀靜，松吹石橋陰。", "見說溪南虎，時來聽梵音。"]'),
('a2274292-0b8a-4519-b6de-a722d3225458','贈楊子中','陳允平','宋','宋诗','song-poetry','','[]','鳳梧鸞竹鬰青葱，文氣沖沖五色虹。',64,'全唐诗/poet.song.233000.json','["鳳梧鸞竹鬰青葱，文氣沖沖五色虹。", "囊裏短歌唐李賀，酒邊奇字漢揚雄。", "銅鋪雨後芭蕉綠，石井霜前薜荔紅。", "茶竈筆牀隨處有，等閑留客坐春風。"]'),
('8c5922d3-c9d2-4b1e-aeb8-83ebf93cb0e6','寄模上人','陳允平','宋','宋诗','song-poetry','','[]','林下逢支遁，人疑是宿生。',48,'全唐诗/poet.song.233000.json','["林下逢支遁，人疑是宿生。", "病憐詩力減，老覺世緣輕。", "短髮吳霜浄，歸心剡雪明。", "相思聽猿夜，幽夢隔重城。"]'),
('95c425ad-e9b5-4662-bb18-de1a07202282','寄趙慶御','陳允平','宋','宋诗','song-poetry','','[]','十年一別雙溪路，君自江南我浙東。',32,'全唐诗/poet.song.233000.json','["十年一別雙溪路，君自江南我浙東。", "彼此有書無雁寄，祇應清夢與君同。"]'),
('4b509fc9-e6b3-46c9-a4d2-71bee4b863cb','寄晚浦張觀使','陳允平','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不願生封萬戶侯，歸來却伴赤松遊。',64,'全唐诗/poet.song.233000.json','["不願生封萬戶侯，歸來却伴赤松遊。", "琴書東里三椽屋，詩酒西湖一葉舟。", "雁過客樓秋雨急，烏棲江樹暮烟愁。", "頻年陡覺生華髮，日日憑高望楚州。"]'),
('bf42949d-69d9-4677-b262-a2309b9305dc','酬同志','陳允平','宋','宋诗','song-poetry','','[]','風光易銷歇，尊□足閑情。',48,'全唐诗/poet.song.233000.json','["風光易銷歇，尊□足閑情。", "穀雨春江暮，茶烟曉寺晴。", "認巢歸燕熟，辭樹落花輕。", "湖上明朝約，初裁白苧成。"]'),
('af8369ed-d60f-4373-967d-0c28f6b72d9a','茅葦','陳允平','宋','宋诗','song-poetry','','[]','白葦黄茅幾斷魂，數家鷄犬不相聞。',32,'全唐诗/poet.song.233000.json','["白葦黄茅幾斷魂，數家鷄犬不相聞。", "江南多少朱門閉，桑柘春深綠似雲。"]'),
('a9659f24-57b4-412c-aa11-046a4c1df262','先天李姆廟','陳允平','宋','宋诗','song-poetry','','[]','毓聖功成宴太清，曾遺雙履下清冥。',32,'全唐诗/poet.song.233000.json','["毓聖功成宴太清，曾遺雙履下清冥。", "隧碑重紀先天德，猶是祥符御製銘。"]'),
('ac6d647d-05ac-4826-9d01-f7c36148fbc7','宛陵道院','陳允平','宋','宋诗','song-poetry','','[]','闕角溪城下，千年黑蟒蟠。',48,'全唐诗/poet.song.233000.json','["闕角溪城下，千年黑蟒蟠。", "雲深仙宅窅，竹密醮壇寒。", "漢量銅花綠，隋鍾火籀丹。", "天風步虛靜，微月聽鳴鑾。"]'),
('98b1565e-cf35-408d-9f52-f538df122722','伍煉士松隠居','陳允平','宋','宋诗','song-poetry','','[]','樹頂危巢墮鶴翎，凌霄花白女蘿青。',32,'全唐诗/poet.song.233000.json','["樹頂危巢墮鶴翎，凌霄花白女蘿青。", "無朝無暮雲烟起，時有人來採茯苓。"]'),
('19642193-bd98-4300-806a-3f60b70a7032','林道士故廬','陳允平','宋','宋诗','song-poetry','','[]','青城道士跨青牛，去作清都汗漫遊。',64,'全唐诗/poet.song.233000.json','["青城道士跨青牛，去作清都汗漫遊。", "朝扣九關朝玉闕，暮回三島宴金樓。", "丹隨鶴舞緱山月，劍伴龍歸洛浦秋。", "猶有石房雲不散，曉風松柏兩颼飀。"]'),
('2256e84d-ecce-43f4-b30e-3cbfdf5cfaa4','許宣平祠','陳允平','宋','宋诗','song-poetry','','[]','開元遺逸士，終老紫陽樵。',48,'全唐诗/poet.song.233000.json','["開元遺逸士，終老紫陽樵。", "市上人猶說，山中隠可招。", "乾坤雙草履，日月一花瓢。", "堪笑騎鯨者，相逢弱水遥。"]'),
('ffb3a41b-3b81-43bc-a702-6a20347e3d8c','郭西文孝廟','陳允平','宋','宋诗','song-poetry','','[]','帝子宸遊白玉京，江南遺廟尚丹青。',64,'全唐诗/poet.song.233000.json','["帝子宸遊白玉京，江南遺廟尚丹青。", "寢園月暗衣冠古，選閣雲深筆硯靈。", "清衛有威森鳳戟，嬌嬪無語倚龍屏。", "太平天子尊儒學，錦帙黄封賜六經。"]'),
('d3da6ed4-c18a-4631-80ea-57bb31f84a6f','聚景園','陳允平','宋','宋诗','song-poetry','','[]','上苑韶光隔鳳城，十分春事屬流鶑。',64,'全唐诗/poet.song.233000.json','["上苑韶光隔鳳城，十分春事屬流鶑。", "雨餘芳草欲無地，風定落花如有聲。", "柳榭雲深棲鸛鵲，櫸塘沙暖浴鵁鶄。", "年來翠輦經遊少，七十二亭空月明。"]'),
('53282b01-bb71-4758-a495-985795dcf225','補陀山','陳允平','宋','宋诗','song-poetry','','[]','茫茫東海東，古洞石玲瓏。',48,'全唐诗/poet.song.233000.json','["茫茫東海東，古洞石玲瓏。", "蓬島三山近，華夷一水通。", "魚龍多變化，日月自虛空。", "此境元非幻，人心隠顯中。"]'),
('fc98dde1-1a97-4014-886d-b04fc88661d2','四明洞天','陳允平','宋','宋诗','song-poetry','','[]','四壁玲瓏聳石樓，四窗雲氣擁仙遊。',64,'全唐诗/poet.song.233000.json','["四壁玲瓏聳石樓，四窗雲氣擁仙遊。", "半空星斗浮天井，一洞烟霞透沃洲。", "蜥蜴現時曾呪雨，獼猴啼處客悲秋。", "他年定作山中隠，肯向紅塵白盡頭。"]'),
('49b70265-2dff-4414-a1b1-d6f147e5d600','盤陀','陳允平','宋','宋诗','song-poetry','','[]','盤陀石上看松眠，薜荔凌霄結紫烟。',32,'全唐诗/poet.song.233000.json','["盤陀石上看松眠，薜荔凌霄結紫烟。", "何處鶴聲驚夢醒，一雙飛起茯苓仙。"]'),
('f4e18843-aae1-4e9d-9265-b683a5269b68','江闊','陳允平','宋','宋诗','song-poetry','','[]','江闊雁聲遥，何人共寂寥。',48,'全唐诗/poet.song.233000.json','["江闊雁聲遥，何人共寂寥。", "青天不可問，明月若爲邀。", "俠士誇騎鶴，蠻奴學射雕。", "平生堂下柳，聊復伴秋宵。"]'),
('1ed217ac-a558-4329-8622-fb90cdf4a8eb','淮西','陳允平','宋','宋诗','song-poetry','','[]','舟子解貪程，能知倦客情。',48,'全唐诗/poet.song.233000.json','["舟子解貪程，能知倦客情。", "斷雲微雨霽，遠水落霞明。", "驛古如荒廟，山平接廢城。", "遊淮少年事，今祇歎勞生。"]'),
('44215ad9-a7fb-4d3e-b0cf-f7f92c9f3fbb','雪竇','陳允平','宋','宋诗','song-poetry','','[]','千年松樹凍欲死，夜半老僧眠樹根。',32,'全唐诗/poet.song.233000.json','["千年松樹凍欲死，夜半老僧眠樹根。", "一片海雲吹不散，白龍拖雪上崑崙。"]'),
('2fcddce9-c580-4ff6-859d-f95f407c67bc','春塘','陳允平','宋','宋诗','song-poetry','','[]','春塘雨歇曙鶑啼，坊院深閑竹樹西。',32,'全唐诗/poet.song.233000.json','["春塘雨歇曙鶑啼，坊院深閑竹樹西。", "靜倚綠窗看漏水，野花開到白棠梨。"]'),
('88487d94-f086-40d5-b8fe-32de1e3a51c4','錢塘八月潮','陳允平','宋','宋诗','song-poetry','','[]','五丁椎碎爛銀堆，注作東南水一杯。',64,'全唐诗/poet.song.233000.json','["五丁椎碎爛銀堆，注作東南水一杯。", "秋半忽疑天外雪，夜深俄聽月中雷。", "大鵬擊浪驚龍卧，老蜃噓雲誤燕來。", "日日濤頭多拱北，至尊元在鬰簫臺。"]'),
('347dd051-3e6a-485e-a4e6-2937f47f48c1','芝山','陳允平','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','春風幾樹石楠開，誰采靈芝去不回。',64,'全唐诗/poet.song.233000.json','["春風幾樹石楠開，誰采靈芝去不回。", "彭蠡水分雙港落，匡廬雲度五峰來。", "鍾沉古寺僧初定，月墮長松鳥自哀。", "堪歎昔人携酒地，斷碑無主卧蒼苔。"]'),
('6c24c9fc-6de9-40b1-acef-0d70e1c58228','堤上柳','陳允平','宋','宋诗','song-poetry','','[]','暗黄摇曳六橋雲，萬戶千門一日春。',32,'全唐诗/poet.song.233000.json','["暗黄摇曳六橋雲，萬戶千門一日春。", "休把柔條都折盡，明朝多少出城人。"]'),
('343726ed-5b9a-496c-85f8-fa61cd85f1dc','城西楊梅','陳允平','宋','宋诗','song-poetry','','[]','炎炎火樹照千山，南客應同荔子看。',64,'全唐诗/poet.song.233000.json','["炎炎火樹照千山，南客應同荔子看。", "金谷人遊紅步障，玉房仙煉紫華丹。", "猩唇泣露珊瑚軟，鶴頂迎風瑪瑙寒。", "若使漢宮知此味，又添飛驛上長安。"]'),
('2b4736ea-776e-429a-bbb0-8547fd79c1e6','僧房薜荔','陳允平','宋','宋诗','song-poetry','','[]','寸草曾收藥籠功，誰移野色近禪翁。',64,'全唐诗/poet.song.233000.json','["寸草曾收藥籠功，誰移野色近禪翁。", "甘同木石拋閑地，恥附松蘿上碧空。", "旋長纖枝宜雨綠，未刪宿葉待霜紅。", "爲衣或許湘人采，清徹崇蘭兩佩風。"]'),
('dc416fe8-a3ab-4837-9656-cd084c3c5600','歸燕','陳允平','宋','宋诗','song-poetry','','[]','王謝堂前柳樹蒼，玉京墳上蘚花黄。',32,'全唐诗/poet.song.233000.json','["王謝堂前柳樹蒼，玉京墳上蘚花黄。", "無情又逐東風去，落日朱簾幾斷腸。"]'),
('7ee382ec-ffd1-4be6-9e39-28d0185b37fc','宿鷺','陳允平','宋','宋诗','song-poetry','','[]','西風歷歷起寒莎，皆立林宵雪一窠。',32,'全唐诗/poet.song.233000.json','["西風歷歷起寒莎，皆立林宵雪一窠。", "三十六陂烟水闊，夜深無奈月明多。"]'),
('e23eb468-b6ef-4275-9511-542f05102d00','猿','陳允平','宋','宋诗','song-poetry','','[]','掛石攀雲日半斜，亂山深處飽烟霞。',32,'全唐诗/poet.song.233000.json','["掛石攀雲日半斜，亂山深處飽烟霞。", "香林月滿僧歸去，啼落春風幾樹花。"]'),
('bb50d607-8a1a-4c30-8432-9e4e27adf92b','故宮','陳允平','宋','宋诗','song-poetry','','[]','瓊臺玉館照青紅，夢斷思陵檜柏風。',32,'全唐诗/poet.song.233000.json','["瓊臺玉館照青紅，夢斷思陵檜柏風。", "三十二門金鎖合，年年春雨掃梧桐。"]'),
('d79bd3d2-a520-4419-8f15-151774fd7d26','長門曲','陳允平','宋','宋诗','song-poetry','','[]','紫鳳雙飛曉鏡臺，玉樓春冷燕空來。',32,'全唐诗/poet.song.233000.json','["紫鳳雙飛曉鏡臺，玉樓春冷燕空來。", "蛾眉不及宮前柳，一度春風一度開。"]'),
('0c04350a-4153-43a3-b184-a9fec7ff2569','多景樓','陳允平','宋','宋诗','song-poetry','','[]','懷古心情獨倚樓，荻花楓葉滿江秋。',64,'全唐诗/poet.song.233000.json','["懷古心情獨倚樓，荻花楓葉滿江秋。", "地雄吳楚東南會，水接荆揚上下流。", "鐵甕百年春雨夢，銅駝萬里夕陽愁。", "西風歷歷吹征雁，又带邊聲過石頭。"]'),
('99748261-babb-45a4-a590-ff9b2b940ffc','清風閣','陳允平','宋','宋诗','song-poetry','','[]','巍巍楹檻逼星河，城上闌干野色多。',64,'全唐诗/poet.song.233000.json','["巍巍楹檻逼星河，城上闌干野色多。", "天目水分波浩渺，大湖山點石嵯峨。", "羅窗夜氣吹銀燭，翠箔秋聲動玉珂。", "我欲乘空呼列子，月明何處起蘋歌。"]'),
('40dad35c-d60e-497d-a85d-fe1c6a95338e','冷泉亭','陳允平','宋','宋诗','song-poetry','','[]','西竺峰飛小朶來，閑僧曾共倚崔嵬。',64,'全唐诗/poet.song.233000.json','["西竺峰飛小朶來，閑僧曾共倚崔嵬。", "寒驚玉匣光初瀉，曉怯冰壺凍未開。", "雲外有香丹桂落，洞中無月白猿哀。", "當年洗耳人何在，擬勺清泠酹碧苔。"]'),
('9857c5db-2703-4337-9ed1-d9802dd79b08','姑蘇臺','陳允平','宋','宋诗','song-poetry','','[]','高樓三百尺，落日幾登臨。',48,'全唐诗/poet.song.233000.json','["高樓三百尺，落日幾登臨。", "越國一嘗膽，吳娃頻捧心。", "野猿窺燐火，宮燕語秋霖。", "坐久忽聞笛，五湖烟水深。"]'),
('b298880f-d9f0-4bd5-b71c-164365ac1b49','春閨','陳允平','宋','宋诗','song-poetry','','[]','終日懷人倚翠闌，別長愁覺釧金寬。',64,'全唐诗/poet.song.233000.json','["終日懷人倚翠闌，別長愁覺釧金寬。", "顰眉鈿葉拋鴛甃，彈淚燈花落鳳盤。", "梅粉有香供夜雨，柳絲無力受春寒。", "階前拾得相思子，自結羅囊繡合歡。"]'),
('7a6e8372-c7f9-4fc0-bf1f-29f9e0d760a5','綠瑣','陳允平','宋','宋诗','song-poetry','','[]','綠瑣銀臺燭焰紅，月痕斜過井梧東。',32,'全唐诗/poet.song.233000.json','["綠瑣銀臺燭焰紅，月痕斜過井梧東。", "背人約住黄金釧，輕札香羅護守宮。"]'),
('62d8baef-ded8-4e89-a14e-679046adeb04','臺上','陳允平','宋','宋诗','song-poetry','','[]','客舍新移近魯臺，翛然一榻少塵埃。',32,'全唐诗/poet.song.233000.json','["客舍新移近魯臺，翛然一榻少塵埃。", "丁寧黄耳休驚吠，不是閑人定不來。"]'),
('122011cf-5233-4574-b868-7af62dbb4dcb','豐樂樓初成','陳允平','宋','宋诗','song-poetry','','[]','紅塵飛不到闌干，十二朱簾捲暮寒。',64,'全唐诗/poet.song.233000.json','["紅塵飛不到闌干，十二朱簾捲暮寒。", "上苑鶑啼花木暗，六橋人散水雲寬。", "春風玉佩驂黄鶴，夜月瓊簫駐紫鸞。", "檐外青青楊柳色，幾回曾向畫船看。"]'),
('84485718-1d28-4e3c-9953-303634cdfc1a','竹枝曲','陳允平','宋','宋诗','song-poetry','','[]','峨眉山頭月如眉，畫眉夬婿歸不歸。',32,'全唐诗/poet.song.233000.json','["峨眉山頭月如眉，畫眉夬婿歸不歸。", "十日學德眉似月，眉成又是月圓時。"]'),
('3d15446c-35f9-4015-8636-c16e196a4a86','春寒','何應龍','宋','宋诗','song-poetry','','[]','博山熏盡鷓鴣斑，羅带同心不忍看。',32,'全唐诗/poet.song.233000.json','["博山熏盡鷓鴣斑，羅带同心不忍看。", "莫近欄干聽花雨，樓高無處着春寒。"]'),
('7f70e298-f5b9-4c03-b59d-6f076ddc1d42','客懷','何應龍','宋','宋诗','song-poetry','','[]','客懷處處不宜秋，秋到梧桐動客愁。',32,'全唐诗/poet.song.233000.json','["客懷處處不宜秋，秋到梧桐動客愁。", "想得故人無字到，鴈聲遠過夕陽樓。"]'),
('8ff6a4bf-63f2-47b9-a1e1-67662d64a6b9','寫情','何應龍','宋','宋诗','song-poetry','','[]','灑淚題春墨暈乾，東風無便寄郎難。',32,'全唐诗/poet.song.233000.json','["灑淚題春墨暈乾，東風無便寄郎難。", "青箱再展牋雲看，蠹却相思字不完。"]'),
('52593749-db56-4862-9911-e24d6a6c83f9','寄胡雪江','何應龍','宋','宋诗','song-poetry','','[]','借得官亭小似船，六橋風月友三賢。',32,'全唐诗/poet.song.233000.json','["借得官亭小似船，六橋風月友三賢。", "芙蓉未發荷花老，一點詩情若箇邊。"]'),
('96269b15-8aa4-44dc-86a1-3d1b481a0c3b','旅中示同輩','何應龍','宋','宋诗','song-poetry','','[]','與君同出已多時，費盡囊金典盡衣。',32,'全唐诗/poet.song.233000.json','["與君同出已多時，費盡囊金典盡衣。", "只待春江煙浪暖，小舟先趁白鷗歸。"]'),
('04545398-9722-4ddd-be89-29280bac4c60','清曉','何應龍','宋','宋诗','song-poetry','','[]','清曉輕傳一信風，花添紅粉草添茸。',32,'全唐诗/poet.song.233000.json','["清曉輕傳一信風，花添紅粉草添茸。", "畫樓十二欄干曲，春在珠簾第幾重。"]'),
('d9520c3d-de3a-409c-aa26-3845cef92fb0','笋','何應龍','宋','宋诗','song-poetry','','[]','泥中莫怪出頭遲，歷盡冰霜祇自知。',32,'全唐诗/poet.song.233000.json','["泥中莫怪出頭遲，歷盡冰霜祇自知。", "昨夜震雷轟渭畝，請君來看化龍枝。"]'),
('5ee78276-a205-45e2-97c9-5cb1d84c00ff','過垂虹','何應龍','宋','宋诗','song-poetry','','[]','垂虹橋下水連天，一带青山落照邊。',32,'全唐诗/poet.song.233000.json','["垂虹橋下水連天，一带青山落照邊。", "三十六陂煙浦冷，鷺鷥飛上釣漁船。"]'),
('4116c87a-f162-451e-ac23-12fcdd45712d','吳蠶','何應龍','宋','宋诗','song-poetry','','[]','正是吳蠶出火時，交交窗外一禽啼。',32,'全唐诗/poet.song.233000.json','["正是吳蠶出火時，交交窗外一禽啼。", "溪西有葉高難採，遥見青裙上竹梯。"]'),
('d08c4a3e-e61f-4c07-a234-6892fef0e7af','效香奩體','何應龍','宋','宋诗','song-poetry','','[]','雲幕重重雨未收，嫩寒先到玉簾鈎。',32,'全唐诗/poet.song.233000.json','["雲幕重重雨未收，嫩寒先到玉簾鈎。", "一杯晚酒無人共，羞带雙花下小樓。"]'),
('aba8cee0-7c0b-4956-9627-3b6eb1ac8800','木犀','何應龍','宋','宋诗','song-poetry','','[]','露粟藏金一半開，層層碧玉映樓臺。',32,'全唐诗/poet.song.233000.json','["露粟藏金一半開，層層碧玉映樓臺。", "西風昨夜吹香過，人在欄干待月來。"]'),
('e4cf9f24-0130-49bb-a2a9-30645faa35ef','夏日即事','何應龍','宋','宋诗','song-poetry','','[]','野土生煙草樹焦，彤彤日脚火雲燒。',32,'全唐诗/poet.song.233000.json','["野土生煙草樹焦，彤彤日脚火雲燒。", "池邊自拗青荷葉，分付山童蓋藥苗。"]'),
('c1bd78b1-681e-4fe3-a99e-6ac428ba5323','題駱秀才葺故廬疏','何應龍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','家在西湖合澗橋，短籬圍得數椽茅。',32,'全唐诗/poet.song.233000.json','["家在西湖合澗橋，短籬圍得數椽茅。", "歸來頗費支撐力，羞見春風燕子巢。"]'),
('f1eac374-104e-4c84-ad2e-62bb68637928','有別','何應龍','宋','宋诗','song-poetry','','[]','樓上佳人唱渭城，樓前楊柳識離情。',32,'全唐诗/poet.song.233000.json','["樓上佳人唱渭城，樓前楊柳識離情。", "一聲未是難聽處，最是難聽第四聲。"]'),
('0a1be2d8-c644-4bce-9bb5-d4ff0abb1e22','春詞','何應龍','宋','宋诗','song-poetry','','[]','玉纖輕揭綉簾開，行到花前淚滿腮。',32,'全唐诗/poet.song.233000.json','["玉纖輕揭綉簾開，行到花前淚滿腮。", "正爾春心無處託，一雙胡蝶忽飛來。"]'),
('d68425ff-8b36-44d6-a17e-0af2525e66aa','有所思','何應龍','宋','宋诗','song-poetry','','[]','曾倚空屏唱柳枝，一聲嬌逐暮雲低。',32,'全唐诗/poet.song.233000.json','["曾倚空屏唱柳枝，一聲嬌逐暮雲低。", "重來只見流鶑在，立盡斜陽不肯啼。"]'),
