('e2478ea5-673c-465a-aba8-09cd33ff7846','春陰','何應龍','宋','宋诗','song-poetry','','[]','密雨流酥入翠苔，春陰日日鏁樓臺。',32,'全唐诗/poet.song.233000.json','["密雨流酥入翠苔，春陰日日鏁樓臺。", "女郎未有尋芳約，辜負櫻桃一半開。"]'),
('bbe49880-53ec-4b33-b181-25672c060352','老翁','何應龍','宋','宋诗','song-poetry','','[]','八十昂藏一老翁，得錢長是醉春風。',32,'全唐诗/poet.song.233000.json','["八十昂藏一老翁，得錢長是醉春風。", "杏花村酒家家好，莫向橋邊問牧童。"]'),
('0535f7fd-8505-4007-8e5b-cf5a61e3be42','清明','何應龍','宋','宋诗','song-poetry','','[]','踏歌槌鼓近清明，小雨霏霏欲弄晴。',32,'全唐诗/poet.song.233000.json','["踏歌槌鼓近清明，小雨霏霏欲弄晴。", "喚起十年心上事，春風樓下賣花聲。"]'),
('2a9f07b2-5608-4221-a475-643e26be1ce4','杜鵑','何應龍','宋','宋诗','song-poetry','','[]','君若思歸可便歸，故鄉祇在錦江西。',32,'全唐诗/poet.song.233000.json','["君若思歸可便歸，故鄉祇在錦江西。", "不知何事留君住，却向空山日夜啼。"]'),
('fff42908-b528-4d4b-b499-8248ef6bf9d6','贈友人','何應龍','宋','宋诗','song-poetry','','[]','我向詩中爲活計，君於酒裏作生涯。',32,'全唐诗/poet.song.233000.json','["我向詩中爲活計，君於酒裏作生涯。", "世間樂事惟詩酒，各自風流占一家。"]'),
('0bda2b11-fd39-4af7-9b6b-29989c46c61e','簾','何應龍','宋','宋诗','song-poetry','','[]','半窣香波護曲欄，纈花紅映玉鈎閑。',32,'全唐诗/poet.song.233000.json','["半窣香波護曲欄，纈花紅映玉鈎閑。", "曉來幾陣輕風過，時見溪南罨畫山。"]'),
('06d93a8a-a4b6-449b-93f0-cf1ecaacabbb','碧桃','何應龍','宋','宋诗','song-poetry','','[]','玉僊同駕玉鸞飛，天上曾攀带露枝。',32,'全唐诗/poet.song.233000.json','["玉僊同駕玉鸞飛，天上曾攀带露枝。", "一片不知何處落，曉來流到湧金池。"]'),
('6222ef1e-978f-44a9-92d3-10ebdcfd981a','芍藥','何應龍','宋','宋诗','song-poetry','','[]','金蕊絲頭茜染成，五雲樓映玉盤傾。',32,'全唐诗/poet.song.233000.json','["金蕊絲頭茜染成，五雲樓映玉盤傾。", "謝郎一入中書後，二十四橋空月明。"]'),
('a89c8f71-71e2-4867-93a5-05ce77577a32','傷春','何應龍','宋','宋诗','song-poetry','','[]','荷葉初浮水上錢，柳花飄盡岸頭綿。',32,'全唐诗/poet.song.233000.json','["荷葉初浮水上錢，柳花飄盡岸頭綿。", "不知春色歸何處，欲向空山問杜鵑。"]'),
('8909f734-8e14-4fd7-92ea-31838f55264b','效無題體','何應龍','宋','宋诗','song-poetry','','[]','玉釵風斷扇雲深，砌冷簾空月易沉。',32,'全唐诗/poet.song.233000.json','["玉釵風斷扇雲深，砌冷簾空月易沉。", "流水落花無處問，一年春事一年心。"]'),
('f1399744-f300-4452-9147-9ef6770b4a5c','臘梅','何應龍','宋','宋诗','song-poetry','','[]','晴日烘開小蜜房，紫檀心裏認蜂黄。',32,'全唐诗/poet.song.233000.json','["晴日烘開小蜜房，紫檀心裏認蜂黄。", "一冬不被風吹落，却訝江梅易斷腸。"]'),
('6036f314-8629-4733-a0fd-f9009ff61d3e','行人','何應龍','宋','宋诗','song-poetry','','[]','柳花吹斷晚寒輕，草色拖裙罨岸青。',32,'全唐诗/poet.song.233000.json','["柳花吹斷晚寒輕，草色拖裙罨岸青。", "解識行人今古恨，路邊惟有短長亭。"]'),
('7eed7028-e0f6-444d-9072-3194de358932','柴門','何應龍','宋','宋诗','song-poetry','','[]','何必逢人盡說貧，自來求己勝求人。',32,'全唐诗/poet.song.233000.json','["何必逢人盡說貧，自來求己勝求人。", "梅花落盡青山遠，深掩柴門過一春。"]'),
('6581db9c-16d2-4f98-8b63-becc2fcb8839','落花','何應龍','宋','宋诗','song-poetry','','[]','南浦雲歸春亦歸，綠楊枝上鳥空啼。',32,'全唐诗/poet.song.233000.json','["南浦雲歸春亦歸，綠楊枝上鳥空啼。", "落花滿地無人管，一半和香作燕泥。"]'),
('89e020d8-8edc-4b90-a277-88b317bca797','元夕戲題','何應龍','宋','宋诗','song-poetry','','[]','從教香月轉亭西，貪看燈毬忘却歸。',32,'全唐诗/poet.song.233000.json','["從教香月轉亭西，貪看燈毬忘却歸。", "挨得玉梅零落盡，蛾兒猶傍鬢邊飛。"]'),
('1f736a3c-6eaa-4dd9-a4a3-3c89beb23979','元夕書懷','何應龍','宋','宋诗','song-poetry','','[]','去歲有燈仍有月，今年無月亦無燈。',32,'全唐诗/poet.song.233000.json','["去歲有燈仍有月，今年無月亦無燈。", "誰知此夕吟懷裏，看盡寒梅一澗冰。"]'),
('ce24a2f6-a101-4187-9153-50f874bceb69','貧女吟二首  其一','褚伯秀','宋','宋诗','song-poetry','','[]','夜續晨炊貧自由，强教塗抹只堪羞。',32,'全唐诗/poet.song.233000.json','["夜續晨炊貧自由，强教塗抹只堪羞。", "閉門靜看花開落，過却春風不識愁。"]'),
('8a67f803-d278-43cb-8945-ab762eb72108','貧女吟二首  其二','褚伯秀','宋','宋诗','song-poetry','','[]','寂寞篷窗鎖冷雲，地爐紉補自陽春。',32,'全唐诗/poet.song.233000.json','["寂寞篷窗鎖冷雲，地爐紉補自陽春。", "千金莫誤朱門聘，不是穿珠插翠人。"]'),
('59cb7da4-d078-40ad-9743-98642b9215f2','呈周清溪','褚伯秀','宋','宋诗','song-poetry','','[]','清溪千仞餘，中有一道士。',192,'全唐诗/poet.song.233000.json','["清溪千仞餘，中有一道士。", "彼亦何人斯，景純慕若此。", "吾鄉汝南英，大滌隠君子。", "好客仍收書，東老未足擬。", "竹宮需賢才，師命促共理。", "無心雲出岫，有類月印水。", "樂與物爲春，自然人鑑止。", "二千年再來，雅號乃默契。", "挈世返真淳，爲教立儀軌。", "潛增翠蛟潤，益壯天柱勢。", "近聞築玄都，崇崗枕龍耳。", "充庭蘭玉茂，五雲樓閣起。", "笙鶴時往來，塵寰一俯視。", "紛爭夢未醒，王侯到螻蟻。", "君壯我垂老，別日嗟激矢。", "相逢且盡歡，昇仙不如醉。"]'),
('35ea7439-3121-4591-8f87-ee4c7810eb81','送金約山歸洞霄','褚伯秀','宋','宋诗','song-poetry','','[]','門掩冷雲堆，推敲更有誰。',48,'全唐诗/poet.song.233000.json','["門掩冷雲堆，推敲更有誰。", "不忘分芋約，來趁折梅期。", "聽雪連宵話，傷時幾首詩。", "侵晨催返棹，猿鶴報先知。"]'),
('89e295d9-fd42-4543-a893-7cf952f36dfa','送玉海宗師還茅山','褚伯秀','宋','宋诗','song-poetry','','[]','湖澥天教十載閒，玉經功就勝居壇。',64,'全唐诗/poet.song.233000.json','["湖澥天教十載閒，玉經功就勝居壇。", "驚塵天目妨龍卧，晚歲華陽望鶴還。", "入詠五噫丹闕近，會心三笑畫溪寒。", "世緣歷盡仙緣熟，坐斷陪真向上關。"]'),
('ae86fd18-2c67-411b-b482-67e053cba4a2','春日山居','褚伯秀','宋','宋诗','song-poetry','','[]','萬山深鎖竹房幽，寒碧欺春恰似秋。',64,'全唐诗/poet.song.233000.json','["萬山深鎖竹房幽，寒碧欺春恰似秋。", "人醉藥爐憑鶴看，窗閑吟筆被猿偷。", "護岩苔色侵衣潤，逼枕溪聲入夢流。", "童子掃花關莫掩，恐妨詩社客來遊。"]'),
('2b9df78c-86af-4475-9b08-f1c1d3f788ed','題翠蛟亭','褚伯秀','宋','宋诗','song-poetry','','[]','不逐風雷去，蜿蜒舞石屏。',48,'全唐诗/poet.song.233000.json','["不逐風雷去，蜿蜒舞石屏。", "源深有龍伴，流遠借丹靈。", "坐覺雲藏樹，吟忘雪濺亭。", "巖隈下斜日，歸去了殘經。"]'),
('b49cf624-c2d8-42bd-a87a-30fdbefbcee2','軍中寄內','陳子全','宋','宋诗','song-poetry','','[]','一望瀟湘徧露迷，胡笳吹月夜凄凄。',64,'全唐诗/poet.song.233000.json','["一望瀟湘徧露迷，胡笳吹月夜凄凄。", "回天無力心難死，矢日同仇志應齊。", "但使首陽存漢地，不教陰塞牧羌羝。", "聲名一墮誰能贖，珍重雌雄劍化蜺。"]'),
('85ad2fbe-4326-4f45-9209-548e60b97d8e','西施吟','何雲','宋','宋诗','song-poetry','','[]','曾將分鏡淚，灑向館娃宮。',48,'全唐诗/poet.song.233000.json','["曾將分鏡淚，灑向館娃宮。", "狐到亡吳日，天留霸越功。", "魄堪寒夜月，香亦撲秋風。", "愧殺轆轤輩，魚須出袖中。"]'),
('4d8cd0df-263f-4be8-b4c6-5a4091be0fb1','句','寶祐時人','宋','宋诗','song-poetry','','[]','空使蜀人思董永，恨無漢劍斬丁公。',16,'全唐诗/poet.song.233000.json','["空使蜀人思董永，恨無漢劍斬丁公。"]'),
('b3653e5f-6d51-402a-a9c3-ccba5718112e','西湖爲陳世崇餞行','壑大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我昔見君方成童，長吉才華驚鉅公。',264,'全唐诗/poet.song.233000.json','["我昔見君方成童，長吉才華驚鉅公。", "人間科第不屑就，直使聲名聞九重。", "乃翁引上凝華殿，子虛不待他人薦。", "入直承明凡幾年，天上奇書盡曾見。", "翩然歸去大江西，二疏父子還相隨。", "故鄉分得雲水地，却喜不爽漁樵期。", "春雨騎牛對烟草，何如振衣隨龍五雲表。", "秋霜黄獨煨地爐，何如駝峰犀筯食天厨。", "林間食葉抄詩句，何如宮妃捧硯揮毫處。", "溪邊照影著荷衣，何如龍門應制奪錦時。", "鈞天夢斷難回顧，浩然合在山中住。", "金石臺前伴白雲，六年不踏西湖路。", "今日重來發長吁，忍看清平破草廬。", "盡拈書籍向人賣，歸買田園供荷鉏。", "乃翁八十齒髮落，倚門待兒斜日薄。", "孤山梅花带不歸，却喚扁舟載童鶴。"]'),
('88a5fe01-44b9-4e53-9ffc-73b77c47eaa4','鈞天','毛吾竹','宋','宋诗','song-poetry','','[]','鳶飛魚躍，鳬短鶴長。',372,'全唐诗/poet.song.233000.json','["鳶飛魚躍，鳬短鶴長。", "各適其適，孰尤彼蒼。", "奈何人異於萬物，身備乎五常。", "學關乎經濟，志效乎忠良。", "乃使蝸蚓同槁乎土壤，鴻雁俱逐乎稻粱。", "精神所著，夢遊八荒。", "浴銀河翻月之浪，熏旃檀带露之香。", "戴芙蓉九華之冠，披雲錦五色之裳。", "騎祥麟兮翳綵鳳，攀若木兮拂扶桑，直造乎玉皇香案之傍。", "白虎守關御劍芒，熒惑執法齒髮張。", "臯夔丘旦列雁行，肅然鳴佩諧宮商。", "關張衛霍立兩廂，相向盾甲明如霜。", "千官拜起低復昂，星輝霞彩難爲祥。", "一人殿中立宣揚，令臣奏事無恐惶。", "臣愚幸覩天日光，願拜短疏裨毫芒。", "讀罷帝親把袖藏，曰汝所奏見未嘗。", "政如藥性和溫良，一一可以瘳民瘡。", "又如百煉昆吾鋼，用之國可無妖祥。", "惜哉無遇徒心傷，亟宜歸世朝君王。", "君王神聖今禹湯，勤求賢雋食不遑。", "扶天大象親提綱，充庭至寶皆琳琅。", "尚憐空谷遺幽芳，蒲輪鶴詔紛相望。", "賜汝紫綬黄金章，衮衣赤舄坐廟堂。", "燮調萬化躋時康，凌轢周漢超虞唐。"]'),
('a4ec235c-01b1-44f8-aa8a-eac311ddafa0','海棠','杜汝能','宋','宋诗','song-poetry','','[]','幾樹繁紅一徑深，春風裁剪錦成屏。',32,'全唐诗/poet.song.233000.json','["幾樹繁紅一徑深，春風裁剪錦成屏。", "花前莫作淵材恨，且看楊妃睡未醒。"]'),
('994fa1d6-70b0-431b-a65e-82657f69f7cb','絲瓜','杜汝能','宋','宋诗','song-poetry','','[]','寂寥籬戶入泉聲，不見山容亦自清。',32,'全唐诗/poet.song.233000.json','["寂寥籬戶入泉聲，不見山容亦自清。", "數日雨晴秋草長，絲瓜沿上瓦牆生。"]'),
('594a6ed3-1c36-4d89-b777-b8c0cbfc0f21','時思薦福寺','杜汝能','宋','宋诗','song-poetry','','[]','□知山不厭，高處更營亭。',48,'全唐诗/poet.song.233000.json','["□知山不厭，高處更營亭。", "對面開詩景，當空列畫屏。", "藥生香草異，蓋結古松靈。", "見說師齋暇，時來此讀經。"]'),
('20962021-a4eb-4164-9063-6674eb18137a','贈陳隨隠','杜汝能','宋','宋诗','song-poetry','','[]','父子名相繼，如君又出奇。',48,'全唐诗/poet.song.233000.json','["父子名相繼，如君又出奇。", "乾坤鍾秀氣，湖海誦新詩。", "放鶴春風遠，橫琴夜月遲。", "未應隨大隠，閑過聖明時。"]'),
('980a93d5-9e8a-4f92-991b-67fbd7c2f53f','寄薛泳','杜汝能','宋','宋诗','song-poetry','','[]','長安君別後，動即是相思。',48,'全唐诗/poet.song.233000.json','["長安君別後，動即是相思。", "料想還家日，勝如爲客時。", "江寒驚夢斷，路遠得書遲。", "幾度空凝望，春風又柳絲。"]'),
('c480fb6c-0f0f-4d5f-8a4c-9d3f696c65b6','寄吳夢鶴','杜汝能','宋','宋诗','song-poetry','','[]','憐君如泛梗，漂泊竟何之。',48,'全唐诗/poet.song.233000.json','["憐君如泛梗，漂泊竟何之。", "經歲無來信，還家是幾時。", "秋高鴻過少，地冷菊開遲。", "屢夕寒燈下，秋吟只自知。"]'),
('0db01fa9-2ade-4845-849e-152ddaa5abb8','送顧梅山之揚州','杜汝能','宋','宋诗','song-poetry','','[]','高人必見知，已是渡淮遲。',48,'全唐诗/poet.song.233000.json','["高人必見知，已是渡淮遲。", "路遠飄零客，囊多絕妙詩。", "早蟬何處聽，歸棹幾時期。", "到定陪吟宴，瓊花惜過時。"]'),
('1c4b34bd-4a92-4141-95e8-48cbd8838caa','句','杜汝能','宋','宋诗','song-poetry','','[]','閑立綠楊影，交眠紅藕花。',12,'全唐诗/poet.song.233000.json','["閑立綠楊影，交眠紅藕花。"]'),
('b1ef8736-1f13-43b1-8505-00dc4efb4b39','贈陳隨隠','吳石翁','宋','宋诗','song-poetry','','["\u534e\u5c71"]','大隠君家小隠君，得名太早忌人聞。',64,'全唐诗/poet.song.233000.json','["大隠君家小隠君，得名太早忌人聞。", "秋窗吟共緱山月，曉榻眠分華嶽雲。", "鶑欲引雛先出谷，馬纔生驥便離羣。", "新詩却要多拈出，突過郎罷張我軍。"]'),
('d8dd0a5c-fc9c-4ac4-a61d-ddb1f21e9e08','贈陳隨隠','劉彥朝','宋','宋诗','song-poetry','','[]','坎止流行只任天，吟廬新傍紫薇邊。',64,'全唐诗/poet.song.233000.json','["坎止流行只任天，吟廬新傍紫薇邊。", "夜窗低過宮花月，曉巷深橫御柳烟。", "五字肯同餘子說，一燈親自乃翁傳。", "雖然不作功名念，却恐功名逼少年。"]'),
('5a52f02e-c4c3-4dda-adaf-d3cfbedb0e67','景定癸亥特旨以布衣陳隨隠除東宮掌書作書賀之  其一','錢舜選','宋','宋诗','song-poetry','','[]','吟筆何須管用銀，日供譔述聖恩新。',32,'全唐诗/poet.song.233000.json','["吟筆何須管用銀，日供譔述聖恩新。", "只今已脫凡塵去，便作金丹換骨人。"]'),
('c88c265f-1dee-4ec3-9483-e198ffe345b2','景定癸亥特旨以布衣陳隨隠除東宮掌書作書賀之  其二','錢舜選','宋','宋诗','song-poetry','','[]','夜泛孤篷載月船，靜搜吟料六橋邊。',32,'全唐诗/poet.song.233000.json','["夜泛孤篷載月船，靜搜吟料六橋邊。", "詩成上達宸聰了，流落人間到處傳。"]'),
('bda91fd6-b8d6-4b36-8f25-4159a41bbb20','紀夢','錢舜選','宋','宋诗','song-poetry','','[]','翠峰嵯峨三十六，寒泉落空響哀玉。',272,'全唐诗/poet.song.233000.json','["翠峰嵯峨三十六，寒泉落空響哀玉。", "甃花石路勢縈紆，玉闌干護修筠綠。", "雪髯老人負紫瓢，金絲麈尾遥相招。", "紅螺酌酒湛湛碧，坐倚蒼石吹洞簫。", "孤鶴來傳天上詔，老人挽余偕一到。", "飄飄高峰凌青冥，直過罡風履黄道。", "祥光樓閣倚崢嶸，神虎守關森衛兵。", "雙闔朱扉忽微啟，中有靈官來遠迎。", "絳衣持斧立丹陛，玉皇手中玉如意。", "雲璈風瑟自宮商，天聲清越非人世。", "帝旁青童傳帝宣，文華宮中呼謫仙。", "謫仙顧余笑且言，子宜亟反來他年。", "探懷贈我五色筆，子當寶之慎勿失。", "濃香氤氳迷帝所，長揖老人下西廡。", "身從日月上頭行，俯視斗杓分子午。", "雲氣相隨步武生，過耳但覺松風鳴。", "覺來握筆紀佳夢，月明樓鼓撾三更。"]'),
('79ee8197-eba4-42d4-b5a1-af6183d22d82','示姪','錢舜選','宋','宋诗','song-poetry','','[]','才過中年百念輕，獨于風月未忘情。',64,'全唐诗/poet.song.233000.json','["才過中年百念輕，獨于風月未忘情。", "貧將入骨詩方好，事不縈心夢亦清。", "萬卷難圖金馬貴，一篷當與白鷗盟。", "幸然不作諸侯客，猶恐江湖說姓名。"]'),
('b332778d-8c33-4918-8b57-9986364b0d4c','項羽','錢舜選','宋','宋诗','song-poetry','','[]','項羽天資自不仁，那堪亞父作謀臣。',32,'全唐诗/poet.song.233000.json','["項羽天資自不仁，那堪亞父作謀臣。", "鴻門若遂樽前計，又一商君又一秦。"]'),
('8151a11f-6a13-4e95-8859-b954218efed9','贈簡竹屋','錢舜選','宋','宋诗','song-poetry','','[]','山房幽潔處，桃李不能春。',48,'全唐诗/poet.song.233000.json','["山房幽潔處，桃李不能春。", "獨與此君子，一如吾故人。", "林空風有韻，影靜月無塵。", "肝肺皆冰雪，吟來字字新。"]'),
('955e0b98-dc04-4b98-8817-2ba9bca7a014','舟中','錢舜選','宋','宋诗','song-poetry','','[]','一舸乘風便，飄然疾似梭。',48,'全唐诗/poet.song.233000.json','["一舸乘風便，飄然疾似梭。", "水鄉秋雨足，茅舍夕陽多。", "野色傷衰草，湖聲泣敗荷。", "亂鴉歸宿處，人唱牧牛歌。"]'),
('b17fc32e-efaa-4657-82d6-1365f48e1f32','閑居','錢舜選','宋','宋诗','song-poetry','','[]','年來百懶惟便靜，幽事相關亦有時。',64,'全唐诗/poet.song.233000.json','["年來百懶惟便靜，幽事相關亦有時。", "窗上紙因晴日補，檻邊花趁小春移。", "夜先休息關門早，曉不趨承出戶遲。", "消遣餘生只如此，好懷正不要人知。"]'),
('8433c0c6-ce91-4854-9b66-7da66c0652bf','書壁','錢舜選','宋','宋诗','song-poetry','','[]','數椽成小隠，游息在其間。',48,'全唐诗/poet.song.233000.json','["數椽成小隠，游息在其間。", "貧者易爲樂，貴人難得閑。", "水雲懷笠澤，梅月夢孤山。", "久矣疏書卷，爲儒亦强顔。"]'),
('359a3410-117c-4e77-8cd8-1c94524d5c25','賀陳隨隠以布衣除東宮掌書','呂三餘','宋','宋诗','song-poetry','','[]','青宮樓觀近堯階，班列屏風間坐開。',64,'全唐诗/poet.song.233000.json','["青宮樓觀近堯階，班列屏風間坐開。", "人羨杜閒生杜甫，天教蘇頲繼蘇瓌。", "馬歸禁苑行邊柳，鶴伴平山隠處梅。", "我恨長鑱斸黄獨，兀年無計策衰頹。"]'),
('ee81cbbd-06a0-44ff-9772-8809e526aebc','賀陳隨隠以布衣除東宮掌書','柳桂孫','宋','宋诗','song-poetry','','[]','鏤玉裁冰字字奇，少年親結九重知。',64,'全唐诗/poet.song.233000.json','["鏤玉裁冰字字奇，少年親結九重知。", "君臣際遇榮千載，父子推敲冠一時。", "罍進楚蘭春奏雅，瓶分陶菊夜聯詩。", "五雲樓近開黄道，金紫連班進赤墀。"]'),
('9c7a7346-e948-4599-a407-6cc0e406afa2','杜鵑花','柳桂孫','宋','宋诗','song-poetry','','[]','金鴨香燒午夜烟，空彈寶瑟怨流年。',32,'全唐诗/poet.song.233000.json','["金鴨香燒午夜烟，空彈寶瑟怨流年。", "東風一架薔薇雪，老盡春風是杜鵑。"]'),
('7e2978ae-05c9-4222-929a-1fa5c30d2ade','花山寺看黄山  其一','柳桂孫','宋','宋诗','song-poetry','','[]','翠色沈沈萬樹春，幽懷宜共竹爲鄰。',32,'全唐诗/poet.song.233000.json','["翠色沈沈萬樹春，幽懷宜共竹爲鄰。", "黄山只在闌干外，谿閣雲深認不真。"]'),
('54c20fe0-a238-4117-8532-e8bb8498fba3','花山寺看黄山  其二','柳桂孫','宋','宋诗','song-poetry','','[]','借得雲房半榻眠，三生夙結靜中緣。',32,'全唐诗/poet.song.233000.json','["借得雲房半榻眠，三生夙結靜中緣。", "茶罏謾著松枝火，趺坐蒲團聽夜禪。"]'),
('b3e4af6e-a9c4-4844-b6ea-3755e9bf77bd','賀陳隨隠以布衣除東宮掌書','俞某','宋','宋诗','song-poetry','','[]','萬人海裏闢幽扉，欲學深居只布衣。',32,'全唐诗/poet.song.233000.json','["萬人海裏闢幽扉，欲學深居只布衣。", "不道內前車馬閙，又催父子入宮闈。"]'),
('6c92c757-61ee-46b9-877a-cf9f32ce0612','送陳隨隠歸江西','黄力敘','宋','宋诗','song-poetry','','[]','詩在天地間，風清月明處。',240,'全唐诗/poet.song.233000.json','["詩在天地間，風清月明處。", "若爲深閉門，而可覓佳句。", "夫君小元龍，豪氣隘區宇。", "青春發詩材，秀茁長膏雨。", "流水與行雲，吾不見滯住。", "乘月滌吟毫，玉椀三危露。", "超詣自透脫，悟在觀劍舞。", "入宮畫蛾眉，胡爲衆女妒。", "君詩亦何憾，千載一時遇。", "向也詩道昌，吟聲喧禁籞。", "應制沈香亭，龍巾曾拭唾。", "今焉詩道厄，短筇策江路。", "悲嘯梁甫吟，侘傺離騷賦。", "浮雲時卷舒，睨此知出處。", "此其隨之義，大隠會境趣。", "天地梅又春，風緊雪飛絮。", "一笠灞橋馿，吟鞍且臨汝。", "得句從人傳，傳今亦傳古。", "要知是家傳，審言以傳甫。", "傳之而又傳，衣鉢傳宗武。"]'),
('3ceaa05c-eca6-445b-9ba8-038cb2c24009','贈陳隨隠歸游江西','張彝','宋','宋诗','song-poetry','','[]','醖藉中涵廊廟姿，詩文都好見宸批。',32,'全唐诗/poet.song.233000.json','["醖藉中涵廊廟姿，詩文都好見宸批。", "只蒙四字君王寵，蟣蝨微臣不用題。"]'),
('8cc495dd-2a5c-4071-a371-b8e386d12fe6','追和叔祖自述韻','胡震雷','宋','宋诗','song-poetry','','[]','霅川疑獄獨承當，敬遠炎炎即館凉。',64,'全唐诗/poet.song.233000.json','["霅川疑獄獨承當，敬遠炎炎即館凉。", "帝子幾曾謀不道，相臣自弗肯包荒。", "李貓初劾猶全命，梁犬重評竟斷腸。", "甘死如飴行素志，豈知流入殺青香。"]'),
('3bc95c47-df3f-48a5-b544-b46137422c5c','績溪書懷  其一','董楷','宋','宋诗','song-poetry','','[]','行來人世塵千里，夢繞故山春萬重。',32,'全唐诗/poet.song.233000.json','["行來人世塵千里，夢繞故山春萬重。", "慈母新年音信缺，遥瞻白雲是中峰。"]'),
('ece62338-2a0e-41d0-8a73-00436abfd1a3','績溪書懷  其二','董楷','宋','宋诗','song-poetry','','[]','閣雪峰陰未肯明，卧聽寒玉瀉簷聲。',32,'全唐诗/poet.song.233000.json','["閣雪峰陰未肯明，卧聽寒玉瀉簷聲。", "官居不事閒來往，閉戶焚香養性靈。"]'),
('3e7e4515-8b25-44a2-bd61-e127f9aeff9d','望雲','謝緒','宋','宋诗','song-poetry','','[]','東山渺渺白雲低，丹鳳何時下紫泥。',64,'全唐诗/poet.song.233000.json','["東山渺渺白雲低，丹鳳何時下紫泥。", "翹首夕陽連舊眺，謾看黄菊滿新谿。", "鶴閑庭砌人稀迹，苔護松蔭山徑迷。", "野老更疑天路近，蒼生猶自望雲霓。"]'),
('fd3ee28a-5bd3-4c48-a916-eb2d5e03488c','絕筆','謝緒','宋','宋诗','song-poetry','','[]','立志平夷尚未酬，莫言心事付東流。',64,'全唐诗/poet.song.233000.json','["立志平夷尚未酬，莫言心事付東流。", "淪胥天下誰能救，一死千年恨不休。", "湖水不沉忠義氣，淮淝自愧破秦謀。", "苕溪北去通胡塞，流此丹心滅虜酋。"]'),
('183569ea-074d-4a20-9678-1c39767163ff','又一首','謝緒','宋','宋诗','song-poetry','','[]','莫笑狂夫老更狂，推輪怒臂勇螳螂。',64,'全唐诗/poet.song.233000.json','["莫笑狂夫老更狂，推輪怒臂勇螳螂。", "三軍未復圖中土，萬姓空悲塞外鄉。", "動地聲名懸宇宙，擎天氣概蕩邊疆。", "忠心自古人人有，莫笑狂夫老更狂。"]'),
('a71de99a-cf8f-47bd-8acb-0955370a311d','贈周孝子二首  其一','徐應鑣','宋','宋诗','song-poetry','','[]','卜吉崇崗思愴然，雙魂同閟晝如年。',32,'全唐诗/poet.song.233000.json','["卜吉崇崗思愴然，雙魂同閟晝如年。", "山中細草初回碧，廬墓人啼血色鮮。"]'),
('7dcde2e9-745d-4143-8c98-f1d575cc45fc','贈周孝子二首  其二','徐應鑣','宋','宋诗','song-poetry','','[]','一自仙遊去不回，徒令孝子有餘哀。',32,'全唐诗/poet.song.233000.json','["一自仙遊去不回，徒令孝子有餘哀。", "他年華表歸來後，知是人間幾劫灰。"]'),
('52a46cdc-74f2-40c7-ab20-962a6ea6449f','絕命詞','徐應鑣','宋','宋诗','song-poetry','','[]','二男并一女，隨我上梯雲。',24,'全唐诗/poet.song.233000.json','["二男并一女，隨我上梯雲。", "烈士甘焚死，丹心照紫雯。"]'),
('ac8aa563-e6b8-4770-9320-e6fa467d6a01','殉節詩  其一','方氏','宋','宋诗','song-poetry','','[]','昊天懵懵，四海洶洶。',20,'全唐诗/poet.song.233000.json','["昊天懵懵，四海洶洶。", "趙氏終衰，妖孽景從。"]'),
('35c21a76-ed6c-4c67-a945-1500a1ad5cd6','殉節詩  其二','方氏','宋','宋诗','song-poetry','','[]','我生不辰，咨嗟風雨。',20,'全唐诗/poet.song.233000.json','["我生不辰，咨嗟風雨。", "一木難支，勸君解組。"]'),
('fd6be12b-640e-46f0-8503-5e6ffde7c759','殉節詩  其三','方氏','宋','宋诗','song-poetry','','[]','妾身邀隠，君志盡忠。',20,'全唐诗/poet.song.233000.json','["妾身邀隠，君志盡忠。", "願學仲連，甘蹈海東。"]'),
('8543090b-f94a-4f4d-9674-ac87eb536ba2','殉節詩  其四','方氏','宋','宋诗','song-poetry','','[]','舉世鬚眉，何殊巾幗。',20,'全唐诗/poet.song.233000.json','["舉世鬚眉，何殊巾幗。", "偏我婦人，尚知報國。"]'),
('d3a1bbb0-ea87-48e7-a6ad-89d674315df9','殉節詩  其五','方氏','宋','宋诗','song-poetry','','[]','有女貞潔，有男才良。',20,'全唐诗/poet.song.233000.json','["有女貞潔，有男才良。", "素解大義，不負綱常。"]'),
('f674082c-73cf-43cf-92e5-803d3fe09a3f','南國有佳人','鄧林','宋','宋诗','song-poetry','','[]','南國有佳人，仙姿自蓬島。',84,'全唐诗/poet.song.233000.json','["南國有佳人，仙姿自蓬島。", "龍綃照明璫，鳳釵橫貴寶。", "新妝試鸞鏡，皎皎顔色好。", "芳年倏已笄，君子可偕老。", "奈何行媒弱，修言棄中道。", "洞房闇怊悵，琦璜結組縞。", "寧作鍾離春，勿學姑瑶草。"]'),
('10079cf7-0b0e-4688-bc66-acf906e53b47','效晉樂志拂舞歌淮南王二篇  其一','鄧林','宋','宋诗','song-poetry','','[]','東昏侯，自言安，仙華玉壽浮雲端。',108,'全唐诗/poet.song.233000.json','["東昏侯，自言安，仙華玉壽浮雲端。", "繡窗錦幔飄蜚仙，丹青美女侍七賢。", "侍七賢，奏笙歌，笙歌逸響哀怨多。", "苑中花木費綺羅，我欲踰城城有圍，願作雙黄鶴，棲瑶池。", "棲瑶池，辟塵垢，至尊屠肉，潘妃酤酒。", "石頭江上龍駒走，三月春風吊楊柳。"]'),
('38662fc9-d644-4fa8-8894-6ee41c73dc12','效晉樂志拂舞歌淮南王二篇  其二','鄧林','宋','宋诗','song-poetry','','[]','唐明皇，自言榮，金輿翠輦游華清。',108,'全唐诗/poet.song.233000.json','["唐明皇，自言榮，金輿翠輦游華清。", "廣寒宮殿凝水晶，霓裳羽衣沈香亭。", "沈香亭，泛流霞，流霞瀲灧隊五家。", "誰知野鹿銜宮花。", "我欲度關關有兵，願作雙丹鳳，蜚瑶京。", "蜚瑶京，隠烟霧，錦繃酥酪，香囊塵土。", "劍閣縈紆家何許，梧桐葉葉鳴秋雨。"]'),
('50ecfbe5-d57a-434c-996a-a4f00f9138dd','劉阮','鄧林','宋','宋诗','song-poetry','','[]','鹿車小宇宙，據鞍常醉眠。',48,'全唐诗/poet.song.233000.json','["鹿車小宇宙，據鞍常醉眠。", "風塵澒洞時，杯裏全其天。", "伶達故自佳，籍放乃無用。", "試看勸進表，何似酒德頌。"]'),
('5d5e9f9b-7385-4bb4-89f9-ed71e03ccc91','東山彭澤','鄧林','宋','宋诗','song-poetry','','[]','乞靈風鶴屐折齒，壁後寘人汗如洗。',40,'全唐诗/poet.song.233000.json','["乞靈風鶴屐折齒，壁後寘人汗如洗。", "樵漁雜沓坐林間。", "蜉蝣塵埃不可攀，石頭擾擾柴桑閒。"]'),
('49839acf-5e0d-4567-a978-c3511ce91346','任彥升','鄧林','宋','宋诗','song-poetry','','[]','鈴縣四角五采旗，分明天産真英奇。',64,'全唐诗/poet.song.233000.json','["鈴縣四角五采旗，分明天産真英奇。", "阿堆文章妙一時，士林往往推元龜。", "楊梅蜜領仁且慈，桃米麥飯清堪師。", "何愁不得中書爲，半生紆意梅蟲兒。"]'),
('6cb3078f-ca4d-407d-8c87-158602792a8b','陶通明','鄧林','宋','宋诗','song-poetry','','[]','眉疏目朗姿圓通，詩書萬卷羅心胸。',80,'全唐诗/poet.song.233000.json','["眉疏目朗姿圓通，詩書萬卷羅心胸。", "華陽三茅仙洞中，鳳笙隠隠和松風。", "薪林圖讖呈梁公，朱砂曾青霜雪容。", "服之身體飄輕鴻，積金澗泉東復東。", "山中宰相那無功，昭陽竟作單于宮。"]'),
('3a7dedcf-2114-4823-b9e4-5f8151a34848','綠珠詞','鄧林','宋','宋诗','song-poetry','','[]','涼臺瀟灑臨清波，幄翠簾珠明綺羅。',128,'全唐诗/poet.song.233000.json','["涼臺瀟灑臨清波，幄翠簾珠明綺羅。", "哀絲豪竹按新歌，紅潮素臉春風和。", "主君歡娛美人醉，報有無情使車至。", "幾叢蘭麝俱委塵，獨指綠珠可當意。", "衆中偏是承恩深，妾身雖賤無二心。", "君前判命效一死，玉笛收聲紅日沉。", "輕裾飄向闌干角，花鈿散地金釵落。", "到頭不負齊奴約，猶勝識字空投閣。"]'),
('97ecba5b-aa22-426b-9397-7070eb0b3c69','玉兒','鄧林','宋','宋诗','song-poetry','','[]','金蓮華上俞尼子，永壽神仙羅繡綺。',80,'全唐诗/poet.song.233000.json','["金蓮華上俞尼子，永壽神仙羅繡綺。", "苑中荆荻市令嚴，玉像支離瓦官寺。", "六宮鴨㔅起淫風，太白便應縣妲己。", "此身肯許兜鍪夫，猛爲東昏判一死。", "到今羞殺賣降人，去作練兒梁姓臣。"]'),
('2a63f297-11b6-4342-acf0-552cb085c7c2','甕繭吟','鄧林','宋','宋诗','song-poetry','','[]','有繭大如甕，其來自扶桑。',84,'全唐诗/poet.song.233000.json','["有繭大如甕，其來自扶桑。", "繅成白雪絲，一縷萬丈長。", "染人嫁五色，妙織雲錦章。", "奇文雜經緯，紈素無晶光。", "相纈時所愛，輕綀貴侯王。", "緇衣不可作，此物閒篚箱。", "衮職豈無闕，終當補虞裳。"]'),
('5242dfb0-fb8b-4475-a8f7-9b1de74bb2cf','結友四清','鄧林','宋','宋诗','song-poetry','','[]','飄風吹游塵，古道少人行。',108,'全唐诗/poet.song.233000.json','["飄風吹游塵，古道少人行。", "涇水化爲泥，滄江污吾纓。", "嗟余偭工巧，世外陶閒情。", "衆芳怨蕪穢，不忍葹葹盈。", "庾領姿皚皚，渭川色青青。", "三閭播秋思，九韶鏗樂聲。", "蕭然庭宇中，對之成五清。", "滔滔揚波者，劍首一吷輕。", "靈修黨見知，冰霜憺姱名。"]'),
('89b2c880-7576-42e9-a36c-4f1485949182','次韻陳鈞甫郊行','鄧林','宋','宋诗','song-poetry','','[]','黄塵敗素意，出門愜郊行。',48,'全唐诗/poet.song.233000.json','["黄塵敗素意，出門愜郊行。", "野鞠含冷焰，巖松起寒聲。", "高山唐業崇，流水晉時清。", "拾薪歸底用，石鼎待彌明。"]'),
('80054ab2-9724-4b10-8764-f94545e3b319','關山月','鄧林','宋','宋诗','song-poetry','','[]','關山夜月明，分彩照胡兵。',72,'全唐诗/poet.song.233000.json','["關山夜月明，分彩照胡兵。", "將軍擁節起，長戍受降城。", "焚烽望別壘，欲驗盈虛駃。", "塞笳將夜鵲，戰氣今如此。", "重關掩莫烟，雲陣上祁連。", "思婦高樓上，遥心萬里縣。"]'),
('609044ea-821a-4e00-b7f1-e988a7c7b5ad','題劉功父與耕堂','鄧林','宋','宋诗','song-poetry','','[]','默耕元不外靈臺，何用錢添百屋堆。',96,'全唐诗/poet.song.233000.json','["默耕元不外靈臺，何用錢添百屋堆。", "甘雨每從和氣出，祥風常自善心來。", "畛畦有礙皆除去，境界須寬更放開。", "種德欲如多黍稌，本仁先且護根荄。", "太平國裏青精飯，永熟鄉中玉液杯。", "會得遺安龐老意，力行好事厚栽培。"]'),
('54abaa3f-0321-45a7-bc9b-154235bdcde3','書懷','鄧林','宋','宋诗','song-poetry','','[]','西風吹羽扇，吾道竟淒涼。',48,'全唐诗/poet.song.233000.json','["西風吹羽扇，吾道竟淒涼。", "上坂勞騏驥，低巢窘鳳凰。", "可求非富貴，無用是文章。", "冉冉深林底，幽蘭正自香。"]'),
('579224da-ae75-4163-be23-640a4add09b4','真陽峽','鄧林','宋','宋诗','song-poetry','','[]','滿眼皆吟料，歸囊未盡空。',48,'全唐诗/poet.song.233000.json','["滿眼皆吟料，歸囊未盡空。", "江波連岸碧，野火張天紅。", "高樹留寒日，長蘆轉晚風。", "客身雖小艇，心已故山中。"]'),
('33a98d40-acbc-4842-9067-9ec39718cc5b','凌江灘','鄧林','宋','宋诗','song-poetry','','[]','灘高舟去緩，閒眺莫江濱。',48,'全唐诗/poet.song.233000.json','["灘高舟去緩，閒眺莫江濱。", "竹本沙痕舊，茅叢燒色新。", "青裙瓶汲澗，白帽斧尋薪。", "渺渺蠻烟起，秋風一旅人。"]'),
('8e12c1f6-c1db-4551-8bd4-5fc2c68225d7','近况','鄧林','宋','宋诗','song-poetry','','[]','近况只如此，深山無見聞。',48,'全唐诗/poet.song.233000.json','["近况只如此，深山無見聞。", "二中猶學道，三上漫攻文。", "芸葉春繙日，梨花曉夢雲。", "添香仍煮茗，嚴敬事天君。"]'),
('41cf7789-b2e8-41a6-9ca8-d8bbdc02edb5','早過劉功父清溪','鄧林','宋','宋诗','song-poetry','','[]','月裏山河大，風前草木凉。',48,'全唐诗/poet.song.233000.json','["月裏山河大，風前草木凉。", "征塵生杖屨，香霧濕衣裳。", "古領扳棲鶻，荒蹊蹴聚蝗。", "白雲看未遠，已轉九回腸。"]'),
('f1a08db1-e539-4302-a357-18d098424bb3','曲江歸舟','鄧林','宋','宋诗','song-poetry','','[]','只道篷低礙覓詩，眼前物色自多奇。',64,'全唐诗/poet.song.233000.json','["只道篷低礙覓詩，眼前物色自多奇。", "千山赭去如秦樣，一水清來似晉時。", "漁父豈無緣葦輩，樵人恐有負苓師。", "僮奴忽報梅花動，春在江頭最北枝。"]'),
('6dc6f13f-92f1-408d-b8d1-866491bf5822','村居','鄧林','宋','宋诗','song-poetry','','[]','古來村裏起功名，當日南陽亦是耕。',64,'全唐诗/poet.song.233000.json','["古來村裏起功名，當日南陽亦是耕。", "幾筆遠山仁者靜，半篙流水聖之清。", "晚風蟬響勝金奏，夜露螢光即火城。", "人得一間高一著，不須史論又詩評。"]'),
('a86c8ffe-4607-4406-a9b3-b69e31468003','感興','鄧林','宋','宋诗','song-poetry','','[]','竹帛功名九折車，棲遲巖野竟何如。',64,'全唐诗/poet.song.233000.json','["竹帛功名九折車，棲遲巖野竟何如。", "浣花溪上尋佳句，積穀山頭讀異書。", "江左風流空醖藉，淮南烟景尚凋疏。", "太平十二河汾策，幾欲排雲謁帝居。"]'),
('284f1344-40cf-4dc8-99a7-b089c8604b18','蛟峰先塋','鄧林','宋','宋诗','song-poetry','','[]','獰蛟蟠伏鬣封孤，雲黯幽亭日向晡。',64,'全唐诗/poet.song.233000.json','["獰蛟蟠伏鬣封孤，雲黯幽亭日向晡。", "雙柱千年翔化鶴，四山半夜泣於菟。", "老天忍挫真英物，厚地甘埋大丈夫。", "無計發潜空涕落，雨松霜柏照烟蕪。"]'),
('281fc4ef-3c4b-4e99-b2c6-f9a1bd079472','賦江郊漁弋','鄧林','宋','宋诗','song-poetry','','[]','占斷江山自一家，寄情漁弋當生涯。',64,'全唐诗/poet.song.233000.json','["占斷江山自一家，寄情漁弋當生涯。", "青楓翠竹春屏葉，白藕紅菱曉鏡花。", "鴻鵠鵾鵬鵰鶚鶻，鱒魴鰷鯉鰋鱨鯊。", "河陽書到君當起，弩發千鈞釣五車。"]'),
('22e0dc65-758f-4306-bee7-b4d91e53a3f7','豫章','鄧林','宋','宋诗','song-poetry','','[]','郡名猶是漢流傳，宇宙江山復幾年。',64,'全唐诗/poet.song.233000.json','["郡名猶是漢流傳，宇宙江山復幾年。", "畫閣倚空家十萬，紅妝鬭夜妓三千。", "層城歌舞秋風外，故國興亡夕照邊。", "近歲潯陽成重鎮，鎮南烏幕鎖蒼烟。"]'),
('b9e1a55f-24ee-4722-8fe5-5f2e2ca97778','贛上思親','鄧林','宋','宋诗','song-poetry','','[]','庭下青萱意自舒，起居近日復何如。',64,'全唐诗/poet.song.233000.json','["庭下青萱意自舒，起居近日復何如。", "熏香莫遣衣篝潤，餌藥從知酒琖疏。", "教婦丁寧唯禮法，要孫久遠是詩書。", "手中綫在常珍重，空寫平安託鯉魚。"]'),
('1c537b60-40b2-4a7b-b347-ea84c4b5d21c','章貢祥符吳道士懶窩','鄧林','宋','宋诗','song-poetry','','[]','早年收得自由身，坐斷窩中懶是真。',64,'全唐诗/poet.song.233000.json','["早年收得自由身，坐斷窩中懶是真。", "日短日長唯守靜，雲來雲去不生嗔。", "破除機械鷗盟熟，脫略錙銖鶴料貧。", "舊看黄庭猶忘却，應無心力對閒人。"]'),
('baaf8dc5-6265-4f3b-84cd-53b4e5cea0ec','江湖偉觀','鄧林','宋','宋诗','song-poetry','','[]','世間無盡是天游，更出吳山最上頭。',64,'全唐诗/poet.song.233000.json','["世間無盡是天游，更出吳山最上頭。", "江面春聲潮卷雪，湖心寒影月澄秋。", "海門舟楫雲開見，瀛嶼亭臺水載浮。", "不比錢塘歌舞處，遠懷西北有神州。"]'),
('9a29262f-dc19-4760-b9e0-5fdd29cc37f5','送徐榷院奉戶檄之九江等郡','鄧林','宋','宋诗','song-poetry','','[]','中邊瑩徹似冰壺，空盡時情意氣殊。',64,'全唐诗/poet.song.233000.json','["中邊瑩徹似冰壺，空盡時情意氣殊。", "已向銅龍梯要路，又隨玉馱駕征涂。", "風生湓浦江流急，雲滿康廬夜月孤。", "竭到東南無力了，一分寬處是規模。"]'),
('1edd8c19-16d3-4146-be1a-1ed993c47ea7','蘭','鄧林','宋','宋诗','song-poetry','','[]','野客過門叫賣蘭，清風便自逼人寒。',32,'全唐诗/poet.song.233000.json','["野客過門叫賣蘭，清風便自逼人寒。", "孤根未必靈均種，推作離騷輩行看。"]'),
('71595296-b516-4aff-b635-d4ce4988a8ff','聞雞','鄧林','宋','宋诗','song-poetry','','[]','不因風雨不分明，羞殺譙樓打亂更。',32,'全唐诗/poet.song.233000.json','["不因風雨不分明，羞殺譙樓打亂更。", "世上公侯多改節，無人肯聽丑前鳴。"]'),
('74e3a7c7-945a-4c9f-bef1-45586517030d','晉武帝','鄧林','宋','宋诗','song-poetry','','[]','秋風銅爵曲池平，吳主宮娃滿掖庭。',32,'全唐诗/poet.song.233000.json','["秋風銅爵曲池平，吳主宮娃滿掖庭。", "憑仗皇孫聰慧早，不知禍在夕陽亭。"]'),
('d5d6f498-4916-4e2e-977e-9632f8486321','左太沖','鄧林','宋','宋诗','song-poetry','','[]','辛勤十稔賦三都，聞者曾貽酒甕書。',32,'全唐诗/poet.song.233000.json','["辛勤十稔賦三都，聞者曾貽酒甕書。", "它日洛中添紙價，陸家兄弟竟何如。"]'),
('4f51381f-186b-4882-b1d9-876182e49ed9','朱彥和','鄧林','宋','宋诗','song-poetry','','[]','文如玉海動時流，曾以書棋伏隠侯。',32,'全唐诗/poet.song.233000.json','["文如玉海動時流，曾以書棋伏隠侯。", "武德閣前消幾語，却令梁氏缺金甌。"]'),
('d83228f5-ea63-41aa-9a2d-78943fdbc331','任蠻奴','鄧林','宋','宋诗','song-poetry','','[]','千里旌旗已渡江，蠻奴苦諫喚蕭郎。',32,'全唐诗/poet.song.233000.json','["千里旌旗已渡江，蠻奴苦諫喚蕭郎。", "却持官裏黄金去，望拜韓擒石子岡。"]'),
('c119eb85-4dcd-4bd3-ba19-6b2fcd0eb41d','敬微','鄧林','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','受用廬山水石奇，亭亭霞外薜蘿衣。',32,'全唐诗/poet.song.233000.json','["受用廬山水石奇，亭亭霞外薜蘿衣。", "侍中那抵蘇門障，笑死丹青陸探微。"]'),
('0234e651-dfd6-4fb4-9487-78d88d0bc04b','鄧郁','鄧林','宋','宋诗','song-poetry','','[]','雲母餱糧五嶽樓，繡袿少嫗導仙遊。',32,'全唐诗/poet.song.233000.json','["雲母餱糧五嶽樓，繡袿少嫗導仙遊。", "不應輕信雙青鳥，便遣東都事業休。"]'),
('f5cdf0c1-209a-4c60-af1e-44e9327ba4dd','石崇','鄧林','宋','宋诗','song-poetry','','[]','梓澤神仙第一居，爭豪不惜碎珊瑚。',32,'全唐诗/poet.song.233000.json','["梓澤神仙第一居，爭豪不惜碎珊瑚。", "荆州使客知何罪，未必亡身爲綠珠。"]'),
('8a48ebbd-38b6-4688-a552-1c0e67ff474e','張茂先','鄧林','宋','宋诗','song-poetry','','[]','辨精龍肉亦奇才，雄匣干將耿不回。',32,'全唐诗/poet.song.233000.json','["辨精龍肉亦奇才，雄匣干將耿不回。", "只守鷦冥蚊睫賦，天星未必拆中台。"]'),
('63be6d20-7e75-4e53-8658-766cce0b8e23','王夷甫','鄧林','宋','宋诗','song-poetry','','[]','玉麈消摇吐妙言，清流都指作龍門。',32,'全唐诗/poet.song.233000.json','["玉麈消摇吐妙言，清流都指作龍門。", "白頭苟活尊胡虜，夜半排牆未是冤。"]'),
('2240ce04-c88f-40cb-9eb4-a09333e68648','張曲江祠','鄧林','宋','宋诗','song-poetry','','[]','延英幾度獻忠言，白羽它時賦感恩。',32,'全唐诗/poet.song.233000.json','["延英幾度獻忠言，白羽它時賦感恩。", "自是三郎真贋錯，却將天寶換開元。"]'),
('a65d17ae-ed37-4144-9042-64460d78dc1f','貪泉','鄧林','宋','宋诗','song-poetry','','[]','千古遺蹤散曉烟，空餘兩字寺門前。',32,'全唐诗/poet.song.233000.json','["千古遺蹤散曉烟，空餘兩字寺門前。", "世間貪者滔滔是，何必俱曾飲此泉。"]'),
('46fd662a-e3ff-40ab-af19-f083c2d54350','送衡山琴畫張道士二首  其一','鄧林','宋','宋诗','song-poetry','','["\u8861\u5c71"]','滿天風月澹消騷，三尺枯桐古調高。',32,'全唐诗/poet.song.233000.json','["滿天風月澹消騷，三尺枯桐古調高。", "不敢問君聽別操，請彈二十五離騷。"]'),
('d9fd196c-2f26-4f15-9014-dbc19b21a505','送衡山琴畫張道士二首  其二','鄧林','宋','宋诗','song-poetry','','["\u8861\u5c71"]','滿空烟雨澹糢糊，三尺霜縑老墨枯。',32,'全唐诗/poet.song.233000.json','["滿空烟雨澹糢糊，三尺霜縑老墨枯。", "不敢問君求別景，請描七十二峰圖。"]'),
('74dc6e66-43e2-423b-bc49-f2de21713ba9','桂村','鄧林','宋','宋诗','song-poetry','','[]','剪剪霜風起晚吹，一溪流水浸寒暉。',32,'全唐诗/poet.song.233000.json','["剪剪霜風起晚吹，一溪流水浸寒暉。", "客衫猶恨吳綿薄，不道邊人盡鐵衣。"]'),
('06cb0a92-b459-4219-ab74-59e6159268b5','利州進馬','鄧林','宋','宋诗','song-poetry','','[]','靈關玉壘自崔嵬，誰向西邊起禍胎。',32,'全唐诗/poet.song.233000.json','["靈關玉壘自崔嵬，誰向西邊起禍胎。", "萬里望堯通一祝，天基御馬利州來。"]'),
('fc8eb9c4-f23e-42d6-a458-a5910ddf983b','過綠野','鄧林','宋','宋诗','song-poetry','','[]','世上今無隠退風，地名偶與午橋同。',32,'全唐诗/poet.song.233000.json','["世上今無隠退風，地名偶與午橋同。", "往來怕看銅駝陌，閒倚柴門憶晉公。"]'),
('cae60d20-70b1-4b5f-870f-f47835972133','西湖','鄧林','宋','宋诗','song-poetry','','["\u897f\u6e56"]','高價租船作勝游，窮逋那敢鬭風流。',32,'全唐诗/poet.song.233000.json','["高價租船作勝游，窮逋那敢鬭風流。", "西湖多少閒春水，不洗中原二百州。"]'),
('85e84528-06f0-44c5-bf70-3c947acd747b','望和靖墓','鄧林','宋','宋诗','song-poetry','','[]','孤山擎出水中央，留下梅花代代香。',32,'全唐诗/poet.song.233000.json','["孤山擎出水中央，留下梅花代代香。", "滿酌湖波遥一酹，問咸平事已荒涼。"]'),
('2293acb3-e29c-4479-83c5-379c2ae99955','九里松','鄧林','宋','宋诗','song-poetry','','[]','松是山靈一手栽，堯天長就棟梁材。',32,'全唐诗/poet.song.233000.json','["松是山靈一手栽，堯天長就棟梁材。", "龍髯怒起春風急，似怪遊人喝道來。"]'),
('39c02725-e614-421c-8738-45e2edd66302','客孟氏塾戲降紫姑','鄧林','宋','宋诗','song-poetry','','[]','隔溪雲薄雨飄蕭，欲采荷花不見橋。',32,'全唐诗/poet.song.233000.json','["隔溪雲薄雨飄蕭，欲采荷花不見橋。", "釵卜無憑芳信杳，酸風空度鳳臺簫。"]'),
('82f424e4-30e3-4f94-8d7a-bebc9c8f74a6','白鶴觀','鄧林','宋','宋诗','song-poetry','','[]','荒徑行如錯，蟠松看轉奇。',48,'全唐诗/poet.song.233000.json','["荒徑行如錯，蟠松看轉奇。", "鳥聲人靜處，山色雨晴時。", "賒得溪翁酒，閒尋道士碁。", "箇中有佳趣，莫怪下山遲。"]'),
('54b83674-6029-418d-a4a4-5bb3f425d007','廬山棲賢寺','鄧林','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','名重於諸剎，前賢舊隠蹤。',48,'全唐诗/poet.song.233000.json','["名重於諸剎，前賢舊隠蹤。", "無人知有路，隔樹忽聞鐘。", "瀑壯山疑裂，雲深樹若封。", "或傳遺稿在，三叩昔時松。"]'),
('c37bf502-5282-4b07-b31a-459cd98263a6','湓江','鄧林','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','遠樹一重重，烟村與市通。',48,'全唐诗/poet.song.233000.json','["遠樹一重重，烟村與市通。", "難尋元亮宅，遥酹菊花叢。", "蜀浪番牆外，廬山几席中。", "何時邊事息，來此作漁翁。"]'),
('73e36e52-64ce-4e79-be1d-2335300ed2c4','登快閣黄明府强使和山谷先生韻','鄧林','宋','宋诗','song-poetry','','[]','未登快閣心先快，紅日半檐秋雨晴。',64,'全唐诗/poet.song.233000.json','["未登快閣心先快，紅日半檐秋雨晴。", "宇宙無邊萬山立，雲烟不動八窗明。", "飛來一鶴天相近，過盡千帆江自橫。", "借問金華老仙伯，幾人無忝入詩盟。"]'),
('e663db8f-b532-4570-a3c6-1b62a270f9fd','贛州上清道院呈姚雪蓬','鄧林','宋','宋诗','song-poetry','','[]','短牆不礙遠山青，無事燒香讀道經。',32,'全唐诗/poet.song.233000.json','["短牆不礙遠山青，無事燒香讀道經。", "時把一杯非好飲，客懷宜醉不宜醒。"]'),
('26743821-1782-4ecd-91fa-2826aada32f3','綠陰亭  其一','鄧林','宋','宋诗','song-poetry','','[]','慘慘秋風吹客襟，唐人遺跡宋人吟。',32,'全唐诗/poet.song.233000.json','["慘慘秋風吹客襟，唐人遺跡宋人吟。", "浮雲世事多遭變，不獨此亭無綠陰。"]'),
('199449f8-e6c8-462f-8732-6cf244114075','綠陰亭  其二','鄧林','宋','宋诗','song-poetry','','[]','千山橫碧一溪清，白鳥飛邊落照明。',32,'全唐诗/poet.song.233000.json','["千山橫碧一溪清，白鳥飛邊落照明。", "吏散庭階無一事，綠陰亭上又詩成。"]'),
('c07b5c72-2d58-42c5-9223-c4f5d4348c00','遊北高峰','鄧林','宋','宋诗','song-poetry','','[]','捫蘿百折上嶙峋，世界仙凡到此分。',64,'全唐诗/poet.song.233000.json','["捫蘿百折上嶙峋，世界仙凡到此分。", "小朵岳蓮來異域，孤撐天拄入層雲。", "江湖待看杯中瀉，鐘磬回從地底聞。", "借問須彌在何處，老僧留客且論文。"]'),
('4021552d-60df-4a00-99c4-67da321c5d1a','孤山訪鄭渭濱不值','鄧林','宋','宋诗','song-poetry','','[]','寂寞石琴臺，香雲撥不開。',48,'全唐诗/poet.song.233000.json','["寂寞石琴臺，香雲撥不開。", "多知騎鶴去，自欲買舟來。", "葑岸春回草，山亭雨謝梅。", "懷人成悵惘，日暮惜空回。"]'),
('b8f309ac-0436-4c3b-970c-e5796891bf06','句','鄧林','宋','宋诗','song-poetry','','[]','鴻雁無蹤存往事，龍蛇有窟似生成。',16,'全唐诗/poet.song.233000.json','["鴻雁無蹤存往事，龍蛇有窟似生成。"]'),
('805cd0b3-237d-468b-a71b-89456efc1f39','湖山十景 蘇隄春曉','王洧','宋','宋诗','song-poetry','','[]','孤山落月趁疎鐘，畫舫參差柳岸風。',32,'全唐诗/poet.song.233000.json','["孤山落月趁疎鐘，畫舫參差柳岸風。", "鶑夢初醒人未起，金鴉飛上五雲東。"]'),
('056ef96c-8e7d-4c98-8d7d-df8755949f6d','湖山十景 段橋殘雪','王洧','宋','宋诗','song-poetry','','[]','望湖亭外半青山，跨水修梁影亦寒。',32,'全唐诗/poet.song.233000.json','["望湖亭外半青山，跨水修梁影亦寒。", "待伴痕邊分草色，鶴驚碎玉啄闌干。"]'),
('19ff660a-c387-44b4-9876-ea3296f4b74b','湖山十景 雷峰夕照','王洧','宋','宋诗','song-poetry','','[]','塔影初收日色昏，隔牆人語近甘園。',32,'全唐诗/poet.song.233000.json','["塔影初收日色昏，隔牆人語近甘園。", "南山遊徧分歸路，半入錢唐半暗門。"]'),
('66ebc3a0-e19f-4914-a6c3-7a4c36f31426','湖山十景 麴院風荷','王洧','宋','宋诗','song-poetry','','[]','避暑人歸自冷泉，步頭雲錦晚凉天。',32,'全唐诗/poet.song.233000.json','["避暑人歸自冷泉，步頭雲錦晚凉天。", "愛渠香陣隨人遠，行過高橋旋買船。"]'),
('6fc1056b-fad5-4a4f-ba27-52e2af9c0232','湖山十景 平湖秋月','王洧','宋','宋诗','song-poetry','','[]','萬頃寒光一席鋪，冰輪行處片雲無。',32,'全唐诗/poet.song.233000.json','["萬頃寒光一席鋪，冰輪行處片雲無。", "鷲峰遥度西風冷，桂子紛紛點玉壺。"]'),
('3b10ad87-e5a0-4fe1-9fc5-9be014e136c5','湖山十景 柳浪聞鶑','王洧','宋','宋诗','song-poetry','','[]','如簧巧囀最高枝，苑樹青歸萬縷絲。',32,'全唐诗/poet.song.233000.json','["如簧巧囀最高枝，苑樹青歸萬縷絲。", "玉輦不來春又老，聲聲訴與落花知。"]'),
('70bba1f2-27cb-4007-8e08-59f72c0f8f87','湖山十景 花港觀魚','王洧','宋','宋诗','song-poetry','','[]','斷汊惟餘舊姓存，倚闌投餌說當年。',32,'全唐诗/poet.song.233000.json','["斷汊惟餘舊姓存，倚闌投餌說當年。", "沙鷗曾見園興廢，近日遊人又玉泉。"]'),
('2cb8c639-354d-4347-a059-e9427cf55212','湖山十景 南屏晚鐘','王洧','宋','宋诗','song-poetry','','[]','涑水崖碑半綠苔，春遊誰向此山來。',32,'全唐诗/poet.song.233000.json','["涑水崖碑半綠苔，春遊誰向此山來。", "晚烟深處蒲牢響，僧自城中應供回。"]'),
('fc20f924-5726-4bdd-a911-a59c9eff4c1c','湖山十景 三潭印月','王洧','宋','宋诗','song-poetry','','[]','塔邊分占宿湖船，寶鑑開匳水接天。',32,'全唐诗/poet.song.233000.json','["塔邊分占宿湖船，寶鑑開匳水接天。", "橫玉叫雲何處起，波心驚覺老龍眠。"]'),
('9e7d8cf2-3315-4c78-8628-9a8c731a247f','湖山十景 兩峰插雲','王洧','宋','宋诗','song-poetry','','[]','浮圖對立曉崔嵬，積翠浮空霽靄迷。',32,'全唐诗/poet.song.233000.json','["浮圖對立曉崔嵬，積翠浮空霽靄迷。", "試向鳳凰山上望，南高天近北烟低。"]'),
('e00a47d3-a12d-42db-87e9-5f7ee062102b','寶祐丙辰余奉漕檄經從得識九鎖山面目咸淳乙丑歲除前五日以帥檄遵奉朝旨四縣疏决回塗重游時積雪初霽瓊瑶境界恍非人世得七言一章錄呈菊巖龔先生','王洧','宋','宋诗','song-poetry','','[]','九鎖山寒玉作圍，紅塵世事可曾知。',64,'全唐诗/poet.song.233000.json','["九鎖山寒玉作圍，紅塵世事可曾知。", "峰迴似覺前無路，身到因思舊有詩。", "雲掩巖扉龍蟄冷，月明華表鶴歸遲。", "梅花笑我真迂闊，踏雪重游臘盡時。"]'),
('65a17ddd-8e5e-4a33-af5e-d1bae5183ec0','清溪周高士芝房','王洧','宋','宋诗','song-poetry','','[]','清溪賢好客，天付此芝房。',48,'全唐诗/poet.song.233000.json','["清溪賢好客，天付此芝房。", "花竹四時景，軒窗幾處堂。", "雲閒侵袂溼，泉冷带丹香。", "曲水亭尤好，何時共禊觴。"]'),
('c680f4f0-e049-45b0-8d3a-6d685dae1d89','鬰羅簫臺','王洧','宋','宋诗','song-poetry','','[]','洞霄儘有遊人到，罕有衝寒冒雪來。',32,'全唐诗/poet.song.233000.json','["洞霄儘有遊人到，罕有衝寒冒雪來。", "清曉步虛鐘磬響，玉山扶出鬰羅臺。"]'),
('59d64a29-fa1c-4c46-94d3-d187ace1d47f','鳴峰巖','黄巖孫','宋','宋诗','song-poetry','','[]','卓道當年愛此峰，直於頂上駐禪筇。',64,'全唐诗/poet.song.233000.json','["卓道當年愛此峰，直於頂上駐禪筇。", "巖深疑有仙人宅，地僻全無俗客蹤。", "罅石引泉圍古屋，斷烟拖露滴寒松。", "夜來冷枕蒲團睡，夢破一聲殘月鐘。"]'),
('7f9e02a8-12ac-43fb-8fc5-2fa2f862bdfa','贈同年樓世仁','史常之','宋','宋诗','song-poetry','','[]','烱烱長庚映五霞，寒風不勁舞衣斜。',64,'全唐诗/poet.song.233000.json','["烱烱長庚映五霞，寒風不勁舞衣斜。", "紫袍早換登瀛客，黄鶴還歸晝錦家。", "謾說文章能射斗，更饒韜略擬乘槎。", "論交似我難爲贈，慚愧囊無句漏砂。"]'),
('a287fd57-53b2-4fd8-ad67-24b350ce023d','遊山','史常之','宋','宋诗','song-poetry','','[]','遊山有約爽秋時，寂靜僧房花壓枝。',32,'全唐诗/poet.song.233000.json','["遊山有約爽秋時，寂靜僧房花壓枝。", "最是停杯愁不語，滿林啼鳥似催詩。"]'),
('b5346246-3472-45b4-b410-e5826c982a52','題鹿田西寺壁','吳琳','宋','宋诗','song-poetry','','[]','爲從吏隠招提宿，相望城中隔幾塵。',64,'全唐诗/poet.song.233000.json','["爲從吏隠招提宿，相望城中隔幾塵。", "雲暗雨來疑是晚，山深寒在不知春。", "鋤松得石添幽徑，接竹通泉隔近鄰。", "此去又尋三洞約，初平應怪我來頻。"]'),
('6eb22e89-2c81-48c4-befd-eaefde8ff2d2','農家','吳琳','宋','宋诗','song-poetry','','[]','野火相連打麥田，仰看斗轉月低弦。',32,'全唐诗/poet.song.233000.json','["野火相連打麥田，仰看斗轉月低弦。", "古來但說農家樂，夜半誰知未得眠。"]'),
('f70b0c91-96b7-4c5c-b520-c23d58d2925b','牡丹亭','鄭士洪','宋','宋诗','song-poetry','','[]','綠楊深處兩三家，幾度凭闌看紫霞。',32,'全唐诗/poet.song.233000.json','["綠楊深處兩三家，幾度凭闌看紫霞。", "雲錦已空煙水闊，轉教人憶舊時花。"]'),
('c2a8ac86-d4d8-49bd-95d8-65170e82c99b','早春山行','鄭蓴','宋','宋诗','song-poetry','','[]','山舍雨餘好，溪深萬竹齊。',48,'全唐诗/poet.song.233000.json','["山舍雨餘好，溪深萬竹齊。", "客同春日出，鳥向谷風啼。", "澹泊雲無着，崎嶇路欲迷。", "由來能力疾，歸踏夕陽低。"]'),
('bc8719d9-2f25-4508-8d25-03f142306ef3','登粵秀山','李春叟','宋','宋诗','song-poetry','','[]','宇宙皇圖遠，山川霸氣收。',48,'全唐诗/poet.song.233000.json','["宇宙皇圖遠，山川霸氣收。", "唯餘漢時月，猶照越臺秋。", "天迥明城樹，雲空斂海樓。", "清光對尊酒，莫作古今愁。"]'),
('63c0e881-45b8-4a7c-b9fc-7664d1878016','文丞相兵挫循州詩以迓之','李春叟','宋','宋诗','song-poetry','','[]','手持兵甲挽天河，鐵石心肝尚枕戈。',64,'全唐诗/poet.song.233000.json','["手持兵甲挽天河，鐵石心肝尚枕戈。", "賓客三千毛遂少，將軍百萬李陵多。", "風波如此子焉往，天道不然人奈何。", "嶺海書生今已老，天涯無石爲君磨。"]'),
('70882bac-0ca2-43be-b156-40f236dd6c74','送熊飛將軍赴文丞相麾下','李春叟','宋','宋诗','song-poetry','','[]','龍泉出匣鬼神驚，獵獵霜風送客程。',64,'全唐诗/poet.song.233000.json','["龍泉出匣鬼神驚，獵獵霜風送客程。", "白髮垂堂千里別，丹心報國一身輕。", "劃開雲路衝牛斗，挽落天河洗甲兵。", "馬革裹屍真壯士，陽關莫作斷腸聲。"]'),
('9d64bf6a-e90b-4386-ac9a-dc11e8cbec43','釣鼇臺','李春叟','宋','宋诗','song-poetry','','[]','誰把漁竿老渭濱，撥開塵鞅對清薰。',64,'全唐诗/poet.song.233000.json','["誰把漁竿老渭濱，撥開塵鞅對清薰。", "乾坤浩蕩臺非舊，湖海淒涼我接君。", "有客携家來上塚，無人載酒共論文。", "山陰興盡空歸去，何處天風落五雲。"]'),
('fea7b567-2fd0-4998-9e30-e1b82fec3d81','輓趙秋曉  其一','李春叟','宋','宋诗','song-poetry','','[]','秀出天潢一派來，廣寒早折桂枝回。',32,'全唐诗/poet.song.233000.json','["秀出天潢一派來，廣寒早折桂枝回。", "生前笑破春風面，盡把浮名付酒杯。"]'),
('5820e2c8-e9f1-42e9-b880-b59ea5b3da38','輓趙秋曉  其二','李春叟','宋','宋诗','song-poetry','','[]','驀地剛風折羽翰，懶將勳業鏡中看。',32,'全唐诗/poet.song.233000.json','["驀地剛風折羽翰，懶將勳業鏡中看。", "時危羞佩黄金印，乍可無氈作冷官。"]'),
('6019b681-bd04-44c5-bf12-8f8125dcc5e1','輓趙秋曉  其三','李春叟','宋','宋诗','song-poetry','','[]','百尺樓中眼孔高，氣吞餘子等兒曹。',32,'全唐诗/poet.song.233000.json','["百尺樓中眼孔高，氣吞餘子等兒曹。", "才名赫赫天公妬，罰作人間詩酒豪。"]'),
('660f1685-83d1-41ce-9b79-8820142cb9f4','輓趙秋曉  其四','李春叟','宋','宋诗','song-poetry','','[]','篋中遺藁墨猶新，門外池塘草自春。',32,'全唐诗/poet.song.233000.json','["篋中遺藁墨猶新，門外池塘草自春。", "鄰笛一聲腸欲斷，騷壇失却倚樓人。"]'),
('bd06fb57-2430-48ab-adca-1e301b1cf0b8','輓趙秋曉  其五','李春叟','宋','宋诗','song-poetry','','[]','世上紛紛白首翁，老天何獨死英雄。',32,'全唐诗/poet.song.233000.json','["世上紛紛白首翁，老天何獨死英雄。", "想應仙魄乘風去，猶在蓬萊第一峰。"]'),
('490fa9fa-9df3-4305-93b0-bf40f38f623b','輓趙秋曉  其六','李春叟','宋','宋诗','song-poetry','','[]','五十年間富貴中，生來玉樹飽春風。',32,'全唐诗/poet.song.233000.json','["五十年間富貴中，生來玉樹飽春風。", "買臣晚貴成何事，那得全歸似此翁。"]'),
('c162ca59-e09a-4449-bc51-7960797fbe1d','輓趙秋曉  其七','李春叟','宋','宋诗','song-poetry','','[]','森森蘭玉出庭闈，突過燕山桂五枝。',32,'全唐诗/poet.song.233000.json','["森森蘭玉出庭闈，突過燕山桂五枝。", "六逸風流誰得似，君家箇箇是麟兒。"]'),
('7e8397f2-271b-4e43-a461-f471b7794e8c','題雲溪寺','李春叟','宋','宋诗','song-poetry','','[]','杖屨前溪踏曉霜，僧茶那定攪饑腸。',32,'全唐诗/poet.song.233000.json','["杖屨前溪踏曉霜，僧茶那定攪饑腸。", "不如乘此清風去，覓取留侯辟穀方。"]'),
('f7e5e6fc-65af-4b96-89b5-edc377925b80','哭張元吉','李春叟','宋','宋诗','song-poetry','','[]','時平持論易，世否見才難。',24,'全唐诗/poet.song.233000.json','["時平持論易，世否見才難。", "孤柱支顛厦，危船上急灘。"]'),
('b13f3c84-fbe7-40bb-9c64-14da5fc91641','留題劍池石壁','方琛','宋','宋诗','song-poetry','','[]','裂破幽篁續古苔，一泓俯瞰石房開。',32,'全唐诗/poet.song.233000.json','["裂破幽篁續古苔，一泓俯瞰石房開。", "轆轤竟日知無盡，泉脈元從海上來。"]'),
('f42ecf90-784c-4ab3-91fe-ea08970e6065','游馬平仙弈洞','趙與霦','宋','宋诗','song-poetry','','[]','鑿石縱橫十九槽，千年仙跡在林皋。',32,'全唐诗/poet.song.233000.json','["鑿石縱橫十九槽，千年仙跡在林皋。", "因思有局無棋意，可是從前不著高。"]'),
('b90753f8-8d43-4645-adb6-f55fe4c4cff9','觀水','徐直方','宋','宋诗','song-poetry','','[]','滄江無盡水，夜夜隨潮去。',24,'全唐诗/poet.song.233000.json','["滄江無盡水，夜夜隨潮去。", "若復作潮來，滄江止不住。"]'),
('cafaae1f-adc2-409b-afbe-9eb2bf20c3de','題畫 春景','李用','宋','宋诗','song-poetry','','[]','春水滿四澤，浪暖魚龍化。',24,'全唐诗/poet.song.233000.json','["春水滿四澤，浪暖魚龍化。", "呼吸成風雲，霖雨遍天下。"]'),
('dea96609-b01e-4609-b7a8-64497f6154f8','題畫 夏景','李用','宋','宋诗','song-poetry','','[]','夏雲多奇峰，翠屏高列聳。',24,'全唐诗/poet.song.233000.json','["夏雲多奇峰，翠屏高列聳。", "瑞氣負鍾靈，羣低皆仰供。"]'),
('c44e46de-a91f-4b7c-a579-62e4a8e085d0','題畫 秋景','李用','宋','宋诗','song-poetry','','[]','秋月揚明輝，芙蓉開朵朵。',24,'全唐诗/poet.song.233000.json','["秋月揚明輝，芙蓉開朵朵。", "捲起水晶簾，明月清風我。"]'),
('7d708cc7-f5ad-4d04-8e40-8f88c422118b','題畫 冬景','李用','宋','宋诗','song-poetry','','[]','冬嶺秀孤松，松枝傲霜雪。',24,'全唐诗/poet.song.233000.json','["冬嶺秀孤松，松枝傲霜雪。", "不同桃李春，永抱歲寒節。"]'),
('713ed0a8-e1df-433b-866c-f5450155a306','哭祥興帝二首  其一','馬南寶','宋','宋诗','song-poetry','','[]','翔龍宮殿已蓬飄，此日傷心萬國朝。',32,'全唐诗/poet.song.233000.json','["翔龍宮殿已蓬飄，此日傷心萬國朝。", "目擊崖門天地改，寸心難與海潮消。"]'),
('cf0438e4-90a5-4d73-9b13-bafedb328998','哭祥興帝二首  其二','馬南寶','宋','宋诗','song-poetry','','[]','黄屋匡扶事已非，遺黎空自淚沾衣。',32,'全唐诗/poet.song.233000.json','["黄屋匡扶事已非，遺黎空自淚沾衣。", "衆星耿耿滄溟底，恨不同歸一少微。"]'),
('7a9b1512-b121-4e1e-9550-5ea198b31793','游元興寺','馬南寶','宋','宋诗','song-poetry','','[]','坐閲人間幾劫灰，試從清淺問蓬萊。',32,'全唐诗/poet.song.233000.json','["坐閲人間幾劫灰，試從清淺問蓬萊。", "此山此水自古有，是佛是仙何處來。"]'),
('3fcff89f-5f82-47b4-ac9c-c11b2297057b','絕命辭','王士敏','宋','宋诗','song-poetry','','[]','此生無復望生還，一死都歸談笑間。',32,'全唐诗/poet.song.233000.json','["此生無復望生還，一死都歸談笑間。", "大地皆爲肝血污，好收吾骨首陽山。"]'),
('a60290f2-49b5-4252-9476-ca0e25d806a2','三井廟','謝雨','宋','宋诗','song-poetry','','[]','曾禱神龍井，雲林杳莽間。',96,'全唐诗/poet.song.233000.json','["曾禱神龍井，雲林杳莽間。", "蘋蘩朝薦廟，風雨夜離山。", "百里田疇熟，一年囹圄閒。", "因循失報謝，石險路難攀。", "何年修廟貌，棟宇已摧殘。", "牲幣三時少，風泉四月寒。", "野僧多稌穥，古木有杉欒。", "深欲重修葺，蹉跎又解官。"]'),
('4ee3353d-a5a9-4efe-a753-7837a6be7856','題湖上','謝雨','宋','宋诗','song-poetry','','["\u897f\u6e56"]','杜鵑呼我我歸休，陸有輕車水有船。',32,'全唐诗/poet.song.233000.json','["杜鵑呼我我歸休，陸有輕車水有船。", "笑殺西湖湖上客，醉生夢死戀杭州。"]'),
('f18e9b6e-2122-4b19-a06b-a8659f9f0f51','暮春遊小園','王淇','宋','宋诗','song-poetry','','[]','一從梅粉褪殘粧，涂抹新紅上海棠。',32,'全唐诗/poet.song.233000.json','["一從梅粉褪殘粧，涂抹新紅上海棠。", "開到荼䕷花事了，絲絲天棘出莓牆。"]'),
('2652de0c-dd3e-4812-8eb6-0548d101cc94','梅','王淇','宋','宋诗','song-poetry','','[]','不受塵埃半點侵，竹籬茅舍自甘心。',32,'全唐诗/poet.song.233000.json','["不受塵埃半點侵，竹籬茅舍自甘心。", "只因誤識林和靖，惹得詩人說到今。"]'),
('768fac4d-b2af-4017-83fd-44b737e572e5','春懷','葛起耕','宋','宋诗','song-poetry','','[]','過了花朝日漸遲，相將又是禁烟時。',64,'全唐诗/poet.song.233000.json','["過了花朝日漸遲，相將又是禁烟時。", "寒留柳葉淒迷處，春在梨花寂寞枝。", "牛角橫書孤壯志，鹿門採藥誤幽期。", "自憐白髮成何事，說與啼鶑未必知。"]'),
('5028e72e-0e60-475b-92cf-c3f2d7174170','姑蘇懷古','葛起耕','宋','宋诗','song-poetry','','[]','闔閭城下水連天，故國淒涼思惘然。',64,'全唐诗/poet.song.233000.json','["闔閭城下水連天，故國淒涼思惘然。", "堤柳數行垂舞带，砌苔幾疊暈歌鈿。", "了無麋鹿遊臺下，祇有鳧鷖戲水邊。", "往事如今銷歇盡，斷霞殘照鎖寒烟。"]'),
('4eecb619-a248-45f0-80d6-851c0e7ef349','記夢','葛起耕','宋','宋诗','song-poetry','','[]','綺寮縹緲敞虛明，鵠峙鸞停護碧城。',64,'全唐诗/poet.song.233000.json','["綺寮縹緲敞虛明，鵠峙鸞停護碧城。", "珠蕊一枝春共瘦，玉環雙珮月同明。", "曾題洛賦緘新意，却拊湘絃寄遠情。", "十二闌干風細細，覺來依約記棋聲。"]'),
('b1b84bfb-c458-425c-95e2-963f07f427dd','湖天霜曉','葛起耕','宋','宋诗','song-poetry','','[]','十里平湖浸曉光，玉鸞飛舞鏡中央。',32,'全唐诗/poet.song.233000.json','["十里平湖浸曉光，玉鸞飛舞鏡中央。", "也知青女催梳掠，淡拂鉛華試靚妝。"]'),
('479c6c4c-4d9a-4847-a00a-ccd5d1435119','暮春雜興  其一','葛起耕','宋','宋诗','song-poetry','','[]','畫闌目斷楚雲西，芳草連天客思迷。',32,'全唐诗/poet.song.233000.json','["畫闌目斷楚雲西，芳草連天客思迷。", "家在江南烟雨裏，落花時節杜鵑啼。"]'),
('32566cd4-e11a-4f4f-befe-d26ea68bc0bb','暮春雜興  其二','葛起耕','宋','宋诗','song-poetry','','[]','紫椹纍纍綴碧桑，林塘雨過綠生香。',32,'全唐诗/poet.song.233000.json','["紫椹纍纍綴碧桑，林塘雨過綠生香。", "荆扉晝掩蒼苔寂，留得芸籤伴日長。"]'),
('44c3685e-7083-4dcd-9cfd-8ebdb191d25a','暮春雜興  其三','葛起耕','宋','宋诗','song-poetry','','[]','閉門花落又春深，白紵歌殘對晚斟。',32,'全唐诗/poet.song.233000.json','["閉門花落又春深，白紵歌殘對晚斟。", "惆悵年來心緒惡，一庭烟草綠沉沉。"]'),
('69f32403-4401-4470-bfa8-d7eb1f62a7e0','暮春雜興  其四','葛起耕','宋','宋诗','song-poetry','','[]','蘭杜初芳湘水春，鷓鴣啼處草如茵。',32,'全唐诗/poet.song.233000.json','["蘭杜初芳湘水春，鷓鴣啼處草如茵。", "雙魚不寄衡皋信，空有燈花入夢頻。"]'),
('0b7dc434-e060-411b-9d33-82c89ea88726','暮春雜興  其五','葛起耕','宋','宋诗','song-poetry','','[]','燕子聲中日正長，讀殘書卷亂堆牀。',32,'全唐诗/poet.song.233000.json','["燕子聲中日正長，讀殘書卷亂堆牀。", "夢回却愛西窗寂，閑看松花带夕陽。"]'),
('fd805f20-e258-43b6-a77f-66759ea1a955','雨中夢故山','葛起耕','宋','宋诗','song-poetry','','[]','冥冥細雨濕江城，掩映書窗翳復明。',64,'全唐诗/poet.song.233000.json','["冥冥細雨濕江城，掩映書窗翳復明。", "倦客一杯愁頓減，故鄉千里夢初成。", "金華洞口羊驚起，石佛山頭鹿伴行。", "何日東歸溪上路，一犁春淥带雲耕。"]'),
('508ab832-160e-41bc-886d-a502fa09ca5a','疏櫺','葛起耕','宋','宋诗','song-poetry','','[]','寒意沁疏櫺，閑階草尚青。',48,'全唐诗/poet.song.233000.json','["寒意沁疏櫺，閑階草尚青。", "市朝人自醉，泉石我常醒。", "桂寫月標格，蘭傳秋典刑。", "何妨爲老伴，相與兩忘形。"]'),
('33371641-56bd-4e23-a89d-d7bbd02c1f9b','初春感舊','葛起耕','宋','宋诗','song-poetry','','[]','又是春生杜若洲，憑欄回首總關愁。',64,'全唐诗/poet.song.233000.json','["又是春生杜若洲，憑欄回首總關愁。", "雲橫楚峽縈新夢，月泛吳波憶舊遊。", "立馬醉題花外驛，聞鶑笑倚柳邊樓。", "如今萬事經心懶，祇合長歌擬四休。"]'),
('3976c974-0473-4261-b9fa-d271499d8730','檄雪','葛起耕','宋','宋诗','song-poetry','','[]','銀闕書飛急羽忙，料應滕六奏虛皇。',64,'全唐诗/poet.song.233000.json','["銀闕書飛急羽忙，料應滕六奏虛皇。", "要將閬苑蓬壺水，幻作瓊林玉樹芳。", "風約雲邊停鶴馭，冰清月際舞霓裳。", "鳳簫莫品淒涼調，催老梅花枉斷腸。"]'),
('58e73fcf-13d6-4222-8cb0-65827b6f9966','和蘆洲劉子泉秋懷','葛起耕','宋','宋诗','song-poetry','','[]','雨送秋歸雁带霜，凝情無處寄詩狂。',64,'全唐诗/poet.song.233000.json','["雨送秋歸雁带霜，凝情無處寄詩狂。", "一庭莎草蛩吟老，萬里梅花鶴夢長。", "德誼可踰鍾鼎貴，聖賢不死簡編香。", "邇來世道添悲梗，不但摧車是太行。"]'),
('8cce411b-79b6-48b4-800e-6fb6abfff6b5','贈燕','葛起耕','宋','宋诗','song-poetry','','[]','鎮日雙棲向畫梁，有時飛去爲誰忙。',64,'全唐诗/poet.song.234000.json','["鎮日雙棲向畫梁，有時飛去爲誰忙。", "得泥趁暖添芹壘，掠水因風貼柳塘。", "語重喚回芳草夢，舞輕時罥落花香。", "五陵年少傷春恨，書繫紅絲擬寄將。"]'),
('e71ee1b1-f298-4611-bb2f-adff92ecf9fa','次子泉韻  其一','葛起耕','宋','宋诗','song-poetry','','[]','一聲鶗鴂又春休，風簸榆錢滿地流。',32,'全唐诗/poet.song.234000.json','["一聲鶗鴂又春休，風簸榆錢滿地流。", "燕子不知花落盡，等閑飛過柳邊樓。"]'),
('a8017061-529e-4642-951b-b58999e6ec09','次子泉韻  其二','葛起耕','宋','宋诗','song-poetry','','[]','月轉庭花玉一闌，寶釵不卸待郎看。',32,'全唐诗/poet.song.234000.json','["月轉庭花玉一闌，寶釵不卸待郎看。", "丁香擬結相思夢，無柰東風作社寒。"]'),
('916bcd41-56ae-4418-965d-ef7fe42c525d','東歸','葛起耕','宋','宋诗','song-poetry','','[]','游倦歸來似長卿，弊廬事事費經營。',64,'全唐诗/poet.song.234000.json','["游倦歸來似長卿，弊廬事事費經營。", "掃除塵土虛堂潔，拂拭窗櫺舊紙明。", "徑菊已荒唯草長，井花少汲覺苔生。", "寒衣未辦西風急，不奈鄰家機杼鳴。"]'),
('511e1bf4-8cf5-4ba7-8654-f84ec4ca71d4','除夕','葛起耕','宋','宋诗','song-poetry','','[]','爆竹傳聲又歲除，流年不駐隙中駒。',64,'全唐诗/poet.song.234000.json','["爆竹傳聲又歲除，流年不駐隙中駒。", "屠蘇未用斟春酒，餺飥先教促曉厨。", "彩絢戶庭更鬰壘，歡傳院落競樗蒲。", "老來樂事關心懶，吟對梅花撚斷鬚。"]'),
('b7f0eeda-a9a5-41e3-9c9e-a37a0f90ab9c','秋寓都城次趙君瑞韻','葛起耕','宋','宋诗','song-poetry','','[]','催破橙香薦蟹黄，快斟新酒潤詩腸。',64,'全唐诗/poet.song.234000.json','["催破橙香薦蟹黄，快斟新酒潤詩腸。", "雁拖暝色橫秋水，鴉带寒聲噪夕陽。", "萬事莫如花下醉，百年渾似夢中狂。", "登高休負湖山約，約買扁舟載豔妝。"]'),
('4cf5a9e5-18fd-4b89-b0ab-5b327ba366d1','次劉野泉韻','葛起耕','宋','宋诗','song-poetry','','[]','自笑生隨雁影浮，幾經楚尾與吳頭。',64,'全唐诗/poet.song.234000.json','["自笑生隨雁影浮，幾經楚尾與吳頭。", "塞樓角送關山月，湘驛砧敲嶽麓秋。", "歲月森輪如走坂，功名求劍記行舟。", "即今安得如澠酒，與汝同澆萬古愁。"]'),
('a5d7dd6d-dd98-4acc-9077-2b75b13ba967','安分','葛起耕','宋','宋诗','song-poetry','','[]','淒烟澹靄鎖林霏，又是秋光欲莫時。',64,'全唐诗/poet.song.234000.json','["淒烟澹靄鎖林霏，又是秋光欲莫時。", "蘋葉江湖風剪剪，桂花庭院雨絲絲。", "世情冷暖杯中酒，人事輸贏局上棋。", "安分得閑閑最好，不須身外强尋思。"]'),
('004b5ee0-a153-432e-9d19-c0820b52dcac','覽鏡','葛起耕','宋','宋诗','song-poetry','','[]','覽鏡羞看鬢點霜，若云勳業更堪傷。',64,'全唐诗/poet.song.234000.json','["覽鏡羞看鬢點霜，若云勳業更堪傷。", "已甘身向山中老，安得名留海內香。", "雅志擬聯高士傳，倦游慵入少年場。", "長吟酒醒憑闌處，更聽秋碪答暮螿。"]'),
('6c025d32-81ab-4fa7-8d88-b39c73aa534c','贈烏龍山圓上人','葛起耕','宋','宋诗','song-poetry','','[]','笑把儒冠換墨衣，深思富貴有危機。',64,'全唐诗/poet.song.234000.json','["笑把儒冠換墨衣，深思富貴有危機。", "參他龍象知今是，還了鴛鴦悟昨非。", "開鉢展單隨所寓，打包持錫去如飛。", "有人若問西來意，正要高談爲發揮。"]'),
('b95a89da-fd5e-4e76-b23e-0cc258a2ff08','支頤','葛起耕','宋','宋诗','song-poetry','','[]','氣數推移有盛衰，老觀此理獨支頤。',64,'全唐诗/poet.song.234000.json','["氣數推移有盛衰，老觀此理獨支頤。", "閲人雲木能千載，過眼風花只片時。", "名利場中棋變幻，是非窠裏浪傾危。", "到頭輸與山中叟，樂在耕鋤別不知。"]'),
('4c9587d3-9b0f-4821-9805-66ca2a3f0e32','淚','葛起耕','宋','宋诗','song-poetry','','[]','誰奏琵琶妬客歡，啼珠泣玉使心酸。',64,'全唐诗/poet.song.234000.json','["誰奏琵琶妬客歡，啼珠泣玉使心酸。", "感時多向英雄灑，怨別還從粉黛彈。", "每聽巴猿愁滴袂，莫燒漢蠟恐堆盤。", "陽關一曲君休唱，唱罷人間行路難。"]'),
('a6623ebc-563d-4d8a-a21c-33e4fdfab46d','小隠','葛起耕','宋','宋诗','song-poetry','','[]','小隠山林習已成，市朝聲利讓渠爭。',64,'全唐诗/poet.song.234000.json','["小隠山林習已成，市朝聲利讓渠爭。", "是非每向靜中見，悔吝多從動處生。", "且約蒼官陪竹友，共邀歡伯訪梅兄。", "歲寒心事期相守，一瞬枯榮任變更。"]'),
('90a5ba4c-9f9a-44ac-8d57-a7902cb53a20','秋夜','葛起耕','宋','宋诗','song-poetry','','[]','城笳吹下暮雲邊，螢照書帷夜未眠。',32,'全唐诗/poet.song.234000.json','["城笳吹下暮雲邊，螢照書帷夜未眠。", "遊子不堪征袖薄，西風懶誦擣衣篇。"]'),
('d06a0604-f677-4fb4-9fa1-ca9d5cd20afa','樓上','葛起耕','宋','宋诗','song-poetry','','[]','樓上何人奏玉簫，數聲和月伴春宵。',32,'全唐诗/poet.song.234000.json','["樓上何人奏玉簫，數聲和月伴春宵。", "斷腸喚起江南夢，愁絕寒梅酒半銷。"]'),
('1b96232b-98a7-41ab-8289-9df53998aa48','宮詞','葛起耕','宋','宋诗','song-poetry','','[]','銀漏疏風透玉屏，碧梧枝上雨三更。',32,'全唐诗/poet.song.234000.json','["銀漏疏風透玉屏，碧梧枝上雨三更。", "依稀似寫華清恨，雲冷香銷夢不成。"]'),
('de81bb3c-54a9-4850-9376-f4cc4e8002fe','隠居雜興  其一','楊公遠','宋','宋诗','song-poetry','','[]','碧雲深處著吾廬，遠却喧囂儘自如。',64,'全唐诗/poet.song.234000.json','["碧雲深處著吾廬，遠却喧囂儘自如。", "呵硯磨冰朝鍊句，擁爐燒葉夜觀書。", "人生窮達乘軒鶴，世事盈虛賦芧狙。", "勘破已無朝市夢，軟紅端不上衣裾。"]'),
('ed05ee12-63f5-4e80-8d3c-38ac4916e86d','隠居雜興  其二','楊公遠','宋','宋诗','song-poetry','','[]','身世悠悠付等閒，盧仝破屋恰三間。',64,'全唐诗/poet.song.234000.json','["身世悠悠付等閒，盧仝破屋恰三間。", "暫時結伴窗前月，耐久論交戶外山。", "竹鼎篆香消更爇，錦囊詩卷改還刪。", "是非榮辱俱烏有，翻笑人間兩觸蠻。"]'),
('7383338b-203d-4fa4-a976-ff7586bd724b','隠居雜興  其三','楊公遠','宋','宋诗','song-poetry','','[]','老屋荒寒亦自清，柴門雖設只長扃。',64,'全唐诗/poet.song.234000.json','["老屋荒寒亦自清，柴門雖設只長扃。", "數行古隸閒居賦，半壁行書陋室銘。", "□□□□□□□，研硃滴露勘黄庭。", "此生與世雖無補，筆底青山到了青。"]'),
('10c5505a-37d5-4e67-8696-62ec3661a1e4','隠居雜興  其四','楊公遠','宋','宋诗','song-poetry','','[]','生計新來喜有涯，蒔菘栽韮樹桑麻。',64,'全唐诗/poet.song.234000.json','["生計新來喜有涯，蒔菘栽韮樹桑麻。", "慣眠紙帳三竿日，飽聽萍池兩部蛙。", "往事真成看墮甑，凡身安敢望乘槎。", "一般受用還官樣，門外黄蜂爲報衙。"]'),
('bb1a83b7-e711-4780-b00b-e1c2676b68c3','隠居雜興  其五','楊公遠','宋','宋诗','song-poetry','','[]','髼鬆兩鬢欲成絲，又是桃紅李白時。',64,'全唐诗/poet.song.234000.json','["髼鬆兩鬢欲成絲，又是桃紅李白時。", "百歲光陰須藉酒，一生志趣莫過詩。", "世情因向貧中識，畫思方知老後宜。", "却喜半犁新雨過，旋分菊本蒔東籬。"]'),
('d51db3da-5dd7-4ca9-90e6-8998b82b0728','隠居雜興  其六','楊公遠','宋','宋诗','song-poetry','','[]','一味幽閒了此生，那曾懷刺謁公卿。',64,'全唐诗/poet.song.234000.json','["一味幽閒了此生，那曾懷刺謁公卿。", "無官可署名雖晦，有句堪吟思自清。", "棋要藏機何用著，琴能識趣底須聲。", "何當辦取青蓑笠，去趁農夫學耦耕。"]'),
('cb6c41bc-1416-4b73-9ee1-00292b42bd5f','隠居雜興  其七','楊公遠','宋','宋诗','song-poetry','','[]','蕭然天地一吟身，著向荒村野水濱。',64,'全唐诗/poet.song.234000.json','["蕭然天地一吟身，著向荒村野水濱。", "耳底松聲風奏樂，窗間竹影月傳神。", "無田種秫難謀醉，有硯遺家未是貧。", "除却推敲無別事，襟懷拍塞四時春。"]'),
('2ffdb62c-022d-4d5b-99bd-45389c01fdab','隠居雜興  其八','楊公遠','宋','宋诗','song-poetry','','[]','籬編紅槿障蓬茅，半近城闉半近郊。',64,'全唐诗/poet.song.234000.json','["籬編紅槿障蓬茅，半近城闉半近郊。", "苔繡曲蹊千萬點，梅窺碧沼兩三梢。", "閒將今古澆胸臆，嬾把榮枯問卦爻。", "一自漁樵分席後，清泉白石與論交。"]'),
('d996794b-19bd-4e85-941f-dfdec24f0f20','隠居雜興  其九','楊公遠','宋','宋诗','song-poetry','','[]','槎牙詩骨等梅臞，試啟青銅失故吾。',64,'全唐诗/poet.song.234000.json','["槎牙詩骨等梅臞，試啟青銅失故吾。", "啖蔗祇應佳境近，解袍那想故人無。", "推排景物歸吟卷，安頓江山入畫圖。", "只此可堪供活計，底須舍瑟學齊竽。"]'),
('3f433abe-c1db-4b97-8a80-ef8116c218f6','隠居雜興  其一○','楊公遠','宋','宋诗','song-poetry','','[]','詰曲通村小徑開，依山結屋任低隈。',64,'全唐诗/poet.song.234000.json','["詰曲通村小徑開，依山結屋任低隈。", "無從問字高人過，有不嫌貧長者來。", "煮茗燒殘柴带葉，脫巾漉起酒和醅。", "絕憐筆硯香猶在，集句曾賡百詠梅。"]'),
('fdee7e38-3f9c-403a-ab40-54defeb93379','中秋','楊公遠','宋','宋诗','song-poetry','','[]','秋氣平分雨乍晴，殘雲斂盡楚天清。',32,'全唐诗/poet.song.234000.json','["秋氣平分雨乍晴，殘雲斂盡楚天清。", "野人不趁□花課，贏得今宵看月明。"]'),
('77a06e6b-6c59-4960-9076-8af02308d109','雨過閒步','楊公遠','宋','宋诗','song-poetry','','[]','霏微雨過不成泥，小步何妨曳杖藜。',64,'全唐诗/poet.song.234000.json','["霏微雨過不成泥，小步何妨曳杖藜。", "半露好山雲斷續，輕籠淡日樹高低。", "池塘有夢春生草，桃李無言下自蹊。", "政此新晴猶未定，那堪又聽竹雞啼。"]'),
('d85113a9-4a2c-4827-a6a3-c20ad8f88141','鷺','楊公遠','宋','宋诗','song-poetry','','[]','飄然片雪下晴空，終日盤旋淺瀨中。',64,'全唐诗/poet.song.234000.json','["飄然片雪下晴空，終日盤旋淺瀨中。", "行近鷗鳬風致別，立依蒲蓼畫圖同。", "數莖絲髮心何慮，一世魚餐體不豐。", "歷遍江湖真漫浪，前身應想是漁翁。"]'),
('e225c7f5-26e4-484e-b181-9aa902bf6b0d','溪行','楊公遠','宋','宋诗','song-poetry','','[]','通村一徑遶清溪，緩步行來曳杖藜。',32,'全唐诗/poet.song.234000.json','["通村一徑遶清溪，緩步行來曳杖藜。", "風弄柳絲垂裊裊，紅桃映水壓枝低。"]'),
('ff791d90-6be1-4e30-8f05-732ef984e474','梅花五首  其一','楊公遠','宋','宋诗','song-poetry','','[]','草木根荄暖未回，□□□□□□□。',64,'全唐诗/poet.song.234000.json','["草木根荄暖未回，□□□□□□□。", "□□□□□□□，老幹槎牙一半摧。", "水急可曾流影去，雪深還不礙香來。", "赤松孤竹真渠友，萬紫千紅總皂臺。"]'),
('0d5c9bb2-545c-4c52-875e-adca0373df97','梅花五首  其二','楊公遠','宋','宋诗','song-poetry','','[]','高標獨立歲寒時，不受狂蜂浪蝶知。',64,'全唐诗/poet.song.234000.json','["高標獨立歲寒時，不受狂蜂浪蝶知。", "樹百千年枯更好，花三兩點少爲奇。", "暗香疎影孤山句，却月凌風水部詩。", "顧我對渠吟未穩，且將淡墨貌橫枝。"]'),
('d2994efc-2da7-4098-bf85-c8de6e40fb51','梅花五首  其三','楊公遠','宋','宋诗','song-poetry','','[]','屋簷斜入一枝低，欲爲形容頗費思。',64,'全唐诗/poet.song.234000.json','["屋簷斜入一枝低，欲爲形容頗費思。", "蕭灑花裁冰腦綴，橫斜幹倚斗杓垂。", "風浮香動更闌後，窗映枝橫月轉時。", "最是孤高難著語，只宜索笑莫言詩。"]'),
('5bcc0ad4-dfed-4621-8755-f15332bd2521','梅花五首  其四','楊公遠','宋','宋诗','song-poetry','','[]','橫隔片煙爭向靜，深藏翠幕全真性。',64,'全唐诗/poet.song.234000.json','["橫隔片煙爭向靜，深藏翠幕全真性。", "霞拖數縷日初沉，月挂一眉天未暝。", "問訊頻敲碧玉枝，覓詩踏遍蒼苔逕。", "有時小醉倚幽窗，只藉清香聞得醒。"]'),
('453f918c-0550-47f2-a219-f6755b8c55ca','梅花五首  其五','楊公遠','宋','宋诗','song-poetry','','[]','半黏殘雪不勝清，可惜梢頭欠月明。',64,'全唐诗/poet.song.234000.json','["半黏殘雪不勝清，可惜梢頭欠月明。", "影不橫斜冰未泮，香微漏洩曉初晴。", "餐氈蘇武應同調，披氅王恭想再生。", "忍凍保全清節在，爲渠從此定交盟。"]'),
('adca074f-6b23-414a-9f1e-6553b15ab5db','螢','楊公遠','宋','宋诗','song-poetry','','[]','飛螢生腐草，熠燿暗中遊。',48,'全唐诗/poet.song.234000.json','["飛螢生腐草，熠燿暗中遊。", "貼水燈相照，穿林火獨幽。", "風前疑燼落，雨裏訝星流。", "映讀除車胤，今人肯效不。"]'),
('08b6fdd4-2e73-41f9-b7a6-da6a38d32198','白杜鵑花','楊公遠','宋','宋诗','song-poetry','','[]','從來只說映山紅，幻出鉛華奪化工。',32,'全唐诗/poet.song.234000.json','["從來只說映山紅，幻出鉛華奪化工。", "莫是杜鵑飛不到，故無啼血染芳叢。"]'),
('185f273f-6290-4f8e-9a86-4287cb344615','雨後  其一','楊公遠','宋','宋诗','song-poetry','','[]','春色相將老，幽禽百樣吟。',48,'全唐诗/poet.song.234000.json','["春色相將老，幽禽百樣吟。", "一犁新雨驟，滿地落花深。", "麥秀風翻浪，秧青水透針。", "年登應可卜，稍稍慰儂心。"]'),
('87825492-c41f-4579-a7d1-5cd2919ef9d0','雨後  其二','楊公遠','宋','宋诗','song-poetry','','[]','沛然傾霔戰驕陽，颯颯風來作晚凉。',64,'全唐诗/poet.song.234000.json','["沛然傾霔戰驕陽，颯颯風來作晚凉。", "吹散浮雲澄玉宇，敲殘枯葉墮銀牀。", "韓檠擢用因書薦，班扇投閒被雨妨。", "自此吟情辜不得，一秋景物要平章。"]'),
('f304577f-9316-4a9a-abdc-1fea0f6085d7','雪','楊公遠','宋','宋诗','song-poetry','','[]','怪得雲頑凍不開，漫空忽攪豆稭灰。',64,'全唐诗/poet.song.234000.json','["怪得雲頑凍不開，漫空忽攪豆稭灰。", "青留一半窗前竹，白勝三分屋外梅。", "剡曲舟應撐月去，灞橋馿想得詩回。", "吾儂喜有煎茶興，不羨銷金帳底杯。"]'),
('a941600d-c8be-402f-97b7-b05790678ad3','白茅道中','楊公遠','宋','宋诗','song-poetry','','[]','支筇過嶺坳，對景試推敲。',48,'全唐诗/poet.song.234000.json','["支筇過嶺坳，對景試推敲。", "野水書之字，山田畫卦爻。", "雲歸峰露頂，葉落樹留梢。", "問此名何地，人言是白茅。"]'),
('50fd3dca-2a53-4456-88a3-e18c1ee93e9c','次程斗山韻','楊公遠','宋','宋诗','song-poetry','','[]','口作蛩吟肩聳山，了無縈繫一生閒。',64,'全唐诗/poet.song.234000.json','["口作蛩吟肩聳山，了無縈繫一生閒。", "夢回春草池塘外，詩在梅花煙雨間。", "但得雙眸長炯炯，從教兩鬢自斑斑。", "此身窮達何消問，天道乘除去復還。"]'),
('4e67cacb-898f-4bed-898b-92189eefd366','次吳篁嶼山行','楊公遠','宋','宋诗','song-poetry','','[]','詰曲深林小逕斜，杖藜徐步訪山家。',32,'全唐诗/poet.song.234000.json','["詰曲深林小逕斜，杖藜徐步訪山家。", "老翁□□無祗待，禁酒官嚴又禁茶。"]'),
('080a750e-1f22-42e1-a465-6a1bd6e1a944','聞鵑  其一','楊公遠','宋','宋诗','song-poetry','','[]','帝魄聲聲切，教儂聽不禁。',48,'全唐诗/poet.song.234000.json','["帝魄聲聲切，教儂聽不禁。", "都緣傷國破，豈是怨春深。", "枕上幽人思，燈前逆旅心。", "花枝疑恨血，到處映山林。"]'),
('1f304ec8-8ebd-4a95-90fb-2cd9a77d4c36','聞鵑  其二','楊公遠','宋','宋诗','song-poetry','','[]','春闌聞杜宇，歸去意難禁。',48,'全唐诗/poet.song.234000.json','["春闌聞杜宇，歸去意難禁。", "蜀道連天嶮，郫城隠霧深。", "差池當日事，懊恨此生心。", "閲世多興廢，君休憶故林。"]'),
('7ec1515e-d903-41dc-956b-61a600eb514b','次程直學秋雨感','楊公遠','宋','宋诗','song-poetry','','[]','一雨戰秋陽，風生衣袂舉。',60,'全唐诗/poet.song.234000.json','["一雨戰秋陽，風生衣袂舉。", "更不假蒲葵，秋陽眇何許。", "渾如赫赫人，其技只鼯鼠。", "須信有循環，凉生屏煩暑。", "此意默領會，何勞向人語。"]'),
('b186f37d-dba1-47f8-9ab1-fda4c4dd7054','弔訥相次仲宣韻  其一','楊公遠','宋','宋诗','song-poetry','','[]','兩字清忠帝衮褒，都緣穩把濟川篙。',32,'全唐诗/poet.song.234000.json','["兩字清忠帝衮褒，都緣穩把濟川篙。", "後來諸老多成敗，何似先生勇退高。"]'),
('5f03d7f9-6d8a-40c2-bc98-1ef50471be6c','弔訥相次仲宣韻  其二','楊公遠','宋','宋诗','song-poetry','','[]','官居鼎鼐只儒酸，雅淡襟期耐歲寒。',32,'全唐诗/poet.song.234000.json','["官居鼎鼐只儒酸，雅淡襟期耐歲寒。", "拂袖乘箕天上去，斑斑青史後人看。"]'),
('adb53628-72e1-4c51-b687-3579db7765a6','始生書懷','楊公遠','宋','宋诗','song-poetry','','[]','非賢非智半癡聾，性稟天然雅淡中。',64,'全唐诗/poet.song.234000.json','["非賢非智半癡聾，性稟天然雅淡中。", "閒閲廢興槐國夢，細思得失楚人弓。", "事無欺世心何愧，詩爲傷時句不工。", "却謝梅花開幾點，年年此日伴山翁。"]'),
('cfb58878-b162-4952-a3c8-50048acfde20','黄山','楊公遠','宋','宋诗','song-poetry','','[]','古今墨客兼騷客，推許黄山甲衆山。',320,'全唐诗/poet.song.234000.json','["古今墨客兼騷客，推許黄山甲衆山。", "三十六峰層漢外，百千萬岫亂雲間。", "鍊丹帝往名長在，搗藥仙歸臼已閒。", "葉落花開人寂寂，雄鳴雌和鳥關關。", "瀑湍巖罅常飛沫，砂現崖巔未带殷。", "水畔青牛眠正穩，源頭白鹿去仍還。", "清潭易見魚翻錦，幽洞難窺豹露斑。", "著罷棋枰留嶂頂，流來桃片點溪灣。", "鸞翔弄影非無侶，鶴唳衝天豈類鷳。", "空谷伐柯樵父遠，平川喚犢牧兒頑。", "石缾傾注泉那竭，瑶草敷榮地匪慳。", "老檜絡藤纏夭矯，蒼苔蝕徑遶迴環。", "遥知衲子明空苦，應笑貪夫競觸蠻。", "斷續小橋艱跋涉，崎嶇絕磴費躋攀。", "枝頭果熟猿爭取，樹杪梢枯鵲爲刪。", "虎踞風前疑嘯吼，龍潛潭底想盤跧。", "水簾珠貫何曾捲，石室雲封底用𣡬。", "對峙容浮高聳峭，合流曹院響湲潺。", "湯泉浴起能輕骨，藥鼎餐遺可駐顔。", "勝概不窮吟不盡，一時模寫在人寰。"]'),
('148a42fe-8068-488a-9dbb-7789ffc86ac4','宮詞','楊公遠','宋','宋诗','song-poetry','','[]','燕語鶑啼日正長，六宮桃李閙春光。',32,'全唐诗/poet.song.234000.json','["燕語鶑啼日正長，六宮桃李閙春光。", "妾身雖未承恩澤，却喜君恩澤萬方。"]'),
('abfe53bd-9af6-4ed3-9372-2e6fac3e9cd9','次敏齋陳先生月艇','楊公遠','宋','宋诗','song-poetry','','[]','小池新艤野航輕，分得江湖一段清。',32,'全唐诗/poet.song.234000.json','["小池新艤野航輕，分得江湖一段清。", "最是好天良月夜，嬋娟冷浸入窗明。"]'),
('e6659918-7887-477c-bce1-f89a13eca37d','悶書','楊公遠','宋','宋诗','song-poetry','','[]','悶來咄咄向空書，怪底年來每事疎。',64,'全唐诗/poet.song.234000.json','["悶來咄咄向空書，怪底年來每事疎。", "著脚左如旋磨蟻，進身難似上竿魚。", "不逢賢者休彈鋏，謾說侯門可曳裾。", "畢竟歸農爲上策，買將蓑笠去耕鋤。"]'),
('888a9217-5ba6-4446-b69a-6cb26d7013d8','次冰寮尤倅落葉','楊公遠','宋','宋诗','song-poetry','','[]','陡覺老秋郊，山臞出嶺坳。',48,'全唐诗/poet.song.234000.json','["陡覺老秋郊，山臞出嶺坳。", "蕭騷風脫葉，清峭樹留梢。", "漸失牛羊徑，難藏鸛鵲巢。", "爐燒供夜讀，童掃莫輕拋。"]'),
('a4a622ee-4c27-40ed-a986-e5b2abbd4b71','偶成','楊公遠','宋','宋诗','song-poetry','','[]','世路崎嶇蜀道難，長年兀兀坐柴關。',64,'全唐诗/poet.song.234000.json','["世路崎嶇蜀道難，長年兀兀坐柴關。", "詩才得句心先喜，事不縈懷夢亦閒。", "已種蒼竿環碧沼，旋營矮屋傍青山。", "倘來軒冕雖無分，贏得優游天地間。"]'),
('f7a0e3f9-1b87-4149-8672-93840440eaac','次蘭皋自詠','楊公遠','宋','宋诗','song-poetry','','[]','生來無分對書燈，却喜逢人便眼青。',64,'全唐诗/poet.song.234000.json','["生來無分對書燈，却喜逢人便眼青。", "枵腹謾臨求米帖，學耕頻勘相牛經。", "崚嶒骨相身長健，磊磈襟懷鬢未星。", "密掩柴扉盤膝坐，人非人是底須聽。"]'),
('9dd9dd4d-8eb6-4c17-906a-91bcd2b8d4a4','次宋省齋避暑','楊公遠','宋','宋诗','song-poetry','','[]','何處避炎威，好是幽人屋。',72,'全唐诗/poet.song.234000.json','["何處避炎威，好是幽人屋。", "拂拂來清風，蒼松間脩竹。", "坐久細哦詩，惜不療饑腹。", "念彼田舍翁，桔槔聲斷續。", "誰知漢陰老，抱甕灌園谷。", "顧我本無機，所願年穀熟。"]'),
('7ffab6c9-c17c-4d3c-83ad-b1fd8565564c','寓乾明觀  其一','楊公遠','宋','宋诗','song-poetry','','[]','梗跡寄琳宮，蕭然萬慮空。',48,'全唐诗/poet.song.234000.json','["梗跡寄琳宮，蕭然萬慮空。", "觀碁評勝負，拂劍認雌雄。", "香篆消還續，缾花白間紅。", "自憐閒雅趣，恰共羽流同。"]'),
('76c4db5d-a888-43fb-84a1-8f045bd33ecb','寓乾明觀  其二','楊公遠','宋','宋诗','song-poetry','','[]','無奈雨潺潺，驅除惡况難。',48,'全唐诗/poet.song.234000.json','["無奈雨潺潺，驅除惡况難。", "三杯官酒薄，一掬客心酸。", "畫卷慵拈起，書編謾展看。", "更誰堪與話，時對老黄冠。"]'),
('493a7060-1695-4aef-b01a-6060e17a03b4','寓乾明觀  其三','楊公遠','宋','宋诗','song-poetry','','[]','多謝老彌明，金芽石鼎烹。',48,'全唐诗/poet.song.234000.json','["多謝老彌明，金芽石鼎烹。", "一甌浮雪白，兩腋覺風清。", "齒頰回真味，詩聯悟道情。", "北窗高卧處，魂夢到蓬瀛。"]'),
('bea0404e-191a-4535-9e02-19e2115970b2','寓乾明觀  其四','楊公遠','宋','宋诗','song-poetry','','[]','丹室白雲深，紅塵不受侵。',48,'全唐诗/poet.song.234000.json','["丹室白雲深，紅塵不受侵。", "鳴琴驚鶴夢，彈鋏恐龍吟。", "只有清虛事，全無名利心。", "謝渠爲下榻，買酒共儂斟。"]'),
('56e92dc2-30c4-4e7b-8243-8ef69be6fc93','寓乾明觀  其五','楊公遠','宋','宋诗','song-poetry','','[]','月色上窗紗，移來竹影斜。',48,'全唐诗/poet.song.234000.json','["月色上窗紗，移來竹影斜。", "夜深人已寂，更轉鼓頻撾。", "杜宇驚幽夢，銀釭墜細花。", "一時渾不記，身在羽人家。"]'),
('7ee87ecc-3faf-4d51-815f-164baf9c8d2f','大佛頭次程斗山','楊公遠','宋','宋诗','song-poetry','','[]','丈六金身本自然，如今丈六未齊肩。',32,'全唐诗/poet.song.234000.json','["丈六金身本自然，如今丈六未齊肩。", "當時若起亭亭立，只恐纔餘尺五天。"]'),
('de556a15-b401-4dbb-8532-eb71bcee4f3b','清明日雨中聞鵑  其一','楊公遠','宋','宋诗','song-poetry','','[]','蜀魄抑何靈，年年不負盟。',48,'全唐诗/poet.song.234000.json','["蜀魄抑何靈，年年不負盟。", "才過百五日，便作兩三聲。", "渠自懷歸計，人因惱別情。", "凄凉無處著，那更雨如傾。"]'),
('2e780a66-ed2d-4309-afeb-2b9e46fe1a42','清明日雨中聞鵑  其二','楊公遠','宋','宋诗','song-poetry','','[]','家輕授鼇靈，不擬再尋盟。',48,'全唐诗/poet.song.234000.json','["家輕授鼇靈，不擬再尋盟。", "故業成荒址，中心飲恨聲。", "廢興猶反掌，今古總傷情。", "最是初聞處，令人淚欲傾。"]'),
('9e5109fb-f44c-4148-8286-1d49014cc70d','借虛谷太博狂吟十詩韻書懷併呈太博  其一','楊公遠','宋','宋诗','song-poetry','','[]','鐘鼎簞瓢信宿緣，且將閒逸度餘年。',64,'全唐诗/poet.song.234000.json','["鐘鼎簞瓢信宿緣，且將閒逸度餘年。", "詩敲雪月風花夜，畫捲江湖煙雨天。", "三尺焦桐方外友，一泓老硯郭邊田。", "自慚野趣無拘束，敢和清吟一十篇。"]'),
('86ee9275-906d-4585-92cf-d544087b32d2','借虛谷太博狂吟十詩韻書懷併呈太博  其二','楊公遠','宋','宋诗','song-poetry','','[]','竹馬纔拋又是翁，年來自覺轉疎慵。',64,'全唐诗/poet.song.234000.json','["竹馬纔拋又是翁，年來自覺轉疎慵。", "欲開竹下三三逕，還借毫端六六峰。", "處世竟無非理事，對人那有可慙容。", "浮沈聊爾從吾好，却笑南陽說卧龍。"]'),
('b9c323f7-dfba-4c65-b291-281ae50d0790','借虛谷太博狂吟十詩韻書懷併呈太博  其三','楊公遠','宋','宋诗','song-poetry','','[]','幽事知誰可共論，烟浮清曉月黄昏。',64,'全唐诗/poet.song.234000.json','["幽事知誰可共論，烟浮清曉月黄昏。", "吟梅細味逋仙句，植蕙閒招楚客魂。", "暴富小池蛙奏樂，安貧陋室席爲門。", "吾生幸自無榮辱，一任傍人笑作村。"]'),
('58311b9f-e702-4afe-8d78-c76c9b919cd3','借虛谷太博狂吟十詩韻書懷併呈太博  其四','楊公遠','宋','宋诗','song-poetry','','[]','頭顱搭颯一山翁，萬事隨宜敢諱窮。',64,'全唐诗/poet.song.234000.json','["頭顱搭颯一山翁，萬事隨宜敢諱窮。", "不結東華塵土夢，何干北海馬牛風。", "半生蹤跡從容裏，一片襟期冷淡中。", "兀坐有時參世味，古今興廢轉頭空。"]'),
('48bc86a3-0978-4f9b-8333-bc4f2b92f8e3','借虛谷太博狂吟十詩韻書懷併呈太博  其五','楊公遠','宋','宋诗','song-poetry','','[]','失笑如何了此生，須教日日醉烏程。',64,'全唐诗/poet.song.234000.json','["失笑如何了此生，須教日日醉烏程。", "是非不較人情好，窮達休論世路平。", "釣月耕雲何限樂，枕流漱石有餘清。", "近來轉覺身强健，賸喜雙瞳炯炯明。"]'),
('3724d074-2db6-4d92-a010-958f5c7e05dc','借虛谷太博狂吟十詩韻書懷併呈太博  其六','楊公遠','宋','宋诗','song-poetry','','[]','書劍謀生總不成，效渠東野以詩鳴。',64,'全唐诗/poet.song.234000.json','["書劍謀生總不成，效渠東野以詩鳴。", "未知唐宋源流異，却喜江湖句法輕。", "肩聳每同臞鶴立，口吟端似冷蛩聲。", "自憐絕少驚人句，生怕人傳浪得名。"]'),
('a4ea1cb7-9673-4f23-bd38-71e7a0aa6132','借虛谷太博狂吟十詩韻書懷併呈太博  其七','楊公遠','宋','宋诗','song-poetry','','[]','一生不把兩眉愁，厭聽瓢聲笑許由。',64,'全唐诗/poet.song.234000.json','["一生不把兩眉愁，厭聽瓢聲笑許由。", "願荷鋤來翻畎畝，懶携刺去謁公侯。", "酒傾明月清風夜，詩琢空山落木秋。", "坎止流行俱莫問，自然霜雪未蒙頭。"]'),
('984674df-af0b-4684-a772-687e28ade3ee','借虛谷太博狂吟十詩韻書懷併呈太博  其八','楊公遠','宋','宋诗','song-poetry','','[]','吾廬近野却依城，彈壓風光藉酒兵。',64,'全唐诗/poet.song.234000.json','["吾廬近野却依城，彈壓風光藉酒兵。", "山色可供圖畫趣，泉流聊當管絃聲。", "眼前無事方安逸，天下豐年即太平。", "權勢從來難倚仗，祇宜孤立度浮生。"]'),
('d24d2196-56e8-4773-b0b1-2d07e267b58b','借虛谷太博狂吟十詩韻書懷併呈太博  其九','楊公遠','宋','宋诗','song-poetry','','[]','身世悠悠歲月侵，兒時歷練到如今。',64,'全唐诗/poet.song.234000.json','["身世悠悠歲月侵，兒時歷練到如今。", "梅臞元稟冰霜操，松老猶堅鐵石心。", "世道任從渠否泰，人情豈爲我辰參。", "欲知卜隠在何處，寂寞荒村煙樹深。"]'),
('6694c0d9-12d7-4e7c-bb58-7f394dd39670','借虛谷太博狂吟十詩韻書懷併呈太博  其一○','楊公遠','宋','宋诗','song-poetry','','[]','逕曲通村深復深，聽鶑吟歇聽蟬吟。',64,'全唐诗/poet.song.234000.json','["逕曲通村深復深，聽鶑吟歇聽蟬吟。", "園林幽雅已成趣，朝市紛華豈到心。", "匣冷馮驩長鋏劍，壁懸元亮不絃琴。", "故知忤世皆緣直，有口從今只合瘖。"]'),
('5f4b7cd1-dc16-4b9a-8d6a-b97f72f49896','一溪趙宰惠詩次韻謝','楊公遠','宋','宋诗','song-poetry','','[]','古歙遭逢定宿緣，作成和氣致豐年。',64,'全唐诗/poet.song.234000.json','["古歙遭逢定宿緣，作成和氣致豐年。", "一溪浪靜一溪月，百里民安百里天。", "草茂圜扉花滿縣，雨餘村落水通田。", "正慙欠識荆州願，忽拜雕冰鏤玉篇。"]'),
('9cc07022-06aa-44a1-94d5-c3e6892ed51d','高齋韓東尉用前韻見寄次韻謝','楊公遠','宋','宋诗','song-poetry','','[]','世間名利我無緣，飽看黄花又一年。',64,'全唐诗/poet.song.234000.json','["世間名利我無緣，飽看黄花又一年。", "鬢有幾根從带雪，心無一事可欺天。", "築居易辦觀梅閣，取醉難謀種秫田。", "欲謁昌黎論此意，那知先已寄新篇。"]'),
('db6f064e-f889-43b8-8e68-982d1bb8e205','聽磵泉琴次趙丞韻','楊公遠','宋','宋诗','song-poetry','','[]','來謁磵泉琴，都忘利與名。',48,'全唐诗/poet.song.234000.json','["來謁磵泉琴，都忘利與名。", "初聞心地爽，飽聽耳根清。", "三峽流波勢，九臯鳴鶴聲。", "更期明月夜，共此暢幽情。"]'),
('01a4f9ff-4841-48a9-936e-490b8ed358fa','生朝','楊公遠','宋','宋诗','song-poetry','','[]','初度今朝四二年，頭顱堪笑尚依然。',64,'全唐诗/poet.song.234000.json','["初度今朝四二年，頭顱堪笑尚依然。", "故廬僅有三間月，負郭曾無二頃田。", "雅淡生涯圖畫裏，清新吟思竹梅邊。", "焚香只祝吾親健，此外窮通付老天。"]'),
('25656900-051d-46bf-bf59-0f2bb6d8ebd9','清明後旬日不聞鵑','楊公遠','宋','宋诗','song-poetry','','[]','過了清明又一旬，不聞杜宇免傷情。',32,'全唐诗/poet.song.234000.json','["過了清明又一旬，不聞杜宇免傷情。", "算渠會得羈人意，應向山林僻處鳴。"]'),
('9423a126-343e-41e6-9293-0240e357fb92','次程斗山村居韻  其一','楊公遠','宋','宋诗','song-poetry','','[]','隠迹深村裏，年今四十餘。',48,'全唐诗/poet.song.234000.json','["隠迹深村裏，年今四十餘。", "謾携三寸管，欠讀幾行書。", "愛竹和煙種，移梅带月鋤。", "簞瓢還自樂，飯糗茹青蔬。"]'),
('c1d20fbe-9157-45cd-986a-3a2870205a85','次程斗山村居韻  其二','楊公遠','宋','宋诗','song-poetry','','[]','蕭灑園池上，依然一故廬。',48,'全唐诗/poet.song.234000.json','["蕭灑園池上，依然一故廬。", "蒼苔封曲逕，老鶴伴閒居。", "計拙身還逸，顔酡鬢任疎。", "日長無個事，窮達儘教渠。"]'),
('3212eff0-cad8-492e-a467-76bbe1d1c081','次程斗山村居韻  其三','楊公遠','宋','宋诗','song-poetry','','[]','山勢主賓立，溪流涇渭分。',48,'全唐诗/poet.song.234000.json','["山勢主賓立，溪流涇渭分。", "景幽詩易得，興逸酒難醺。", "有累營家燕，無心出岫雲。", "若言朝市事，毫髮不曾聞。"]'),
('68a8bc2b-a500-419c-ab88-5c7b0991aa4b','次程斗山村居韻  其四','楊公遠','宋','宋诗','song-poetry','','[]','融和天氣好，携杖作清遊。',48,'全唐诗/poet.song.234000.json','["融和天氣好，携杖作清遊。", "景物自消長，禽言或去留。", "人登山際寺，花映水邊樓。", "欲寫歸吟卷，敲推手不休。"]'),
('7ed726fc-c178-4b16-b683-4dd35f1058c1','次程斗山村居韻  其五','楊公遠','宋','宋诗','song-poetry','','[]','搔頭無別想，得句但長吟。',48,'全唐诗/poet.song.234000.json','["搔頭無別想，得句但長吟。", "懶到風波地，堅存鐵石心。", "人情從冷熱，世態任浮沈。", "却喜虛簷外，清吹滿竹林。"]'),
('928a38ea-d7e8-4d5c-9ee7-edb47a160b01','次程斗山村居韻  其六','楊公遠','宋','宋诗','song-poetry','','[]','茅結兩間月，白雲分半間。',48,'全唐诗/poet.song.234000.json','["茅結兩間月，白雲分半間。", "利名俱拚捨，雲月共清閒。", "來轍元無俗，論交頼有山。", "謝渠梁上燕，社後又飛還。"]'),
('f636611e-f278-4b45-9e8e-470ec5bc9819','次程斗山村居韻  其七','楊公遠','宋','宋诗','song-poetry','','[]','山中閒宰相，日日有蜂衙。',48,'全唐诗/poet.song.234000.json','["山中閒宰相，日日有蜂衙。", "劍戟門前竹，槍棋鼎內茶。", "鶑歌喉宛轉，蝶舞翅欹斜。", "只此堪娛樂，何消解語花。"]'),
('11b42869-5598-44eb-a4d6-1ea8718e35a6','次程斗山村居韻  其八','楊公遠','宋','宋诗','song-poetry','','[]','村疃多幽趣，誰言景象稀。',48,'全唐诗/poet.song.234000.json','["村疃多幽趣，誰言景象稀。", "雲欹山卸帽，苔長石添衣。", "一歲驚春老，千林覺綠肥。", "可憐雙蛺蝶，又傍菜花飛。"]'),
('b7204014-eed2-4856-a16d-4484b2491ee1','次程斗山村居韻  其九','楊公遠','宋','宋诗','song-poetry','','[]','生來疎拙甚，怕與俗流同。',48,'全唐诗/poet.song.234000.json','["生來疎拙甚，怕與俗流同。", "頗識一丁字，寧牽兩石弓。", "夜敲篩柳月，曉對落花風。", "但得身無事，何消效送窮。"]'),
('6a397fcc-8d8a-496e-8f1a-2adf377db16b','次程斗山村居韻  其一○','楊公遠','宋','宋诗','song-poetry','','[]','詩骨清臞甚，幾如沈隠侯。',48,'全唐诗/poet.song.234000.json','["詩骨清臞甚，幾如沈隠侯。", "自編籬象眼，爲護笋貓頭。", "日有丘園樂，身無世俗愁。", "憐渠名利客，汩汩幾時休。"]'),
('6308f307-bc37-486a-8367-64f40d76a5b2','再用韻  其一','楊公遠','宋','宋诗','song-poetry','','[]','非郭非山住，蕭然樂有餘。',48,'全唐诗/poet.song.234000.json','["非郭非山住，蕭然樂有餘。", "晝長延客話，夜靜課兒書。", "藥潤晴時曬，畦磽雨後鋤。", "近來生計好，新味富佳蔬。"]'),
('a106174f-4c8a-4271-910d-9eea441f1af8','再用韻  其二','楊公遠','宋','宋诗','song-poetry','','[]','數椽欹欲壓，髣髴玉川廬。',48,'全唐诗/poet.song.234000.json','["數椽欹欲壓，髣髴玉川廬。", "不結市朝夢，惟便水竹居。", "靜中諳世味，貧裏見親疏。", "忽怪幽池漲，元通灌稻渠。"]'),
('2fcce3f2-e12c-42e7-b05a-ddfca49ef548','再用韻  其三','楊公遠','宋','宋诗','song-poetry','','[]','村深林密處，路向小橋分。',48,'全唐诗/poet.song.234000.json','["村深林密處，路向小橋分。", "屋老誅茅葺，腸枯借酒醺。", "廢興隨反掌，富貴等浮雲。", "近更澆漓甚，傷懷不忍聞。"]'),
('55d39ff1-8b1d-46ef-bee3-f9b0e6aa06b3','再用韻  其四','楊公遠','宋','宋诗','song-poetry','','[]','林塘幽復僻，俗士可曾遊。',48,'全唐诗/poet.song.234000.json','["林塘幽復僻，俗士可曾遊。", "景物因人勝，茶瓜爲客留。", "納凉尋密竹，凝眺倚層樓。", "浮世榮枯事，從今莫問休。"]'),
('cd861e6b-aa62-4bb4-82c2-708ab08b1d0a','再用韻  其五','楊公遠','宋','宋诗','song-poetry','','[]','閒拂蒼苔坐，新蟬伴我吟。',48,'全唐诗/poet.song.234000.json','["閒拂蒼苔坐，新蟬伴我吟。", "有山堪著眼，無事可縈心。", "風細荷香度，池清鳥影沈。", "詩成慙句拙，那得落雞林。"]'),
('5a836e4f-1582-47ef-a37d-685c0bd0e12a','再用韻  其六','楊公遠','宋','宋诗','song-poetry','','[]','孤竹赤松子，定交泉石間。',48,'全唐诗/poet.song.234000.json','["孤竹赤松子，定交泉石間。", "不關渠勢利，落得自蕭閒。", "畫寫景中景，雲分山外山。", "興來時散策，興盡便知還。"]'),
('628156e9-b43a-45ac-a12f-2581abed4639','再用韻  其七','楊公遠','宋','宋诗','song-poetry','','[]','遶簷森竹木，環列類排衙。',48,'全唐诗/poet.song.234000.json','["遶簷森竹木，環列類排衙。", "供客何消酒，論文只藉茶。", "禽聲喧晝永，日影印窗斜。", "更有清虛事，凭欄看藕花。"]'),
('310171d4-4119-4870-9379-ef2699c421f1','再用韻  其八','楊公遠','宋','宋诗','song-poetry','','[]','地僻人煙少，林深轍迹稀。',48,'全唐诗/poet.song.234000.json','["地僻人煙少，林深轍迹稀。", "折蕉當巨扇，裁葛作單衣。", "田綠秧初遍，梅紅雨後肥。", "茅簷喧閙處，紫燕引雛飛。"]'),
('08f535ab-b9f7-4244-af0a-07c4aa197b7a','再用韻  其九','楊公遠','宋','宋诗','song-poetry','','[]','平生丘壑趣，閒雅更誰同。',48,'全唐诗/poet.song.234000.json','["平生丘壑趣，閒雅更誰同。", "養竹苔三徑，栽花地一弓。", "棋邊消永日，琴上鼓薰風。", "靜裏謀生計，優游道不窮。"]'),
('48321b2d-29d2-4699-a276-8115b7716171','再用韻  其一○','楊公遠','宋','宋诗','song-poetry','','[]','骨相寒如許，那封萬戶侯。',48,'全唐诗/poet.song.234000.json','["骨相寒如許，那封萬戶侯。", "紅顔非藉酒，白雪未蒙頭。", "事少渾無夢，身閒豈有愁。", "老天能覆我，飽暖四宜休。"]'),
('26eb741d-4781-4d81-8937-7ce7bdba0de9','三用韻  其一','楊公遠','宋','宋诗','song-poetry','','[]','卜築郊坰外，寬閒一畝餘。',48,'全唐诗/poet.song.234000.json','["卜築郊坰外，寬閒一畝餘。", "汲泉朝灌菊，炙燭夜觀書。", "酒熟邀朋酌，園荒課僕鋤。", "喜嘗紅稻飯，旋薦晚菘蔬。"]'),
('5879f1e2-c005-4315-9c77-e453da386553','三用韻  其二','楊公遠','宋','宋诗','song-poetry','','[]','地不喧車馬，蕭然一草廬。',48,'全唐诗/poet.song.234000.json','["地不喧車馬，蕭然一草廬。", "曲通樵牧逕，正合野人居。", "秋老欣禾熟，林寒覺葉疏。", "高歌仍鼓腹，世事豈關渠。"]'),
('0335048c-c814-4252-a2ce-aef3e7967d81','三用韻  其三','楊公遠','宋','宋诗','song-poetry','','[]','屋頭明月上，此夕又秋分。',48,'全唐诗/poet.song.234000.json','["屋頭明月上，此夕又秋分。", "千里人俱共，三杯酒自醺。", "河清疑有水，夜永喜無雲。", "桂樹婆娑影，天香滿世聞。"]'),
('8210d6a3-b746-47c0-bce4-c88a05f0720a','三用韻  其四','楊公遠','宋','宋诗','song-poetry','','[]','人生期滿百，有興且追遊。',48,'全唐诗/poet.song.234000.json','["人生期滿百，有興且追遊。", "白髮來非約，青春去莫留。", "兔烏雙轉轂，今古一凭樓。", "莫問窮通事，從今付分休。"]'),
('08e21aab-134e-4a2d-ae9c-7b91405ab9aa','三用韻  其五','楊公遠','宋','宋诗','song-poetry','','[]','夜凉清似水，凄切只蛩吟。',48,'全唐诗/poet.song.234000.json','["夜凉清似水，凄切只蛩吟。", "喚起離人思，催殘懶婦心。", "敲梧風淅淅，篩竹月沈沈。", "顥氣微茫裏，依稀見遠林。"]'),
('22a7415d-0eb1-4951-8605-e160ed4307c7','三用韻  其六','楊公遠','宋','宋诗','song-poetry','','[]','性野耽幽隠，茅茨一二間。',48,'全唐诗/poet.song.234000.json','["性野耽幽隠，茅茨一二間。", "身侔黄鶴瘦，心與白雲閒。", "囊裏詩無俗，毫端畫有山。", "忽驚時節換，塞鴈又南還。"]'),
('26187d00-a351-4919-820b-8b39e0e8fe9e','三用韻  其七','楊公遠','宋','宋诗','song-poetry','','[]','不作皺眉事，何煩古押衙。',48,'全唐诗/poet.song.234000.json','["不作皺眉事，何煩古押衙。", "且嘗桑落酒，更瀹雨前茶。", "風銳霜初結，天寒日易斜。", "莫言秋色老，猶自有黄花。"]'),
('87a3952f-8628-406c-acc2-07d65aa412e9','三用韻  其八','楊公遠','宋','宋诗','song-poetry','','[]','陡覺秋蕭索，林端葉漸稀。',48,'全唐诗/poet.song.234000.json','["陡覺秋蕭索，林端葉漸稀。", "菊殘堪作枕，荷老不成衣。", "著句愁詩俗，持螯喜蟹肥。", "晚來風色緊，吹起荻花飛。"]'),
('3d81ee45-90aa-44f4-880a-09d2106f2bd2','三用韻  其九','楊公遠','宋','宋诗','song-poetry','','[]','生計雖隨分，年來迥不同。',48,'全唐诗/poet.song.234000.json','["生計雖隨分，年來迥不同。", "窮通槐國夢，得失楚人弓。", "世事埋雲月，人情過耳風。", "但教强健在，佳况自無窮。"]'),
('f0143222-e9a2-411d-870c-8a82f8a88094','三用韻  其一○','楊公遠','宋','宋诗','song-poetry','','[]','無官堪受祿，有橘當封侯。',48,'全唐诗/poet.song.234000.json','["無官堪受祿，有橘當封侯。", "俗事退三舍，吟情出一頭。", "策筇枝縱步，買竹葉澆愁。", "又是秋歸去，推移不暫休。"]'),
('d18d4dcb-adfb-480f-b774-0b982608cf96','四用韻  其一','楊公遠','宋','宋诗','song-poetry','','[]','探梅時節近，春小已秋餘。',48,'全唐诗/poet.song.234000.json','["探梅時節近，春小已秋餘。", "飯足農家樂，年豐史筆書。", "籬隈眠繭栗，池淺立舂鋤。", "對景閒吟句，風騷沒笋蔬。"]'),
('a996c0d4-962d-48eb-b0a5-5a03dd4f3750','四用韻  其二','楊公遠','宋','宋诗','song-poetry','','[]','朝市何曾夢，山林自結廬。',48,'全唐诗/poet.song.234000.json','["朝市何曾夢，山林自結廬。", "清幽無俗事，蕭灑類僧居。", "地鎖苔痕潤，池窺竹影疎。", "每番新雨過，門外水成渠。"]'),
('0a737f7b-a3fc-4aa6-8bca-124c22165508','四用韻  其三','楊公遠','宋','宋诗','song-poetry','','[]','朔風號萬竅，冷色倍三分。',48,'全唐诗/poet.song.234000.json','["朔風號萬竅，冷色倍三分。", "榾柮爐偏暖，茅柴酒易醺。", "烘梅慳愛日，釀雪布彤雲。", "今是豐年瑞，吾儂政樂聞。"]'),
('04b520bd-a29d-4671-a78b-ebff782fae57','四用韻  其四','楊公遠','宋','宋诗','song-poetry','','[]','小醉初醒後，衝寒作興遊。',48,'全唐诗/poet.song.234000.json','["小醉初醒後，衝寒作興遊。", "宿雲山頂散，殘雪樹根留。", "簷溜懸冰柱，風威凍玉樓。", "欲吟吟未穩，歸擁地爐休。"]'),
('7145fa23-3208-4fe7-8de1-30e89b640418','四用韻  其五','楊公遠','宋','宋诗','song-poetry','','[]','夢覺燈初燼，搔頭謾短吟。',48,'全唐诗/poet.song.234000.json','["夢覺燈初燼，搔頭謾短吟。", "人生隨宿分，世慮莫縈心。", "霜結風聲息，參橫月影沈。", "此時朝市客，爭似卧家林。"]'),
('04eb4643-1641-43d3-b473-21d99002f264','四用韻  其六','楊公遠','宋','宋诗','song-poetry','','[]','活計人知否，無聲詩句間。',48,'全唐诗/poet.song.234000.json','["活計人知否，無聲詩句間。", "高低煙樹古，來往釣舟閒。", "練挂千尋瀑，屏圍幾座山。", "天涯無限景，只仗筆追還。"]'),
('42c45e8e-d4f9-4756-96ab-5b8b5637314c','四用韻  其七','楊公遠','宋','宋诗','song-poetry','','[]','捲起黄紬被，何消道放衙。',48,'全唐诗/poet.song.234000.json','["捲起黄紬被，何消道放衙。", "瓦盆常貯酒，雪水旋煎茶。", "但得詩聯穩，從教竹屋斜。", "助儂高興處，索笑共梅花。"]'),
('0467d31f-a3c2-4511-aee8-bb45945f78a8','四用韻  其八','楊公遠','宋','宋诗','song-poetry','','[]','六出新裁就，漫空密又稀。',48,'全唐诗/poet.song.234000.json','["六出新裁就，漫空密又稀。", "獨行無鶴氅，冷卧有牛衣。", "竹頂千鈞重，梅添十倍肥。", "品題輸謝女，柳絮逐風飛。"]'),
('e4e01f45-a575-405e-b17b-9caab2b53d0d','四用韻  其九','楊公遠','宋','宋诗','song-poetry','','[]','愛梅能獨立，不與衆芳同。',48,'全唐诗/poet.song.234000.json','["愛梅能獨立，不與衆芳同。", "花貯香千斛，梢籠月一弓。", "倚松還傍竹，洗雨更梳風。", "和靖清吟後，題評愈不窮。"]'),
('1d6cd0e8-5529-4e67-8cb0-d083d4592778','四用韻  其一○','楊公遠','宋','宋诗','song-poetry','','[]','因循身漸老，性懶謁王侯。',48,'全唐诗/poet.song.234000.json','["因循身漸老，性懶謁王侯。", "嘗到新藍尾，翻餘舊歷頭。", "春來雖可喜，歲去抑何愁。", "桃板書聯句，三平二滿休。"]'),
('5e468fbd-9a64-48a9-b758-6be6c4ba85be','見遠樓次敏齋陳先生韻','楊公遠','宋','宋诗','song-poetry','','[]','目欲窮千里，樓頭著意看。',48,'全唐诗/poet.song.234000.json','["目欲窮千里，樓頭著意看。", "雲橫知岫遠，野迥覺天寬。", "對景詩懷壯，乘風衣袂寒。", "主人還解事，容我恣憑闌。"]'),
('5dac5e62-bdbe-4978-a4de-376a9fbe9d4e','次汪制議梅巖韻','楊公遠','宋','宋诗','song-poetry','','[]','梅倚幽巖頂，花開碧蘚枝。',48,'全唐诗/poet.song.234000.json','["梅倚幽巖頂，花開碧蘚枝。", "了無脂粉態，惟有雪霜姿。", "一點香清遠，千年樹倔奇。", "和羹風味在，那許浪題詩。"]'),
('2acd8e39-83b8-4642-9490-76fb20cc5c11','覽鏡','楊公遠','宋','宋诗','song-poetry','','[]','覽鏡顔非昔，相將老態催。',48,'全唐诗/poet.song.234000.json','["覽鏡顔非昔，相將老態催。", "青春彈指去，白雪上頭來。", "興逸三杯酒，詩清百咏梅。", "襟期除此外，萬事付悠哉。"]'),
('eea97601-c65f-461d-af69-cb73040cd252','閏九日','楊公遠','宋','宋诗','song-poetry','','[]','九日重逢惱肺腸，世情底事便炎凉。',32,'全唐诗/poet.song.234000.json','["九日重逢惱肺腸，世情底事便炎凉。", "今朝有酒還堪醉，不信黄花不復香。"]'),
('ee2a16c2-f5eb-45a9-aa42-2228b30b12a7','喜晴','楊公遠','宋','宋诗','song-poetry','','[]','厭聽滴簷聲，風回喜乍晴。',48,'全唐诗/poet.song.234000.json','["厭聽滴簷聲，風回喜乍晴。", "潤添新柳重，瘦損落花輕。", "山翠雲初斂，溪渾水漸清。", "野人無別事，杖策又郊行。"]'),
('412c1e0e-5213-4501-bd33-3a87b3bbd3bf','促織','楊公遠','宋','宋诗','song-poetry','','[]','促人機杼意殊深，徹夜啾啾不絕吟。',32,'全唐诗/poet.song.234000.json','["促人機杼意殊深，徹夜啾啾不絕吟。", "莫入五侯庭院去，青蛾紅粉少知心。"]'),
('3dc4f867-399d-46c6-b41f-3d931f623d5d','除夜','楊公遠','宋','宋诗','song-poetry','','[]','老境漸相干，饒儂鬢未斑。',48,'全唐诗/poet.song.234000.json','["老境漸相干，饒儂鬢未斑。", "歲華今夜換，天道此時還。", "累重家常儉，身輕心自閒。", "莫愁生計薄，筆底有青山。"]'),
('a9093985-8033-4540-ad93-065f422579ed','再謁紫極宮','楊公遠','宋','宋诗','song-poetry','','[]','一去重來已十年，頭顱堪笑尚依然。',32,'全唐诗/poet.song.234000.json','["一去重來已十年，頭顱堪笑尚依然。", "何當了却塵紛事，來結梅花紙帳緣。"]'),
('97dbe9be-e08a-4569-bb95-8205cf42c5f6','偶得李竹屋居士摘和靖先生梅詩四聯演成八韻句工而韻險似難繼和愧不自揣僭敢續貂珠玉在傍覺我形穢  其一','楊公遠','宋','宋诗','song-poetry','','[]','疎影橫斜水清淺，冰容不比尋常見。',64,'全唐诗/poet.song.234000.json','["疎影橫斜水清淺，冰容不比尋常見。", "若非采石謫仙魂，定是汨羅騷客面。", "鶴膝枝低俯鏡奩，鴨頭波靜澄江練。", "憑誰說與老孤山，敢續君詩君莫厭。"]'),
('229c2b80-7a05-40ec-9b1a-87bed208574d','偶得李竹屋居士摘和靖先生梅詩四聯演成八韻句工而韻險似難繼和愧不自揣僭敢續貂珠玉在傍覺我形穢  其二','楊公遠','宋','宋诗','song-poetry','','[]','暗香浮動月黄昏，斗轉參橫月闖門。',64,'全唐诗/poet.song.234000.json','["暗香浮動月黄昏，斗轉參橫月闖門。", "香一線通清曉夢，影千枝寫悄詩魂。", "荒寒老屋疎籬處，寂寞斷橋流水村。", "青女橫陳雞唱徹，懸知煙霧暝雲根。"]'),
('47e3bc49-5ebf-4984-829f-619a558b1a85','偶得李竹屋居士摘和靖先生梅詩四聯演成八韻句工而韻險似難繼和愧不自揣僭敢續貂珠玉在傍覺我形穢  其三','楊公遠','宋','宋诗','song-poetry','','[]','雪後園林纔半樹，支筇細認孤山路。',64,'全唐诗/poet.song.234000.json','["雪後園林纔半樹，支筇細認孤山路。", "雲頑未斂風更嚴，木凍且僵天欲莫。", "冷蕊依稀無處尋，清香髣髴暗中度。", "翻思立馬老坡翁，月上黄昏方得句。"]'),
('0b8095ea-824a-48d5-8211-c17ec9271836','偶得李竹屋居士摘和靖先生梅詩四聯演成八韻句工而韻險似難繼和愧不自揣僭敢續貂珠玉在傍覺我形穢  其四','楊公遠','宋','宋诗','song-poetry','','[]','水邊籬落忽橫枝，不受狂蜂浪蝶知。',64,'全唐诗/poet.song.234000.json','["水邊籬落忽橫枝，不受狂蜂浪蝶知。", "萬紫千紅俱寂寞，三花五蕊自新奇。", "風號浪湧連天起，雪作雲凝拂地垂。", "此景此時難著脚，輸渠耐冷立江湄。"]'),
('582f1b53-3653-4d2c-9d7e-521cde8bb3ec','偶得李竹屋居士摘和靖先生梅詩四聯演成八韻句工而韻險似難繼和愧不自揣僭敢續貂珠玉在傍覺我形穢  其五','楊公遠','宋','宋诗','song-poetry','','[]','池水倒窺疎影動，任渠羌管吹三弄。',64,'全唐诗/poet.song.234000.json','["池水倒窺疎影動，任渠羌管吹三弄。", "碧波清淺浄無痕，老榦槎牙堅耐凍。", "花放羞同桃李場，香來偏惱詩人夢。", "當年曾醉老師雄，翠羽雙雙疑作鳳。"]'),
('45e719d2-5709-4b87-a90c-057f39208426','江草塘袖詩言別次韻以餞','楊公遠','宋','宋诗','song-poetry','','[]','數日君不來，欲賦莫雲詩。',108,'全唐诗/poet.song.234000.json','["數日君不來，欲賦莫雲詩。", "今朝忽過我，歡然如先期。", "談論已忘倦，坐卧猶忘機。", "正爾躊躇間，袖出言別詩。", "且知束錦囊，屆途無多時。", "使我心爲感，使我心爲悲。", "此意竟何如，寫作送行詩。", "君不鄙我句，喜色形鬚眉。", "明朝天一方，胥會知何時。"]'),
('ee9e5ef1-d21b-47c8-8f27-774236805ecb','次蘭皋吳堂長曉起','楊公遠','宋','宋诗','song-poetry','','[]','曉起披衣不奈寒，搔頭自愧轉疎頑。',64,'全唐诗/poet.song.234000.json','["曉起披衣不奈寒，搔頭自愧轉疎頑。", "吟情冷淡梅花外，畫思微茫烟雨間。", "有興何妨終日醉，無求贏得此生閒。", "要知人事循環理，歲月推移去復還。"]'),
('21576696-edfb-4670-b6f5-6fcfaa2cc0c5','生朝','楊公遠','宋','宋诗','song-poetry','','[]','浮生四十自今朝，一味清閒宿分招。',64,'全唐诗/poet.song.234000.json','["浮生四十自今朝，一味清閒宿分招。", "山在筆端長不老，雪於鬢裏幸相饒。", "有時得句難緘口，無事干人懶折腰。", "多謝梅花爲我壽，年年先放小溪橋。"]'),
('36a40fc3-2352-428c-80e5-4b389218c691','贄雨村施權宰','楊公遠','宋','宋诗','song-poetry','','[]','旌旆來時桂未華，如今烟柳又藏鴉。',64,'全唐诗/poet.song.234000.json','["旌旆來時桂未華，如今烟柳又藏鴉。", "一塵不著千家月，萬象無私滿縣花。", "草茂圜扉春寂靜，吏閒庭院燕諠譁。", "剩膺當路飛騰剡，玉笋催班已有涯。"]'),
('fd6d60a7-4c1d-4eec-ac8a-f2478be4b914','偶題','楊公遠','宋','宋诗','song-poetry','','[]','鵝黄又染柳絲絲，自笑勞生作麽爲。',64,'全唐诗/poet.song.234000.json','["鵝黄又染柳絲絲，自笑勞生作麽爲。", "雨耒雲耕三寸管，風櫺月牖一聯詩。", "酒逢知己何妨醉，事不如人且待時。", "祇恁眼前隨分去，展開懷抱豁雙眉。"]'),
('daa2cbb1-ab3c-405d-a38e-37cc8290e6d5','懶','楊公遠','宋','宋诗','song-poetry','','[]','疎懶春來分外添，蒲團兀坐地爐邊。',64,'全唐诗/poet.song.234000.json','["疎懶春來分外添，蒲團兀坐地爐邊。", "關心事少夜慳夢，酌酒杯多晝亦眠。", "琴有徽絃姑挂壁，詩無眼目謾成篇。", "自憐不似門前柳，才得東風翠拂天。"]'),
('8ad182a7-94e2-4d60-863c-84c20dcc5f0d','次黄山中山居韻  其一','楊公遠','宋','宋诗','song-poetry','','[]','山居無一事，所得趣何深。',48,'全唐诗/poet.song.234000.json','["山居無一事，所得趣何深。", "閲世秋聲賦，存心夜氣箴。", "步徐携葛杖，興逸鼓嵇琴。", "最喜疎籬下，悠然見翠岑。"]'),
('8ae9f773-7760-4b30-b341-7eeeac640980','次黄山中山居韻  其二','楊公遠','宋','宋诗','song-poetry','','[]','結茅林麓久，老大鬢絲多。',48,'全唐诗/poet.song.234000.json','["結茅林麓久，老大鬢絲多。", "浮世幾棋局，生涯一釣蓑。", "位卑希少室，飲醉達無何。", "勘破紅塵事，風恬水不波。"]'),
('3c96df85-e4cc-4eeb-a7d4-882020e4902d','雪月梅','楊公遠','宋','宋诗','song-poetry','','[]','寒梅開後雪初晴，斂盡殘雲月又生。',64,'全唐诗/poet.song.234000.json','["寒梅開後雪初晴，斂盡殘雲月又生。", "月映雪時梅更好，梅橫月處雪爭明。", "羨渠結伴成三白，添我相親即四清。", "今夕細吟詩說與，來年此際莫寒盟。"]'),
('5cfafb47-9c1a-41f9-95a5-cd11a243e416','次趙篷窗歲莫','楊公遠','宋','宋诗','song-poetry','','[]','人間歷日又天頒，造化推移豈暫閒。',64,'全唐诗/poet.song.234000.json','["人間歷日又天頒，造化推移豈暫閒。", "春到却添詩思好，年高何惜鬢毛斑。", "非干己事慵開口，不受人情免厚顔。", "試問近來知我者，梅花之外只青山。"]'),
('95e08bf0-9213-4fbc-aad4-34b7d3f8083e','有感','楊公遠','宋','宋诗','song-poetry','','[]','勘破浮生且任真，底須苦苦役精神。',64,'全唐诗/poet.song.234000.json','["勘破浮生且任真，底須苦苦役精神。", "靜觀歷代千張紙，細數英才幾掬塵。", "朝市只尊黄閣貴，山林誰念素衣貧。", "何如領取閒風月，贏得襟懷日日春。"]'),
('eb28c747-7b4f-4ca5-b360-c66ee12500d5','旅寓','楊公遠','宋','宋诗','song-poetry','','[]','憶昔離家日，村村煮繭香。',48,'全唐诗/poet.song.234000.json','["憶昔離家日，村村煮繭香。", "因循淹五月，次第過重陽。", "排悶詩多感，懷歸夢最長。", "君言名利事，都只付亡羊。"]'),
('49161988-7b72-4e76-93c6-6dc79c470a18','池塘生春草','楊公遠','宋','宋诗','song-poetry','','[]','燕寢凝香夢更清，夢回得句快吟情。',32,'全唐诗/poet.song.234000.json','["燕寢凝香夢更清，夢回得句快吟情。", "可憐人化遼天鶴，池上年年草自生。"]'),
('828eb9b7-b029-4b27-9297-17e757537ff6','偶成','楊公遠','宋','宋诗','song-poetry','','[]','抱膝長吟更短歌，百年身世易蹉跎。',64,'全唐诗/poet.song.234000.json','["抱膝長吟更短歌，百年身世易蹉跎。", "事逢如意從來少，詩不驚人空自多。", "暖日烘時花著子，東風吹後草成莎。", "看渠天道無私覆，寒谷陽春有脚麽。"]'),
('5f6b746a-6cc6-4c91-9702-89752456681d','次蘭皋擘蟹','楊公遠','宋','宋诗','song-poetry','','[]','江湖郭索草泥行，不料遭人入鼎烹。',64,'全唐诗/poet.song.234000.json','["江湖郭索草泥行，不料遭人入鼎烹。", "勇恃甲戈身莫衛，富藏金玉味還清。", "持螯細咀仍三詠，把酒高吟快一生。", "鱸膾侯鯖應退舍，算渠只合伴香橙。"]'),
('d240e209-4280-4942-88c4-a656d460fa56','旅寓岑寂中園丁送花四品因賦五絕  其一','楊公遠','宋','宋诗','song-poetry','','[]','倚遍闌干日欲斜，春光撩動客思家。',32,'全唐诗/poet.song.234000.json','["倚遍闌干日欲斜，春光撩動客思家。", "園丁頗識人岑寂，特地携來四品花。"]'),
('d569d0b0-3d59-4fd0-88d9-6e8e8a34411a','旅寓岑寂中園丁送花四品因賦五絕  其二','楊公遠','宋','宋诗','song-poetry','','[]','玉蕊花開觸處芳，甆缾安頓細平章。',32,'全唐诗/poet.song.234000.json','["玉蕊花開觸處芳，甆缾安頓細平章。", "怕渠不肯梅花弟，能趁春風七里香。"]'),
('b26bb52a-a5bb-4ce1-843c-68c40952f6c5','旅寓岑寂中園丁送花四品因賦五絕  其三','楊公遠','宋','宋诗','song-poetry','','[]','百葉夭桃簇絳綃，向人含笑態妖嬈。',32,'全唐诗/poet.song.234000.json','["百葉夭桃簇絳綃，向人含笑態妖嬈。", "開元天子曾擡舉，簪向妃冠恨便消。"]'),
('fcf66c74-44e9-497f-b253-b3cfb0d721eb','旅寓岑寂中園丁送花四品因賦五絕  其四','楊公遠','宋','宋诗','song-poetry','','[]','西蜀名花別樣芳，玉環睡起試新粧。',32,'全唐诗/poet.song.234000.json','["西蜀名花別樣芳，玉環睡起試新粧。", "化工還有無情處，祇與胭脂不與香。"]'),
('1984040a-25d7-4214-83d3-a820a139449d','旅寓岑寂中園丁送花四品因賦五絕  其五','楊公遠','宋','宋诗','song-poetry','','[]','粉綃細剪綴枝條，無奈盈盈笑靨嬌。',32,'全唐诗/poet.song.234000.json','["粉綃細剪綴枝條，無奈盈盈笑靨嬌。", "最是短籬遥認處，渾如臘雪未全消。"]'),
('3180838f-7df6-4b03-a1b9-11e15ef77998','次菊坡汪判丞','楊公遠','宋','宋诗','song-poetry','','[]','襟期坡上菊，稟得一天秋。',48,'全唐诗/poet.song.234000.json','["襟期坡上菊，稟得一天秋。", "德述須銀管，詩吟聳玉樓。", "不關心富貴，愛隠迹林丘。", "只恐符商夢，桃源莫可留。"]'),
('f74b1748-f70c-475e-892a-ca77e7eb40c0','次蘭皋秋感','楊公遠','宋','宋诗','song-poetry','','[]','向晚郊墟送嫩凉，征鴻點點又南翔。',64,'全唐诗/poet.song.234000.json','["向晚郊墟送嫩凉，征鴻點點又南翔。", "年光迅似離弦箭，世事艱於上水航。", "月不冷炎來戶牖，詩多凄怨感蛩螿。", "秋容莫道全蕭索，籬菊芙蓉競試粧。"]'),
('eea14296-faa2-4f77-926b-f0dd4de1e190','次宋省齋立秋','楊公遠','宋','宋诗','song-poetry','','[]','纔見春花榮，又見春花謝。',84,'全唐诗/poet.song.234000.json','["纔見春花榮，又見春花謝。", "花謝綠成陰，瞬目逢炎夏。", "誰知俯仰間，祝融便回駕。", "却喜西風來，美矣難酬價。", "且效柴桑人，寄傲南窗下。", "此意自領會，那許傍人借。", "所願無榮辱，靜中觀物化。"]'),
('3a1940e0-3f7d-4797-a146-bfc692a0b856','病腰','楊公遠','宋','宋诗','song-poetry','','[]','偶病腰疼失步傷，艱行終日坐胡床。',64,'全唐诗/poet.song.234000.json','["偶病腰疼失步傷，艱行終日坐胡床。", "非干騎鶴因錢重，豈是懸魚爲带長。", "倒屣蔡邕那敢效，休官陶令却相當。", "名方細檢無良劑，祇好頻頻酌酒漿。"]'),
('446070a9-32ae-485f-b5af-f7fe8f30e0b6','雪  其一','楊公遠','宋','宋诗','song-poetry','','[]','萬籟更深寂不鳴，窗間恍覺月微明。',32,'全唐诗/poet.song.234000.json','["萬籟更深寂不鳴，窗間恍覺月微明。", "情知是雪疑非雪，忽聽前村折竹聲。"]'),
('699ed3f3-728a-4e9d-a0e6-335ca44b0362','雪  其二','楊公遠','宋','宋诗','song-poetry','','[]','無奈風威冷逼衾，起來搔首更披襟。',32,'全唐诗/poet.song.234000.json','["無奈風威冷逼衾，起來搔首更披襟。", "方知攪下漫空雪，已積階前尺許深。"]'),
('2eb5fd76-78e8-4d3b-84fe-2f0feec6a96c','雪  其三','楊公遠','宋','宋诗','song-poetry','','[]','祇應王母宴瑶池，宴罷羣仙趁醉歸。',32,'全唐诗/poet.song.234000.json','["祇應王母宴瑶池，宴罷羣仙趁醉歸。", "駕鳳鞭鸞仍馭鶴，滿空風捲羽毛飛。"]'),
('10534e82-dd7c-4fc4-9032-a36c61680ef2','雪  其四','楊公遠','宋','宋诗','song-poetry','','[]','天教塵世換規模，萬象憂愁心未孚。',32,'全唐诗/poet.song.234000.json','["天教塵世換規模，萬象憂愁心未孚。", "一夜蒼松鬚白盡，青山頓覺老頭顱。"]'),
('4302c79c-e536-40d5-9c68-02f471837b9c','雪  其五','楊公遠','宋','宋诗','song-poetry','','[]','堆瓊積玉遍階除，個是騷人富貴餘。',32,'全唐诗/poet.song.234000.json','["堆瓊積玉遍階除，個是騷人富貴餘。", "莫道得渠無用處，寒窗能映夜觀書。"]'),
('383a3996-9afc-4274-8f27-33a52640a7c6','雪  其六','楊公遠','宋','宋诗','song-poetry','','[]','造化須臾變物華，園林無處不梅花。',32,'全唐诗/poet.song.234000.json','["造化須臾變物華，園林無處不梅花。", "三間矮屋清溪上，疑似林逋處士家。"]'),
('ee3407a3-86b5-4b03-a370-79f2412c66b5','雪  其七','楊公遠','宋','宋诗','song-poetry','','[]','喧呼童稚塑獅兒，髣髴形模便有威。',32,'全唐诗/poet.song.234000.json','["喧呼童稚塑獅兒，髣髴形模便有威。", "枯炭點睛鈴用橘，酒杯疊疊印毛衣。"]'),
('3a78002e-113c-4941-931b-33bbef9565c6','雪  其八','楊公遠','宋','宋诗','song-poetry','','[]','臘前三白兆豐年，此話農家萬古傳。',32,'全唐诗/poet.song.234000.json','["臘前三白兆豐年，此話農家萬古傳。", "近值世更人事改，生民全藉老天憐。"]'),
('9255d0c1-38c3-4820-9b33-3d0f9e96329e','雪  其九','楊公遠','宋','宋诗','song-poetry','','[]','雪滿乾坤月滿天，剡溪風景尚依然。',32,'全唐诗/poet.song.234000.json','["雪滿乾坤月滿天，剡溪風景尚依然。", "戴逵仙去徽之死，乘興無人更棹船。"]'),
('6c1dc8b4-522e-42b3-b7d9-ebb72ac61ab8','雪  其一○','楊公遠','宋','宋诗','song-poetry','','[]','徹夜陰風恣怒號，誰家帳底飲羊羔。',32,'全唐诗/poet.song.234000.json','["徹夜陰風恣怒號，誰家帳底飲羊羔。", "何如榾柮爐邊坐，雪水煎茶興味高。"]'),
('827b271e-1e0c-454c-9e60-297c4446aa3a','春夜雪再用韻  其一','楊公遠','宋','宋诗','song-poetry','','[]','東風怒撼樹梢鳴，凍住頑雲黯不明。',32,'全唐诗/poet.song.234000.json','["東風怒撼樹梢鳴，凍住頑雲黯不明。", "兀坐爐邊閒側耳，春蟲撩亂撲窗聲。"]'),
('e2257da0-2b5f-4256-9cff-2a2e5f602b4b','春夜雪再用韻  其二','楊公遠','宋','宋诗','song-poetry','','[]','向曉披衣更擁衾，略無一事惱胸襟。',32,'全唐诗/poet.song.234000.json','["向曉披衣更擁衾，略無一事惱胸襟。", "起來點檢窗前雪，地上無多屋上深。"]'),
('df33ca75-6fb5-4867-a8ad-998b74d748de','春夜雪再用韻  其三','楊公遠','宋','宋诗','song-poetry','','[]','詩夢關情草滿池，東皇已向歲前歸。',32,'全唐诗/poet.song.234000.json','["詩夢關情草滿池，東皇已向歲前歸。", "怪渠楊柳摇金未，底事漫空絮便飛。"]'),
('763d1145-7271-404c-a2ff-0af0c2991d7c','春夜雪再用韻  其四','楊公遠','宋','宋诗','song-poetry','','[]','江梅带雪狀糢糊，梅雪相逢意不孚。',32,'全唐诗/poet.song.234000.json','["江梅带雪狀糢糊，梅雪相逢意不孚。", "雪遜無香梅遜白，雪消梅現舊頭顱。"]'),
('711050c1-dee3-4962-bcea-a08ffb7771a5','春夜雪再用韻  其五','楊公遠','宋','宋诗','song-poetry','','[]','茆簷堆積未消除，仔細觀來半尺餘。',32,'全唐诗/poet.song.234000.json','["茆簷堆積未消除，仔細觀來半尺餘。", "臘後春前知幾白，豐年可卜史官書。"]'),
('e6e9bac1-e85e-427f-87c6-77216ff220aa','春夜雪再用韻  其六','楊公遠','宋','宋诗','song-poetry','','[]','瓊林玉樹競奢華，老眼光摇眩有花。',32,'全唐诗/poet.song.234000.json','["瓊林玉樹競奢華，老眼光摇眩有花。", "莫是幻成銀色界，樓臺勝處梵王家。"]'),
('aec0cdd0-18e8-4e9d-a39d-d46e8ae06f26','春夜雪再用韻  其七','楊公遠','宋','宋诗','song-poetry','','[]','仙禽灑羽半天飛，疑是歸來老令威。',32,'全唐诗/poet.song.234000.json','["仙禽灑羽半天飛，疑是歸來老令威。", "粧點江鄉堪入畫，漁翁披得滿蓑衣。"]'),
('613b2374-2b07-4926-9029-89804ae439b8','春夜雪再用韻  其八','楊公遠','宋','宋诗','song-poetry','','[]','數聲爆竹入新年，萬紫千紅信息傳。',32,'全唐诗/poet.song.234000.json','["數聲爆竹入新年，萬紫千紅信息傳。", "巽二攙先施妙手，花開頃刻更堪憐。"]'),
('b58a437c-8d9b-49c8-9925-a82c42c22559','春夜雪再用韻  其九','楊公遠','宋','宋诗','song-poetry','','[]','一色寰區水墨天，了無塵翳自天然。',32,'全唐诗/poet.song.234000.json','["一色寰區水墨天，了無塵翳自天然。", "惜乎官禁缾無酒，勝賞空辜藥玉船。"]'),
('ef789a52-a663-4de2-afca-1c79f44b212d','春夜雪再用韻  其一○','楊公遠','宋','宋诗','song-poetry','','[]','雪霽風猶萬竅號，微吟擁鼻袖無羔。',32,'全唐诗/poet.song.234000.json','["雪霽風猶萬竅號，微吟擁鼻袖無羔。", "一寒如此還風味，和得詩成句法高。"]'),
('96508809-9646-4cd1-94d0-2317a260de21','苦雨','楊公遠','宋','宋诗','song-poetry','','[]','滴碎空階頗厭聽，惱人况又近清明。',64,'全唐诗/poet.song.234000.json','["滴碎空階頗厭聽，惱人况又近清明。", "三分春忽二分過，十日天無一日晴。", "寒沁柳眉愁寂寂，濕凝花臉淚盈盈。", "蒼穹好憫雲霓望，留作甘霖助有成。"]'),
('91d694c7-bb1b-4608-ae70-9af92d699d95','次羅梅谷詩畫總觀','楊公遠','宋','宋诗','song-poetry','','[]','梅谷梅應占作魁，不論時節遣花開。',88,'全唐诗/poet.song.234000.json','["梅谷梅應占作魁，不論時節遣花開。", "傳真舊說華光老，詩到林逋俱壓倒。", "華光去後誰逼真，補之筆底生陽春。", "月香水影許多態，竹外斜枝奇且怪。", "後來若問誰解無聲兼有聲，須還梅谷野趣相與共推評。"]'),
('cf37ba52-adf2-4a12-adb5-bf6af7c0dd31','雪消','楊公遠','宋','宋诗','song-poetry','','[]','風姨剪水作花鈿，鋪遍乾坤惜不堅。',64,'全唐诗/poet.song.234000.json','["風姨剪水作花鈿，鋪遍乾坤惜不堅。", "滑滑淤泥溶暖日，潺潺簷溜滴晴天。", "山頭白了青還在，梅臉肥添瘦復前。", "倒指兼旬猶是臘，願期再作兆豐年。"]'),
('b7de557f-ad38-4f1f-b1a3-8a8e72667929','次宋省齋木犀  其一','楊公遠','宋','宋诗','song-poetry','','[]','西風生桂子，香色總關情。',48,'全唐诗/poet.song.234000.json','["西風生桂子，香色總關情。", "籬菊宜交友，山礬可弟兄。", "慣承秋露重，獨占楚天清。", "對此須吟句，呼童索管城。"]'),
('e7c6a729-fa3d-443b-bf28-2df80cfd14ee','次宋省齋木犀  其二','楊公遠','宋','宋诗','song-poetry','','[]','顥氣清如許，全鍾在木犀。',48,'全唐诗/poet.song.234000.json','["顥氣清如許，全鍾在木犀。", "碎金羞色淺，片腦愧香低。", "根析蟾宮種，詩吟繭紙題。", "折來供鼻觀，何用上天梯。"]'),
('e7809b3c-47a0-4615-a74e-1f76704991fa','見竹溪羅權府','楊公遠','宋','宋诗','song-poetry','','[]','琅玕萬箇碧雲深，長覆晴川數畝陰。',64,'全唐诗/poet.song.234000.json','["琅玕萬箇碧雲深，長覆晴川數畝陰。", "渭水侯封元有節，葛陂龍化本無心。", "波光靜處涵清影，灘瀨鳴時和好音。", "除却寒流相映外，此君那許俗塵侵。"]'),
('343c8b59-f5b1-43c8-8d9f-884f366dbc45','見古梅吳府教','楊公遠','宋','宋诗','song-poetry','','[]','萬木風饕凍欲癡，孤根逗暖正斯時。',64,'全唐诗/poet.song.234000.json','["萬木風饕凍欲癡，孤根逗暖正斯時。", "樹槎牙歷百千歲，花摘索開三兩枝。", "兄弟山礬應未稱，交朋松竹恐相宜。", "玉堂標致和羹味，可是香名滿世知。"]'),
('a4af5461-2d3f-43fd-8b62-9525d5ec2b7e','次宋省齋懷竹洲','楊公遠','宋','宋诗','song-poetry','','[]','蒼洲無恙在，依舊匝溪灣。',48,'全唐诗/poet.song.234000.json','["蒼洲無恙在，依舊匝溪灣。", "闌護竹三逕，屋環梅數間。", "幽池生草夢，危石繡苔斑。", "遥想銜杯處，何曾醉玉山。"]'),
('0b9e2699-67b6-4d95-8b3d-2a7eadb9393d','探梅','楊公遠','宋','宋诗','song-poetry','','[]','傍水尋梅步水湄，輕寒輕暖日斜時。',64,'全唐诗/poet.song.234000.json','["傍水尋梅步水湄，輕寒輕暖日斜時。", "不辭二里還三里，且看南枝又北枝。", "蘂勝珠圓香勝腦，花如玉潔蔕如脂。", "絕憐疎影橫清淺，欲爲題詩未敢詩。"]'),
('c3709ec4-e34b-4242-b814-0f6abeda25ba','次省齋桂花','楊公遠','宋','宋诗','song-poetry','','[]','羨君詩句正而葩，閒對西風賦桂花。',32,'全唐诗/poet.song.234000.json','["羨君詩句正而葩，閒對西風賦桂花。", "可惜分來蟾窟種，如今開遍野人家。"]'),
('c929e1c6-33eb-4f6e-9ab8-af8313f70857','池上芙蓉','楊公遠','宋','宋诗','song-poetry','','[]','小池擎雨已無荷，池上芙蓉映碧波。',64,'全唐诗/poet.song.234000.json','["小池擎雨已無荷，池上芙蓉映碧波。", "初試晨粧銅鏡浄，未醒卯醉玉顔酡。", "一秋造化全鍾此，十月風光尚屬他。", "除却籬邊叢菊伴，別誰能奈曉霜何。"]'),
('82a3a27c-51fc-412f-9be5-814309c1842b','次朋山鄭管轄韻','楊公遠','宋','宋诗','song-poetry','','[]','朋山心與白雲閒，一點塵囂不可干。',64,'全唐诗/poet.song.234000.json','["朋山心與白雲閒，一點塵囂不可干。", "披褐朝真香篆裊，登壇召將劍芒寒。", "棋枰子落鳴飛雹，石鼎茶煎吼怒湍。", "待得功成丹九轉，願隨雞犬事劉安。"]'),
('8fea08c6-118d-4310-9543-18eb71a901e0','次趙都使心田壽域韻','楊公遠','宋','宋诗','song-poetry','','[]','非園非圃亦非坰，寸地無多好力耕。',64,'全唐诗/poet.song.234000.json','["非園非圃亦非坰，寸地無多好力耕。", "豈藉鋤犁開曠蕩，但除塵垢自和平。", "雲收月挂天長浄，水止風恬浪不生。", "壽域預營真得所，王家繭室可齊名。"]'),
('45e5eac9-8385-4aeb-b08f-30d61e01793a','借汪路教韻題趙東麓判丞臨清堂','楊公遠','宋','宋诗','song-poetry','','[]','結屋俯清溪，蕭然迥出奇。',120,'全唐诗/poet.song.234000.json','["結屋俯清溪，蕭然迥出奇。", "書藏千萬卷，梅浸兩三枝。", "入竹風聲細，移花日影遲。", "樂山仍樂水，何慮復何思。", "菊有陶潛逸，蘭無屈子悲。", "娛情琴上操，遣興局間棋。", "對客頻傾酒，臨流賸賦詩。", "要將閒度日，只恐道關時。", "觸目多幽致，留題總色絲。", "細吟增敬羨，貂續匪佳辭。"]'),
('e1d7cc07-d146-4f74-975d-7035f1f1e127','遠浦歸帆','楊公遠','宋','宋诗','song-poetry','','[]','江山勝處簇人家，樓閣重重枕水涯。',32,'全唐诗/poet.song.234000.json','["江山勝處簇人家，樓閣重重枕水涯。", "試倚闌干凝望眼，帆歸遠浦隔蘆花。"]'),
('f6ef56e0-9b51-4ab8-884a-95fcd6728dca','烟寺晚鐘','楊公遠','宋','宋诗','song-poetry','','[]','山寺鐘敲晚照殘，僧歸雲暝費躋攀。',32,'全唐诗/poet.song.234000.json','["山寺鐘敲晚照殘，僧歸雲暝費躋攀。", "浮屠屹立巔崖頂，恰在煙嵐紫翠間。"]'),
('0158c275-8f81-48e0-be21-d0c4aadf9a92','平沙起鴈','楊公遠','宋','宋诗','song-poetry','','[]','極目青山带夕陽，平沙漠漠水茫茫。',32,'全唐诗/poet.song.234000.json','["極目青山带夕陽，平沙漠漠水茫茫。", "幾聲漁笛蘆花外，驚起斜飛鴈一行。"]'),
('eee78bae-3a9d-4ee9-808f-e89bfa1aa166','江天莫雪','楊公遠','宋','宋诗','song-poetry','','[]','垂垂四幕凍雲頑，萬木號風晚更寒。',32,'全唐诗/poet.song.234000.json','["垂垂四幕凍雲頑，萬木號風晚更寒。", "繫纜漁人歸去後，亂飛柳絮滿江干。"]'),
('34a440c8-dc04-4d0c-8f42-04c0fb66bcba','瀟湘夜雨','楊公遠','宋','宋诗','song-poetry','','[]','薄莫維舟古岸邊，濃雲潑墨暗江天。',32,'全唐诗/poet.song.234000.json','["薄莫維舟古岸邊，濃雲潑墨暗江天。", "道林嶽麓知何處，雨打篷窗夜不眠。"]'),
('7b4b30f5-9231-4e65-954b-f1055405b79c','洞庭秋月','楊公遠','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','月色湖天浸岳城，蘆花渺渺白鋪汀。',32,'全唐诗/poet.song.234000.json','["月色湖天浸岳城，蘆花渺渺白鋪汀。", "玻瓈萬頃清無滓，只有君山一點青。"]'),
('51b0fa37-ff57-49fe-a822-8b1dc53398d3','山市晴嵐','楊公遠','宋','宋诗','song-poetry','','[]','橫嵐髣髴抹高岡，村市人家釀秫香。',32,'全唐诗/poet.song.234000.json','["橫嵐髣髴抹高岡，村市人家釀秫香。", "溪上曉來爭渡急，裹鹽沽酒趁虛忙。"]'),
('b08d392f-21bb-4040-aa74-96f52e075be3','漁村夕照','楊公遠','宋','宋诗','song-poetry','','[]','一簇漁家古渡頭，生涯只在幾扁舟。',32,'全唐诗/poet.song.234000.json','["一簇漁家古渡頭，生涯只在幾扁舟。", "歸來曬網斜陽外，欵乃數聲烟樹秋。"]'),
('05c1d2d2-b6a9-42f5-b5d2-d14cd488b15b','上趙相公  其一','楊公遠','宋','宋诗','song-poetry','','[]','天教古歙巧遭逢，和氣薰蒸蠶麥豐。',64,'全唐诗/poet.song.234000.json','["天教古歙巧遭逢，和氣薰蒸蠶麥豐。", "重見龔黄宣德化，再生韓柳振文風。", "萬間廣厦人人共，千里明蟾處處同。", "端的相門還拜相，魯公行即繼周公。"]'),
('fdbb98f1-4a02-42e3-833e-4ae37ffd784b','上趙相公  其二','楊公遠','宋','宋诗','song-poetry','','[]','徹骨清貧頗自憐，生涯淡薄只隨緣。',64,'全唐诗/poet.song.234000.json','["徹骨清貧頗自憐，生涯淡薄只隨緣。", "搜羅景象畫多趣，抖擻襟期詩幾篇。", "毛穎漫供煙雨耒，石泓聊當稻粱田。", "化爐倘賜甄陶意，便是人生際遇年。"]'),
('100a03da-8bd2-4ea0-a4dd-1458d7cc688b','次姚吏隠惠詩韻','楊公遠','宋','宋诗','song-poetry','','[]','相逢一笑信前緣，聞道先吾豈較年。',64,'全唐诗/poet.song.234000.json','["相逢一笑信前緣，聞道先吾豈較年。", "灑落襟期良夜月，沖融氣宇小春天。", "喜評曲直人間事，懶問肥磽郭外田。", "忙裏依然清興在，時時不吝惠新篇。"]'),
('c1ba1e97-c185-47d1-8be0-b7c457d54204','龍金庵次壁間韻','楊公遠','宋','宋诗','song-poetry','','[]','續得遠公派，結庵千仞巔。',48,'全唐诗/poet.song.234000.json','["續得遠公派，結庵千仞巔。", "利名俱拚捨，寒暑任推遷。", "供佛燃香篆，餐松嚥石泉。", "箇中三昧處，克廣自無邊。"]'),
('9103154a-16f1-441a-9343-7f56dd4566ef','學稼','楊公遠','宋','宋诗','song-poetry','','[]','塵埃面目半生勤，去住渾如出岫雲。',64,'全唐诗/poet.song.234000.json','["塵埃面目半生勤，去住渾如出岫雲。", "腹餒謾揮求米帖，囊空徒誦送窮文。", "詩書滿架何堪煮，稌黍盈疇政樂聞。", "欲辦烟蓑并雨笠，願隨田叟學耕耘。"]'),
('4072e2c6-63aa-467c-92e4-c15218ed0ac4','學圃','楊公遠','宋','宋诗','song-poetry','','[]','蕭然身世儘寬舒，剩有工夫學種蔬。',64,'全唐诗/poet.song.234000.json','["蕭然身世儘寬舒，剩有工夫學種蔬。", "每汲清泉勤抱甕，旋鋤荒圃謾携書。", "綠葵紫芥香尤美，春韭秋菘味有餘。", "時擷鮮苗烹石銚，朱門肉食不如渠。"]'),
('d87f30d0-80ad-4780-91c1-664c17384353','學漁','楊公遠','宋','宋诗','song-poetry','','[]','年來懶問是和非，謾向滄浪理釣磯。',64,'全唐诗/poet.song.234000.json','["年來懶問是和非，謾向滄浪理釣磯。", "折取綠荷充蒻笠，收將紅芰緝蓑衣。", "秋風蓴菜鱸堪膾，春水桃花鱖正肥。", "身逐煙波逃世慮，沙鷗汀鷺共忘機。"]'),
('4aa6bf1e-74c1-4b48-95ab-62ef5f0486b5','學樵','楊公遠','宋','宋诗','song-poetry','','[]','因嫌蹤跡混塵囂，腰斧高歌去採樵。',64,'全唐诗/poet.song.234000.json','["因嫌蹤跡混塵囂，腰斧高歌去採樵。", "欲效買臣無貴骨，何如王質有仙標。", "丁丁伐木空山外，軋軋肩薪小逕遥。", "一任雪天霜月夜，且將带葉地爐燒。"]'),
('c627d028-7fa9-486a-be28-183d5d71a8fc','次江草塘','楊公遠','宋','宋诗','song-poetry','','[]','西堂夢徹草塘春，得句渾無半點塵。',32,'全唐诗/poet.song.234000.json','["西堂夢徹草塘春，得句渾無半點塵。", "却喜寥寥千古後，只今分付與詩人。"]'),
('edc94b6f-ae60-4745-8c65-2bf3272759f7','次黄山中進退韻以餞','楊公遠','宋','宋诗','song-poetry','','[]','會聚渾無定，雲萍一樣觀。',48,'全唐诗/poet.song.234000.json','["會聚渾無定，雲萍一樣觀。", "今朝酬俚句，明日隔重山。", "鴻便書須寄，秋期盟莫寒。", "算來無遠別，底用唱陽關。"]'),
('c71d4a10-b0f3-4016-894e-4b403f68de68','次吳篁嶼贈別','楊公遠','宋','宋诗','song-poetry','','[]','每嗟人世等浮漚，會聚如雲散復收。',64,'全唐诗/poet.song.234000.json','["每嗟人世等浮漚，會聚如雲散復收。", "詩賦別情無白雪，酒澆離思有青州。", "見梅須寄一枝信，對月還關兩地愁。", "此去若逢風雨夜，肯思細話對床不。"]'),
('3722c76d-5217-41b7-86b0-62f440fc4889','次余靜庵寒夜詩思  其一','楊公遠','宋','宋诗','song-poetry','','[]','地爐煨芋栗，兀坐數寒更。',48,'全唐诗/poet.song.234000.json','["地爐煨芋栗，兀坐數寒更。", "香篆消重爇，銀釭剔復明。", "月穿窗隙過，風拂樹梢鳴。", "喚醒吟邊興，敲推睡不成。"]'),
('0f831ec9-a3cf-47e9-ac02-4705d4e16b18','次余靜庵寒夜詩思  其二','楊公遠','宋','宋诗','song-poetry','','[]','拂拭蒲團坐，從渠歲事更。',48,'全唐诗/poet.song.234000.json','["拂拭蒲團坐，從渠歲事更。", "年來心益壯，老去眼增明。", "月牖描梅影，風簷撼鐸鳴。", "撩儂詩興動，得句自天成。"]'),
('4ba682fc-61bd-4578-a06e-44dcbdbe8c5e','蠟梅','楊公遠','宋','宋诗','song-poetry','','[]','一種孤芳別樣奇，化工鎔蠟雪霜時。',64,'全唐诗/poet.song.234000.json','["一種孤芳別樣奇，化工鎔蠟雪霜時。", "正憐粉蝶歸何處，却怪黄蜂集滿枝。", "衣效道粧香惹袖，面侔佛相臉無脂。", "清名也受梅花號，底事林逋不贈詩。"]'),
('9b99aba5-033d-40d5-a063-1e2e2e03132a','逗春海棠','楊公遠','宋','宋诗','song-poetry','','[]','蜀地名花迥出奇，玉環卯醉未醒時。',64,'全唐诗/poet.song.234000.json','["蜀地名花迥出奇，玉環卯醉未醒時。", "只開春暖二三月，偶冒冬寒四五枝。", "曉带清霜濃傅粉，晚迎紅日淡勻脂。", "惜渠未敢輕攀折，子美如何少得詩。"]');
